import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Player = 'red' | 'blue';

export interface Position {
  row: number;
  col: number;
}

export interface Piece {
  id: string;
  player: Player;
  isKing: boolean;
  position: Position;
  isCaptured: boolean; // Visual state
}

export interface Move {
  from: Position;
  to: Position;
  isJump: boolean;
  capturedPieceId?: string;
  jumpedPosition?: Position;
}

export type GameState = 'menu' | 'playing' | 'winner';

export interface Particle {
  id: string;
  x: number;
  y: number;
  color: string;
  text?: string;
}

// Simple Audio Synthesis to avoid needing external assets
const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
const ctx = new AudioContextClass();

const playTone = (freq: number, type: OscillatorType, duration: number, delay: number = 0, vol: number = 0.1) => {
  if (ctx.state === 'suspended') ctx.resume();

  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = type;
  osc.frequency.setValueAtTime(freq, ctx.currentTime + delay);

  gain.gain.setValueAtTime(vol, ctx.currentTime + delay);
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + delay + duration);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start(ctx.currentTime + delay);
  osc.stop(ctx.currentTime + delay + duration);
};

export const playSound = {
  move: () => {
    // A soft "thud" or "whoosh"
    playTone(200, 'sine', 0.1, 0, 0.15);
    playTone(100, 'triangle', 0.1, 0.05, 0.1);
  },
  capture: () => {
    // A cartoon "pop"
    playTone(400, 'sine', 0.1, 0, 0.2);
    playTone(600, 'square', 0.1, 0.05, 0.1);
  },
  king: () => {
    // Magical chime
    playTone(500, 'sine', 0.3, 0);
    playTone(700, 'sine', 0.4, 0.1);
    playTone(1000, 'sine', 0.5, 0.2, 0.1);
  },
  win: () => {
    // Victory fanfare
    [300, 400, 500, 600, 800].forEach((f, i) => {
      playTone(f, 'square', 0.4, i * 0.1, 0.1);
    });
  },
  error: () => {
    playTone(150, 'sawtooth', 0.2);
    playTone(100, 'sawtooth', 0.2, 0.1);
  }
};

import React, { useEffect, useState } from 'react';
import { Piece, Player } from '../types';

interface ToonPieceProps {
  piece: Piece;
  isSelected: boolean;
  isTargeted?: boolean; // For future AI or tutorial hints
  onClick: () => void;
  canMove: boolean; // Is it this player's turn?
}

const ToonPiece: React.FC<ToonPieceProps> = ({ piece, isSelected, onClick, canMove }) => {
  const [mood, setMood] = useState<'idle' | 'happy' | 'surprised'>('idle');

  // Random blinking logic handled by CSS, but mood changes on interaction
  useEffect(() => {
    if (isSelected) {
      setMood('surprised');
    } else if (piece.isKing) {
      setMood('happy');
    } else {
      setMood('idle');
    }
  }, [isSelected, piece.isKing]);

  // Colors
  const baseColor = piece.player === 'red' ? 'bg-rose-500' : 'bg-sky-500';
  const shadowColor = piece.player === 'red' ? 'shadow-rose-900' : 'shadow-sky-900';
  const rimColor = piece.player === 'red' ? 'border-rose-300' : 'border-sky-300';
  const glow = isSelected ? 'ring-4 ring-yellow-400 scale-110 z-20' : '';

  return (
    <div 
      onClick={(e) => {
        e.stopPropagation();
        onClick();
      }}
      className={`
        relative w-[80%] h-[80%] rounded-full cursor-pointer
        transition-all duration-300 ease-[cubic-bezier(0.34,1.56,0.64,1)]
        ${baseColor} ${rimColor} border-2
        shadow-[inset_-4px_-6px_10px_rgba(0,0,0,0.4),0_6px_0px_rgba(0,0,0,0.3)]
        ${glow}
        flex items-center justify-center
        group
        ${canMove ? 'hover:-translate-y-1 hover:brightness-110' : ''}
      `}
    >
      {/* Glossy Reflection */}
      <div className="absolute top-2 left-1/4 w-1/2 h-1/3 bg-white opacity-20 rounded-full blur-[1px]"></div>

      {/* Face Container */}
      <div className="relative w-full h-full flex flex-col items-center justify-center mt-1">

        {/* Eyes */}
        <div className="flex gap-2 mb-1">
          {/* Left Eye */}
          <div className="relative w-3 h-4 bg-white rounded-full animate-blink overflow-hidden">
            <div className={`absolute w-1.5 h-1.5 bg-black rounded-full top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 
              ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
          </div>
          {/* Right Eye */}
          <div className="relative w-3 h-4 bg-white rounded-full animate-blink overflow-hidden" style={{ animationDelay: '0.1s' }}>
            <div className={`absolute w-1.5 h-1.5 bg-black rounded-full top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 
              ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
          </div>
        </div>

        {/* Mouth */}
        <div className={`
          w-4 h-2 bg-black/70 rounded-b-full transition-all duration-300
          ${mood === 'surprised' ? 'h-3 w-3 rounded-full' : ''}
          ${mood === 'happy' ? 'h-3 w-5 rounded-b-xl border-t-0' : ''}
        `}></div>

      </div>

      {/* Crown for King */}
      {piece.isKing && (
        <div className="absolute -top-6 left-1/2 transform -translate-x-1/2 w-8 h-8 animate-float z-30 pointer-events-none">
           <svg viewBox="0 0 24 24" fill="none" className="w-full h-full drop-shadow-lg filter animate-crown">
             <path d="M2 18h20v2H2v-2zm0-2l4-8 4 6 4-6 4 8H2z" fill="#FFD700" stroke="#B8860B" strokeWidth="1.5" strokeLinejoin="round"/>
             <circle cx="6" cy="6" r="1" fill="#FFF" />
             <circle cx="12" cy="10" r="1" fill="#FFF" />
             <circle cx="18" cy="6" r="1" fill="#FFF" />
           </svg>
           {/* Sparkles */}
           <div className="absolute -top-1 -right-2 text-yellow-300 text-xs font-bold animate-pulse">✦</div>
           <div className="absolute top-2 -left-2 text-yellow-300 text-[10px] font-bold animate-pulse" style={{animationDelay:'0.5s'}}>✦</div>
        </div>
      )}
    </div>
  );
};

export default ToonPiece;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import ToonPiece from './components/ToonPiece';
import { Piece, Position, Move, Player, GameState, Particle } from './types';
import { playSound } from './utils/audio';

// --- Constants ---
const BOARD_SIZE = 8;
const ANIMATION_DELAY = 400; // ms to wait during CPU move or animations

const App: React.FC = () => {
  // --- State ---
  const [gameState, setGameState] = useState<GameState>('menu');
  const [board, setBoard] = useState<(Piece | null)[][]>([]);
  const [turn, setTurn] = useState<Player>('red'); // Red starts
  const [selectedPieceId, setSelectedPieceId] = useState<string | null>(null);
  const [validMoves, setValidMoves] = useState<Move[]>([]);
  const [forcedCapture, setForcedCapture] = useState<string | null>(null); // ID of piece that MUST double jump
  const [scores, setScores] = useState({ red: 0, blue: 0 });
  const [particles, setParticles] = useState<Particle[]>([]);
  const [winner, setWinner] = useState<Player | null>(null);
  const [comboCount, setComboCount] = useState(0);

  // --- Initialization ---
  const initGame = () => {
    const newBoard: (Piece | null)[][] = Array(BOARD_SIZE).fill(null).map(() => Array(BOARD_SIZE).fill(null));
    let idCounter = 0;

    for (let row = 0; row < BOARD_SIZE; row++) {
      for (let col = 0; col < BOARD_SIZE; col++) {
        if ((row + col) % 2 === 1) {
          if (row < 3) {
            newBoard[row][col] = { id: `blue-${idCounter++}`, player: 'blue', isKing: false, position: { row, col }, isCaptured: false };
          } else if (row > 4) {
            newBoard[row][col] = { id: `red-${idCounter++}`, player: 'red', isKing: false, position: { row, col }, isCaptured: false };
          }
        }
      }
    }
    setBoard(newBoard);
    setTurn('red');
    setScores({ red: 12, blue: 12 });
    setGameState('playing');
    setWinner(null);
    setForcedCapture(null);
    setSelectedPieceId(null);
    setValidMoves([]);
    setComboCount(0);
    playSound.move();
  };

  // --- Logic Helper Functions ---

  const getPieceAt = (b: (Piece | null)[][], pos: Position) => {
    if (pos.row < 0 || pos.row >= BOARD_SIZE || pos.col < 0 || pos.col >= BOARD_SIZE) return null;
    return b[pos.row][pos.col];
  };

  const calculateValidMoves = (piece: Piece, currentBoard: (Piece | null)[][]): Move[] => {
    const moves: Move[] = [];
    const directions = piece.isKing 
      ? [[-1, -1], [-1, 1], [1, -1], [1, 1]] 
      : piece.player === 'red' ? [[-1, -1], [-1, 1]] : [[1, -1], [1, 1]];

    directions.forEach(([dRow, dCol]) => {
      // 1. Simple Move
      const targetPos = { row: piece.position.row + dRow, col: piece.position.col + dCol };
      if (
        targetPos.row >= 0 && targetPos.row < BOARD_SIZE &&
        targetPos.col >= 0 && targetPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, targetPos)
      ) {
         // Only allow simple move if NOT currently in a forced capture sequence
         moves.push({ from: piece.position, to: targetPos, isJump: false });
      }

      // 2. Jump (Capture)
      const jumpPos = { row: piece.position.row + (dRow * 2), col: piece.position.col + (dCol * 2) };
      if (
        jumpPos.row >= 0 && jumpPos.row < BOARD_SIZE &&
        jumpPos.col >= 0 && jumpPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, jumpPos)
      ) {
        const midPos = targetPos;
        const midPiece = getPieceAt(currentBoard, midPos);
        if (midPiece && midPiece.player !== piece.player) {
          moves.push({ 
            from: piece.position, 
            to: jumpPos, 
            isJump: true, 
            capturedPieceId: midPiece.id, 
            jumpedPosition: midPos 
          });
        }
      }
    });

    return moves;
  };

  const getAllValidMovesForPlayer = (player: Player, currentBoard: (Piece | null)[][]) => {
    let allMoves: { pieceId: string, move: Move }[] = [];
    let hasJump = false;

    // Iterate board to find all player pieces
    for(let r=0; r<BOARD_SIZE; r++){
      for(let c=0; c<BOARD_SIZE; c++){
        const p = currentBoard[r][c];
        if(p && p.player === player && !p.isCaptured){
          const moves = calculateValidMoves(p, currentBoard);
          moves.forEach(m => {
            if(m.isJump) hasJump = true;
            allMoves.push({ pieceId: p.id, move: m });
          });
        }
      }
    }

    // Forced capture rule: If a jump exists, remove non-jumps
    if (hasJump) {
      allMoves = allMoves.filter(m => m.move.isJump);
    }

    return { allMoves, hasJump };
  };

  // --- Interaction ---

  const handleSquareClick = (row: number, col: number) => {
    if (gameState !== 'playing') return;

    const clickedPiece = board[row][col];
    const isCurrentPlayerPiece = clickedPiece?.player === turn;

    // 1. Selecting a piece
    if (isCurrentPlayerPiece) {
      if (forcedCapture && forcedCapture !== clickedPiece.id) {
        playSound.error();
        return; // Must play the forced piece
      }

      // Calculate moves for this piece
      const { allMoves, hasJump } = getAllValidMovesForPlayer(turn, board);

      // If forced jumps exist globally, can only select pieces that can jump
      if (hasJump) {
         const canThisJump = allMoves.some(m => m.pieceId === clickedPiece.id && m.move.isJump);
         if (!canThisJump) {
            playSound.error();
            return;
         }
      }

      setSelectedPieceId(clickedPiece.id);

      // Filter valid moves for just this piece
      const movesForPiece = allMoves
        .filter(m => m.pieceId === clickedPiece.id)
        .map(m => m.move);

      setValidMoves(movesForPiece);
      playSound.move();
      return;
    }

    // 2. Moving to an empty square (executing a move)
    if (!clickedPiece && selectedPieceId) {
      const move = validMoves.find(m => m.to.row === row && m.to.col === col);
      if (move) {
        executeMove(move);
      } else {
        // Deselect if clicking invalid empty square
        setSelectedPieceId(null);
        setValidMoves([]);
      }
    }
  };

  const executeMove = (move: Move) => {
    const piece = getPieceAt(board, move.from);
    if (!piece) return;

    // Create deep copy for mutation
    const newBoard = board.map(row => row.map(p => p ? { ...p } : null));
    const movedPiece = newBoard[move.from.row][move.from.col]!;

    // Update position
    newBoard[move.from.row][move.from.col] = null;
    newBoard[move.to.row][move.to.col] = movedPiece;
    movedPiece.position = move.to;

    let justCaptured = false;

    // Handle Capture
    if (move.isJump && move.jumpedPosition) {
      const captured = newBoard[move.jumpedPosition.row][move.jumpedPosition.col];
      newBoard[move.jumpedPosition.row][move.jumpedPosition.col] = null; // Remove from board

      if (captured) {
        spawnParticles(move.to.row, move.to.col, "+1");
        setScores(prev => ({
          ...prev,
          [captured.player]: prev[captured.player] - 1
        }));
        justCaptured = true;
        setComboCount(c => c + 1);
        playSound.capture();
      }
    } else {
      setComboCount(0);
      playSound.move();
    }

    // Handle Promotion
    let promoted = false;
    if (!movedPiece.isKing) {
      if ((movedPiece.player === 'red' && move.to.row === 0) ||
          (movedPiece.player === 'blue' && move.to.row === BOARD_SIZE - 1)) {
        movedPiece.isKing = true;
        promoted = true;
        playSound.king();
        spawnParticles(move.to.row, move.to.col, "KING!", true);
      }
    }

    setBoard(newBoard);
    setSelectedPieceId(null);
    setValidMoves([]);

    // Multi-jump Logic
    if (justCaptured && !promoted) {
      // Check if this specific piece can jump again
      const nextMoves = calculateValidMoves(movedPiece, newBoard).filter(m => m.isJump);
      if (nextMoves.length > 0) {
        // Must continue with this piece
        setForcedCapture(movedPiece.id);
        setSelectedPieceId(movedPiece.id);
        setValidMoves(nextMoves);
        return; // Turn does NOT change
      }
    }

    // End Turn
    endTurn(newBoard);
  };

  const endTurn = (currentBoard: (Piece | null)[][]) => {
    setForcedCapture(null);
    setComboCount(0);
    const nextPlayer = turn === 'red' ? 'blue' : 'red';

    // Check win condition (count pieces or no moves)
    const { allMoves } = getAllValidMovesForPlayer(nextPlayer, currentBoard);

    if (allMoves.length === 0) {
      setWinner(turn); // Current player wins because next has no moves
      setGameState('winner');
      playSound.win();
    } else {
      setTurn(nextPlayer);
    }
  };

  // --- Effects & Visuals ---

  const spawnParticles = (row: number, col: number, text?: string, gold: boolean = false) => {
    const id = Date.now().toString();
    const x = col * 100 + 50; // Roughly center of cell (assuming responsive calc later, using % for now)
    const y = row * 100 + 50;

    setParticles(prev => [...prev, { id, x: 0, y: 0, color: gold ? '#FFD700' : '#FFF', text }]); // Coordinates handled in CSS via grid

    // Cleanup
    setTimeout(() => {
      setParticles(prev => prev.filter(p => p.id !== id));
    }, 1000);
  };

  // Render Helpers
  const renderSquare = (row: number, col: number) => {
    const isBlack = (row + col) % 2 === 1;
    const piece = board[row][col];

    // Highlights
    const isPossibleMove = validMoves.some(m => m.to.row === row && m.to.col === col);
    const isSource = selectedPieceId && piece && piece.id === selectedPieceId;
    const isLastMoveSrc = false; // Could add history logic
    const isLastMoveDst = false;

    return (
      <div 
        key={`${row}-${col}`}
        onClick={() => handleSquareClick(row, col)}
        className={`
          relative w-full h-full flex items-center justify-center
          ${isBlack ? 'bg-slate-800' : 'bg-slate-200'}
          ${isPossibleMove ? 'ring-inset ring-4 ring-green-400 cursor-pointer' : ''}
          border-b-4 ${isBlack ? 'border-slate-900' : 'border-slate-300'}
        `}
      >
        {/* Cell Highlight for Possible Move */}
        {isPossibleMove && (
          <div className="absolute w-4 h-4 bg-green-400 rounded-full animate-pulse opacity-80"></div>
        )}

        {/* Piece */}
        {piece && (
          <div className={`w-full h-full p-1 z-10 transition-transform duration-300 ${isSource ? 'scale-110' : ''}`}>
             <ToonPiece 
                piece={piece} 
                isSelected={!!isSource} 
                canMove={turn === piece.player}
                onClick={() => handleSquareClick(row, col)} 
             />
          </div>
        )}

        {/* Floating Particles (Simplified implementation: specific to cell) */}
        {particles.map(p => {
          // Check if this particle belongs to this square (logic shortcut)
          // In a real physics engine, particles would be global overlay. 
          // Here, we just trigger them in the `executeMove` and render conditionally? 
          // Actually, let's just render specific "pop" divs here if a capture happened recently.
          return null; 
        })}
      </div>
    );
  };

  // Global Particle Overlay (Better approach)
  const renderParticles = () => {
    // We need to map row/col to screen percentage or absolute pixels.
    // Since grid is fluid, this is tricky without refs.
    // Simplified: Just show a central combo text for now or keep it simple.
    return null;
  };

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center text-white relative overflow-hidden select-none">

      {/* Background Ambience */}
      <div className="absolute inset-0 opacity-20 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900 via-slate-900 to-black pointer-events-none"></div>

      {/* Header / UI */}
      <header className="w-full max-w-lg flex justify-between items-center p-4 z-10">
        <div className={`
          flex flex-col items-center transition-all duration-300
          ${turn === 'blue' ? 'scale-110 opacity-100' : 'scale-90 opacity-60 grayscale'}
        `}>
          <div className="w-16 h-16 bg-sky-500 rounded-full border-4 border-white shadow-lg flex items-center justify-center mb-1 relative overflow-hidden">
             <div className="absolute w-2 h-2 bg-white rounded-full top-4 left-4"></div>
             <span className="text-2xl font-black">{scores.blue}</span>
          </div>
          <span className="font-bold text-sky-300 tracking-wider">BLUE</span>
        </div>

        <div className="flex flex-col items-center">
          <h1 className="text-3xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500 drop-shadow-sm tracking-tighter">
            CHECKERS
          </h1>
          <div className="bg-slate-800 px-4 py-1 rounded-full text-xs font-bold text-slate-400 mt-1 uppercase tracking-widest border border-slate-700">
             {gameState === 'playing' ? `${turn.toUpperCase()}'S TURN` : 'GAME OVER'}
          </div>
        </div>

        <div className={`
          flex flex-col items-center transition-all duration-300
          ${turn === 'red' ? 'scale-110 opacity-100' : 'scale-90 opacity-60 grayscale'}
        `}>
          <div className="w-16 h-16 bg-rose-500 rounded-full border-4 border-white shadow-lg flex items-center justify-center mb-1 relative overflow-hidden">
            <div className="absolute w-2 h-2 bg-white rounded-full top-4 right-4"></div>
            <span className="text-2xl font-black">{scores.red}</span>
          </div>
          <span className="font-bold text-rose-300 tracking-wider">RED</span>
        </div>
      </header>

      {/* Combo Indicator */}
      {comboCount > 1 && (
        <div className="absolute top-24 z-50 animate-pop">
          <span className="text-4xl font-black text-yellow-400 drop-shadow-[0_4px_0_rgba(0,0,0,1)] stroke-black">
            COMBO x{comboCount}!
          </span>
        </div>
      )}

      {/* Main Game Area */}
      <main className="relative z-10 p-2 perspective-board">
        <div className={`
          w-[90vw] h-[90vw] max-w-[600px] max-h-[600px] 
          bg-slate-950 p-2 rounded-xl shadow-2xl border-b-8 border-slate-950
          transition-transform duration-700
          ${gameState === 'winner' ? 'scale-90 blur-sm' : ''}
        `}>
          <div className="w-full h-full bg-slate-800 rounded-lg overflow-hidden grid grid-cols-8 grid-rows-8 shadow-inner border-4 border-slate-700">
            {board.map((row, r) => row.map((_, c) => renderSquare(r, c)))}
          </div>
        </div>
      </main>

      {/* Menus / Overlays */}
      {gameState === 'menu' && (
        <div className="absolute inset-0 bg-black/80 z-50 flex flex-col items-center justify-center backdrop-blur-sm">
           <div className="text-6xl font-black text-white mb-8 tracking-tighter drop-shadow-xl animate-float">
             TOON CHECKERS
           </div>
           <button 
             onClick={initGame}
             className="px-8 py-4 bg-green-500 hover:bg-green-400 text-white rounded-full font-black text-xl shadow-[0_6px_0_rgb(21,128,61)] hover:shadow-[0_4px_0_rgb(21,128,61)] hover:translate-y-[2px] active:shadow-none active:translate-y-[6px] transition-all"
           >
             PLAY GAME
           </button>
        </div>
      )}

      {gameState === 'winner' && (
        <div className="absolute inset-0 bg-black/80 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in">
           <div className="text-yellow-400 text-7xl mb-4 animate-bounce">🏆</div>
           <h2 className="text-5xl font-black text-white mb-2 drop-shadow-lg">
             {winner?.toUpperCase()} WINS!
           </h2>
           <p className="text-slate-300 mb-8 font-bold text-xl">
             Incredible Strategy!
           </p>
           <button 
             onClick={initGame}
             className="px-8 py-4 bg-blue-500 hover:bg-blue-400 text-white rounded-full font-black text-xl shadow-[0_6px_0_rgb(30,58,138)] hover:shadow-[0_4px_0_rgb(30,58,138)] hover:translate-y-[2px] active:shadow-none active:translate-y-[6px] transition-all"
           >
             PLAY AGAIN
           </button>
        </div>
      )}

      {/* Footer */}
      <div className="mt-4 text-slate-500 text-xs font-bold tracking-widest uppercase">
         Use Strategy to Promote to King
      </div>

    </div>
  );
};

export default App;

export type Player = 'red' | 'blue';

export interface Position {
  row: number;
  col: number;
}

export interface Piece {
  id: string;
  player: Player;
  isKing: boolean;
  position: Position;
  isCaptured: boolean; // Visual state
}

export interface Move {
  from: Position;
  to: Position;
  isJump: boolean;
  capturedPieceId?: string;
  jumpedPosition?: Position;
}

export type GameState = 'menu' | 'playing' | 'winner';

export interface Particle {
  id: string;
  row: number;
  col: number;
  color: string;
  text?: string;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import ToonPiece from './components/ToonPiece';
import { Piece, Position, Move, Player, GameState, Particle } from './types';
import { playSound } from './utils/audio';

// --- Constants ---
const BOARD_SIZE = 8;

const App: React.FC = () => {
  // --- State ---
  const [gameState, setGameState] = useState<GameState>('menu');
  const [board, setBoard] = useState<(Piece | null)[][]>([]);
  const [turn, setTurn] = useState<Player>('red'); // Red starts
  const [selectedPieceId, setSelectedPieceId] = useState<string | null>(null);
  const [validMoves, setValidMoves] = useState<Move[]>([]);
  const [forcedCapture, setForcedCapture] = useState<string | null>(null); // ID of piece that MUST double jump
  const [scores, setScores] = useState({ red: 0, blue: 0 });
  const [particles, setParticles] = useState<Particle[]>([]);
  const [winner, setWinner] = useState<Player | null>(null);
  const [comboCount, setComboCount] = useState(0);

  // --- Initialization ---
  const initGame = () => {
    const newBoard: (Piece | null)[][] = Array(BOARD_SIZE).fill(null).map(() => Array(BOARD_SIZE).fill(null));
    let idCounter = 0;

    for (let row = 0; row < BOARD_SIZE; row++) {
      for (let col = 0; col < BOARD_SIZE; col++) {
        if ((row + col) % 2 === 1) {
          if (row < 3) {
            newBoard[row][col] = { id: `blue-${idCounter++}`, player: 'blue', isKing: false, position: { row, col }, isCaptured: false };
          } else if (row > 4) {
            newBoard[row][col] = { id: `red-${idCounter++}`, player: 'red', isKing: false, position: { row, col }, isCaptured: false };
          }
        }
      }
    }
    setBoard(newBoard);
    setTurn('red');
    setScores({ red: 12, blue: 12 });
    setGameState('playing');
    setWinner(null);
    setForcedCapture(null);
    setSelectedPieceId(null);
    setValidMoves([]);
    setComboCount(0);
    playSound.move();
  };

  // --- Logic Helper Functions ---

  const getPieceAt = (b: (Piece | null)[][], pos: Position) => {
    if (pos.row < 0 || pos.row >= BOARD_SIZE || pos.col < 0 || pos.col >= BOARD_SIZE) return null;
    return b[pos.row][pos.col];
  };

  const calculateValidMoves = (piece: Piece, currentBoard: (Piece | null)[][]): Move[] => {
    const moves: Move[] = [];
    const directions = piece.isKing 
      ? [[-1, -1], [-1, 1], [1, -1], [1, 1]] 
      : piece.player === 'red' ? [[-1, -1], [-1, 1]] : [[1, -1], [1, 1]];

    directions.forEach(([dRow, dCol]) => {
      // 1. Simple Move
      const targetPos = { row: piece.position.row + dRow, col: piece.position.col + dCol };
      if (
        targetPos.row >= 0 && targetPos.row < BOARD_SIZE &&
        targetPos.col >= 0 && targetPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, targetPos)
      ) {
         // Only allow simple move if NOT currently in a forced capture sequence
         moves.push({ from: piece.position, to: targetPos, isJump: false });
      }

      // 2. Jump (Capture)
      const jumpPos = { row: piece.position.row + (dRow * 2), col: piece.position.col + (dCol * 2) };
      if (
        jumpPos.row >= 0 && jumpPos.row < BOARD_SIZE &&
        jumpPos.col >= 0 && jumpPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, jumpPos)
      ) {
        const midPos = targetPos;
        const midPiece = getPieceAt(currentBoard, midPos);
        if (midPiece && midPiece.player !== piece.player) {
          moves.push({ 
            from: piece.position, 
            to: jumpPos, 
            isJump: true, 
            capturedPieceId: midPiece.id, 
            jumpedPosition: midPos 
          });
        }
      }
    });

    return moves;
  };

  const getAllValidMovesForPlayer = (player: Player, currentBoard: (Piece | null)[][]) => {
    let allMoves: { pieceId: string, move: Move }[] = [];
    let hasJump = false;

    // Iterate board to find all player pieces
    for(let r=0; r<BOARD_SIZE; r++){
      for(let c=0; c<BOARD_SIZE; c++){
        const p = currentBoard[r][c];
        if(p && p.player === player && !p.isCaptured){
          const moves = calculateValidMoves(p, currentBoard);
          moves.forEach(m => {
            if(m.isJump) hasJump = true;
            allMoves.push({ pieceId: p.id, move: m });
          });
        }
      }
    }

    // Forced capture rule: If a jump exists, remove non-jumps
    if (hasJump) {
      allMoves = allMoves.filter(m => m.move.isJump);
    }

    return { allMoves, hasJump };
  };

  // --- Interaction ---

  const handleSquareClick = (row: number, col: number) => {
    if (gameState !== 'playing') return;

    const clickedPiece = board[row][col];
    const isCurrentPlayerPiece = clickedPiece?.player === turn;

    // 1. Selecting a piece
    if (isCurrentPlayerPiece) {
      if (forcedCapture && forcedCapture !== clickedPiece.id) {
        playSound.error();
        return; // Must play the forced piece
      }

      // Calculate moves for this piece
      const { allMoves, hasJump } = getAllValidMovesForPlayer(turn, board);

      // If forced jumps exist globally, can only select pieces that can jump
      if (hasJump) {
         const canThisJump = allMoves.some(m => m.pieceId === clickedPiece.id && m.move.isJump);
         if (!canThisJump) {
            playSound.error();
            return;
         }
      }

      setSelectedPieceId(clickedPiece.id);

      // Filter valid moves for just this piece
      const movesForPiece = allMoves
        .filter(m => m.pieceId === clickedPiece.id)
        .map(m => m.move);

      setValidMoves(movesForPiece);
      playSound.move();
      return;
    }

    // 2. Moving to an empty square (executing a move)
    if (!clickedPiece && selectedPieceId) {
      const move = validMoves.find(m => m.to.row === row && m.to.col === col);
      if (move) {
        executeMove(move);
      } else {
        // Deselect if clicking invalid empty square
        setSelectedPieceId(null);
        setValidMoves([]);
      }
    }
  };

  const executeMove = (move: Move) => {
    const piece = getPieceAt(board, move.from);
    if (!piece) return;

    // Create deep copy for mutation
    const newBoard = board.map(row => row.map(p => p ? { ...p } : null));
    const movedPiece = newBoard[move.from.row][move.from.col]!;

    // Update position
    newBoard[move.from.row][move.from.col] = null;
    newBoard[move.to.row][move.to.col] = movedPiece;
    movedPiece.position = move.to;

    let justCaptured = false;

    // Handle Capture
    if (move.isJump && move.jumpedPosition) {
      const captured = newBoard[move.jumpedPosition.row][move.jumpedPosition.col];
      newBoard[move.jumpedPosition.row][move.jumpedPosition.col] = null; // Remove from board

      if (captured) {
        spawnParticles(move.to.row, move.to.col, "+1");
        setScores(prev => ({
          ...prev,
          [captured.player]: prev[captured.player] - 1
        }));
        justCaptured = true;
        setComboCount(c => c + 1);
        playSound.capture();
      }
    } else {
      setComboCount(0);
      playSound.move();
    }

    // Handle Promotion
    let promoted = false;
    if (!movedPiece.isKing) {
      if ((movedPiece.player === 'red' && move.to.row === 0) ||
          (movedPiece.player === 'blue' && move.to.row === BOARD_SIZE - 1)) {
        movedPiece.isKing = true;
        promoted = true;
        playSound.king();
        spawnParticles(move.to.row, move.to.col, "KING!", true);
      }
    }

    setBoard(newBoard);
    setSelectedPieceId(null);
    setValidMoves([]);

    // Multi-jump Logic
    if (justCaptured && !promoted) {
      // Check if this specific piece can jump again
      const nextMoves = calculateValidMoves(movedPiece, newBoard).filter(m => m.isJump);
      if (nextMoves.length > 0) {
        // Must continue with this piece
        setForcedCapture(movedPiece.id);
        setSelectedPieceId(movedPiece.id);
        setValidMoves(nextMoves);
        return; // Turn does NOT change
      }
    }

    // End Turn
    endTurn(newBoard);
  };

  const endTurn = (currentBoard: (Piece | null)[][]) => {
    setForcedCapture(null);
    setComboCount(0);
    const nextPlayer = turn === 'red' ? 'blue' : 'red';

    // Check win condition (count pieces or no moves)
    const { allMoves } = getAllValidMovesForPlayer(nextPlayer, currentBoard);

    if (allMoves.length === 0) {
      setWinner(turn); // Current player wins because next has no moves
      setGameState('winner');
      playSound.win();
    } else {
      setTurn(nextPlayer);
    }
  };

  // --- Effects & Visuals ---

  const spawnParticles = (row: number, col: number, text?: string, gold: boolean = false) => {
    const id = Date.now().toString() + Math.random();
    setParticles(prev => [...prev, { id, row, col, color: gold ? '#FFD700' : '#FFF', text }]);

    // Cleanup
    setTimeout(() => {
      setParticles(prev => prev.filter(p => p.id !== id));
    }, 1200);
  };

  // Render Helpers
  const renderSquare = (row: number, col: number) => {
    const isBlack = (row + col) % 2 === 1;
    const piece = board[row][col];

    // Highlights
    const isPossibleMove = validMoves.some(m => m.to.row === row && m.to.col === col);
    const isSource = selectedPieceId && piece && piece.id === selectedPieceId;

    // Particles for this square
    const cellParticles = particles.filter(p => p.row === row && p.col === col);

    return (
      <div 
        key={`${row}-${col}`}
        onClick={() => handleSquareClick(row, col)}
        className={`
          relative w-full h-full flex items-center justify-center
          ${isBlack ? 'bg-slate-800' : 'bg-slate-200'}
          ${isPossibleMove ? 'ring-inset ring-4 ring-green-400 cursor-pointer' : ''}
          /* Subtle internal borders for texture */
          ${isBlack ? 'shadow-[inset_0_0_10px_rgba(0,0,0,0.5)]' : 'shadow-[inset_0_0_10px_rgba(255,255,255,0.5)]'}
        `}
      >
        {/* Cell Highlight for Possible Move */}
        {isPossibleMove && (
          <div className="absolute inset-2 bg-green-400 rounded-full animate-pulse opacity-40"></div>
        )}

        {/* Piece */}
        {piece && (
          <div className={`w-full h-full p-1.5 z-10 transition-transform duration-300 ${isSource ? 'scale-110' : ''}`}>
             <ToonPiece 
                piece={piece} 
                isSelected={!!isSource} 
                canMove={turn === piece.player}
                onClick={() => handleSquareClick(row, col)} 
             />
          </div>
        )}

        {/* Floating Particles in Cell */}
        {cellParticles.map(p => (
           <div key={p.id} className="absolute inset-0 flex items-center justify-center z-50 pointer-events-none">
              <div className="animate-pop flex flex-col items-center">
                 {/* Sparkle graphic */}
                 <div className="text-3xl filter drop-shadow-md">💥</div>
                 {/* Text */}
                 {p.text && (
                   <span className="text-xl font-black text-white stroke-black drop-shadow-[0_2px_0_rgba(0,0,0,0.8)]" style={{color: p.color}}>
                     {p.text}
                   </span>
                 )}
              </div>
           </div>
        ))}
      </div>
    );
  };

  return (
    <div className="min-h-screen h-[100dvh] bg-slate-900 flex flex-col items-center justify-center text-white relative overflow-hidden select-none touch-none">

      {/* Background Ambience */}
      <div className="absolute inset-0 opacity-20 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900 via-slate-900 to-black pointer-events-none"></div>

      {/* Header / UI - Adaptive Flex Layout */}
      <div className="relative w-full max-w-4xl flex flex-col md:flex-row items-center justify-center md:justify-between gap-4 p-4 z-10 flex-shrink-0">

        {/* Blue Player Stats (Left/Top) */}
        <div className={`
          flex items-center gap-4 transition-all duration-300 order-2 md:order-1
          ${turn === 'blue' ? 'opacity-100 scale-105' : 'opacity-60 scale-95 grayscale'}
        `}>
          <div className="w-14 h-14 md:w-20 md:h-20 bg-sky-500 rounded-full border-4 border-white shadow-lg flex items-center justify-center relative overflow-hidden">
             <div className="absolute w-3 h-3 bg-white rounded-full top-3 left-3 opacity-50"></div>
             <span className="text-2xl md:text-3xl font-black">{scores.blue}</span>
          </div>
          <div className="hidden md:block font-bold text-sky-300 text-xl tracking-wider">BLUE</div>
        </div>

        {/* Title & Game Info (Center) */}
        <div className="flex flex-col items-center order-1 md:order-2 mb-2 md:mb-0">
          <h1 className="text-3xl md:text-5xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500 drop-shadow-sm tracking-tighter">
            CHECKERS
          </h1>
          <div className="bg-slate-800/80 backdrop-blur px-6 py-1.5 rounded-full text-xs md:text-sm font-bold text-slate-300 mt-2 uppercase tracking-widest border border-slate-700 shadow-xl">
             {gameState === 'playing' ? (
                <span className={turn === 'red' ? 'text-rose-400' : 'text-sky-400'}>
                   {turn.toUpperCase()}'S TURN
                </span>
             ) : 'GAME OVER'}
          </div>
        </div>

        {/* Red Player Stats (Right/Bottom) */}
        <div className={`
          flex items-center gap-4 transition-all duration-300 order-3
          ${turn === 'red' ? 'opacity-100 scale-105' : 'opacity-60 scale-95 grayscale'}
        `}>
          <div className="md:hidden font-bold text-rose-300 text-xl tracking-wider"></div> 
          <div className="hidden md:block font-bold text-rose-300 text-xl tracking-wider text-right">RED</div>
          <div className="w-14 h-14 md:w-20 md:h-20 bg-rose-500 rounded-full border-4 border-white shadow-lg flex items-center justify-center relative overflow-hidden">
            <div className="absolute w-3 h-3 bg-white rounded-full top-3 right-3 opacity-50"></div>
            <span className="text-2xl md:text-3xl font-black">{scores.red}</span>
          </div>
        </div>
      </div>

      {/* Combo Indicator */}
      {comboCount > 1 && (
        <div className="absolute top-[20%] z-50 animate-pop pointer-events-none">
          <span className="text-5xl md:text-6xl font-black text-yellow-400 drop-shadow-[0_4px_0_rgba(0,0,0,1)] stroke-black" style={{WebkitTextStroke: '2px black'}}>
            COMBO x{comboCount}!
          </span>
        </div>
      )}

      {/* Main Game Area - Perfectly Centered & Responsive */}
      <main className="relative z-10 flex items-center justify-center p-2 md:p-4 w-full h-full flex-grow">
        <div className={`
          relative
          /* The Magic Responsive Formula: */
          w-[min(90vw,90vw)]
          h-[min(90vw,90vw)]
          md:w-[min(600px,75vmin)] 
          md:h-[min(600px,75vmin)]
          bg-slate-950 p-3 rounded-2xl shadow-2xl border-b-[8px] border-slate-950
          transition-all duration-700
          perspective-board
          ${gameState === 'winner' ? 'scale-90 blur-sm' : ''}
        `}>
          <div className="w-full h-full bg-slate-800 rounded-xl overflow-hidden grid grid-cols-8 grid-rows-8 shadow-inner ring-4 ring-slate-800">
            {board.map((row, r) => row.map((_, c) => renderSquare(r, c)))}
          </div>
        </div>
      </main>

      {/* Menus / Overlays */}
      {gameState === 'menu' && (
        <div className="absolute inset-0 bg-slate-900/90 z-50 flex flex-col items-center justify-center backdrop-blur-md">
           <div className="text-5xl md:text-7xl font-black text-white mb-8 tracking-tighter drop-shadow-xl animate-float text-center px-4">
             TOON CHECKERS
           </div>
           <button 
             onClick={initGame}
             className="px-10 py-5 bg-green-500 hover:bg-green-400 text-white rounded-full font-black text-2xl shadow-[0_8px_0_rgb(21,128,61)] hover:shadow-[0_6px_0_rgb(21,128,61)] hover:translate-y-[2px] active:shadow-none active:translate-y-[8px] transition-all transform hover:scale-105"
           >
             PLAY GAME
           </button>
        </div>
      )}

      {gameState === 'winner' && (
        <div className="absolute inset-0 bg-slate-900/90 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in">
           <div className="text-yellow-400 text-8xl mb-6 animate-bounce">🏆</div>
           <h2 className="text-6xl font-black text-white mb-2 drop-shadow-lg text-center">
             {winner?.toUpperCase()} WINS!
           </h2>
           <p className="text-slate-300 mb-10 font-bold text-2xl">
             Incredible Strategy!
           </p>
           <button 
             onClick={initGame}
             className="px-10 py-5 bg-blue-500 hover:bg-blue-400 text-white rounded-full font-black text-2xl shadow-[0_8px_0_rgb(30,58,138)] hover:shadow-[0_6px_0_rgb(30,58,138)] hover:translate-y-[2px] active:shadow-none active:translate-y-[8px] transition-all transform hover:scale-105"
           >
             PLAY AGAIN
           </button>
        </div>
      )}

      {/* Footer Instructions */}
      <div className="absolute bottom-2 text-slate-500 text-[10px] md:text-xs font-bold tracking-widest uppercase opacity-50 pointer-events-none">
         {turn === 'blue' ? 'Blue' : 'Red'} to move
      </div>

    </div>
  );
};

export default App;

import React, { useEffect, useState, useMemo } from 'react';
import { Piece, Position } from '../types';

interface ToonPieceProps {
  piece: Piece;
  isSelected: boolean;
  canMove: boolean;
  onClick: () => void;
  focusTarget: Position | null; // The tile currently being moved TO
}

const ToonPiece: React.FC<ToonPieceProps> = ({ piece, isSelected, onClick, canMove, focusTarget }) => {
  const [mood, setMood] = useState<'idle' | 'happy' | 'surprised' | 'focused'>('idle');

  // Calculate eye direction relative to the active move
  const lookAtStyle = useMemo(() => {
    if (!focusTarget || isSelected) return { x: 0, y: 0, rotate: 0 };

    const dy = focusTarget.row - piece.position.row;
    const dx = focusTarget.col - piece.position.col;

    // Don't look at self if I am the one moving (handled by isSelected usually, but safeguard)
    if (dx === 0 && dy === 0) return { x: 0, y: 0, rotate: 0 };

    // Calculate normalized direction for eyes (max movement 4px)
    const distance = Math.sqrt(dx * dx + dy * dy) || 1;
    const moveX = (dx / distance) * 5; 
    const moveY = (dy / distance) * 4;

    // Slight body rotation towards the event (max 10 degrees)
    // If target is right, rotate right (positive).
    const rotation = (dx / distance) * 10;

    return { x: moveX, y: moveY, rotate: rotation };
  }, [focusTarget, piece.position, isSelected]);

  useEffect(() => {
    if (isSelected) {
      setMood('surprised');
    } else if (piece.isKing) {
      setMood('happy');
    } else if (focusTarget) {
      // If watching a move, look focused
      setMood('focused');
    } else {
      setMood('idle');
    }
  }, [isSelected, piece.isKing, focusTarget]);

  // Colors
  const baseColor = piece.player === 'red' ? 'bg-rose-500' : 'bg-sky-500';
  const rimColor = piece.player === 'red' ? 'border-rose-300' : 'border-sky-300';
  const glow = isSelected ? 'ring-4 ring-yellow-400 scale-110 z-20' : '';

  // Dynamic transform for the whole body to lean/turn
  const bodyTransform = focusTarget && !isSelected 
    ? `rotate(${lookAtStyle.rotate}deg) scale(1.02)` 
    : 'rotate(0deg)';

  return (
    <div 
      onClick={(e) => {
        e.stopPropagation();
        onClick();
      }}
      className={`
        relative w-[80%] h-[80%] rounded-full cursor-pointer
        transition-all duration-500 ease-[cubic-bezier(0.34,1.56,0.64,1)]
        ${baseColor} ${rimColor} border-2
        shadow-[inset_-4px_-6px_10px_rgba(0,0,0,0.4),0_6px_0px_rgba(0,0,0,0.3)]
        ${glow}
        flex items-center justify-center
        group
        ${canMove ? 'hover:-translate-y-1 hover:brightness-110' : ''}
      `}
      style={{
        transform: isSelected ? undefined : bodyTransform // Don't override hover/select transforms if possible, but React style overrides class
      }}
    >
      {/* Glossy Reflection */}
      <div className="absolute top-2 left-1/4 w-1/2 h-1/3 bg-white opacity-20 rounded-full blur-[1px] pointer-events-none"></div>

      {/* Face Container */}
      <div className="relative w-full h-full flex flex-col items-center justify-center mt-1 pointer-events-none">

        {/* Eyes */}
        <div className="flex gap-2 mb-1 transition-transform duration-300" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
          {/* Left Eye */}
          <div className="relative w-3 h-4 bg-white rounded-full animate-blink overflow-hidden">
            <div className={`absolute w-1.5 h-1.5 bg-black rounded-full top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 
              ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
          </div>
          {/* Right Eye */}
          <div className="relative w-3 h-4 bg-white rounded-full animate-blink overflow-hidden" style={{ animationDelay: '0.1s' }}>
            <div className={`absolute w-1.5 h-1.5 bg-black rounded-full top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 
              ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
          </div>
        </div>

        {/* Mouth */}
        <div className={`
          w-4 h-2 bg-black/70 rounded-b-full transition-all duration-300
          ${mood === 'surprised' ? 'h-3 w-3 rounded-full' : ''}
          ${mood === 'happy' ? 'h-3 w-5 rounded-b-xl border-t-0' : ''}
          ${mood === 'focused' ? 'w-3 h-1.5 rounded-full scale-90' : ''}
        `}
        style={{ transform: `translate(${lookAtStyle.x * 0.5}px, ${lookAtStyle.y * 0.5}px)` }}
        ></div>

      </div>

      {/* Crown for King */}
      {piece.isKing && (
        <div className="absolute -top-6 left-1/2 transform -translate-x-1/2 w-8 h-8 animate-float z-30 pointer-events-none">
           <svg viewBox="0 0 24 24" fill="none" className="w-full h-full drop-shadow-lg filter animate-crown">
             <path d="M2 18h20v2H2v-2zm0-2l4-8 4 6 4-6 4 8H2z" fill="#FFD700" stroke="#B8860B" strokeWidth="1.5" strokeLinejoin="round"/>
             <circle cx="6" cy="6" r="1" fill="#FFF" />
             <circle cx="12" cy="10" r="1" fill="#FFF" />
             <circle cx="18" cy="6" r="1" fill="#FFF" />
           </svg>
           {/* Sparkles */}
           <div className="absolute -top-1 -right-2 text-yellow-300 text-xs font-bold animate-pulse">✦</div>
           <div className="absolute top-2 -left-2 text-yellow-300 text-[10px] font-bold animate-pulse" style={{animationDelay:'0.5s'}}>✦</div>
        </div>
      )}
    </div>
  );
};

export default ToonPiece;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import ToonPiece from './components/ToonPiece';
import { Piece, Position, Move, Player, GameState, Particle } from './types';
import { playSound } from './utils/audio';

// --- Constants ---
const BOARD_SIZE = 8;

const App: React.FC = () => {
  // --- State ---
  const [gameState, setGameState] = useState<GameState>('menu');
  const [board, setBoard] = useState<(Piece | null)[][]>([]);
  const [turn, setTurn] = useState<Player>('red'); // Red starts
  const [selectedPieceId, setSelectedPieceId] = useState<string | null>(null);
  const [validMoves, setValidMoves] = useState<Move[]>([]);
  const [forcedCapture, setForcedCapture] = useState<string | null>(null); // ID of piece that MUST double jump
  const [scores, setScores] = useState({ red: 0, blue: 0 });
  const [particles, setParticles] = useState<Particle[]>([]);
  const [winner, setWinner] = useState<Player | null>(null);
  const [comboCount, setComboCount] = useState(0);

  // Tracks where a move is currently landing so other pieces can look at it
  const [activeMoveTarget, setActiveMoveTarget] = useState<Position | null>(null);

  // --- Initialization ---
  const initGame = () => {
    const newBoard: (Piece | null)[][] = Array(BOARD_SIZE).fill(null).map(() => Array(BOARD_SIZE).fill(null));
    let idCounter = 0;

    for (let row = 0; row < BOARD_SIZE; row++) {
      for (let col = 0; col < BOARD_SIZE; col++) {
        if ((row + col) % 2 === 1) {
          if (row < 3) {
            newBoard[row][col] = { id: `blue-${idCounter++}`, player: 'blue', isKing: false, position: { row, col }, isCaptured: false };
          } else if (row > 4) {
            newBoard[row][col] = { id: `red-${idCounter++}`, player: 'red', isKing: false, position: { row, col }, isCaptured: false };
          }
        }
      }
    }
    setBoard(newBoard);
    setTurn('red');
    setScores({ red: 12, blue: 12 });
    setGameState('playing');
    setWinner(null);
    setForcedCapture(null);
    setSelectedPieceId(null);
    setValidMoves([]);
    setComboCount(0);
    setActiveMoveTarget(null);
    playSound.move();
  };

  // --- Logic Helper Functions ---

  const getPieceAt = (b: (Piece | null)[][], pos: Position) => {
    if (pos.row < 0 || pos.row >= BOARD_SIZE || pos.col < 0 || pos.col >= BOARD_SIZE) return null;
    return b[pos.row][pos.col];
  };

  const calculateValidMoves = (piece: Piece, currentBoard: (Piece | null)[][]): Move[] => {
    const moves: Move[] = [];
    const directions = piece.isKing 
      ? [[-1, -1], [-1, 1], [1, -1], [1, 1]] 
      : piece.player === 'red' ? [[-1, -1], [-1, 1]] : [[1, -1], [1, 1]];

    directions.forEach(([dRow, dCol]) => {
      // 1. Simple Move
      const targetPos = { row: piece.position.row + dRow, col: piece.position.col + dCol };
      if (
        targetPos.row >= 0 && targetPos.row < BOARD_SIZE &&
        targetPos.col >= 0 && targetPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, targetPos)
      ) {
         // Only allow simple move if NOT currently in a forced capture sequence
         moves.push({ from: piece.position, to: targetPos, isJump: false });
      }

      // 2. Jump (Capture)
      const jumpPos = { row: piece.position.row + (dRow * 2), col: piece.position.col + (dCol * 2) };
      if (
        jumpPos.row >= 0 && jumpPos.row < BOARD_SIZE &&
        jumpPos.col >= 0 && jumpPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, jumpPos)
      ) {
        const midPos = targetPos;
        const midPiece = getPieceAt(currentBoard, midPos);
        if (midPiece && midPiece.player !== piece.player) {
          moves.push({ 
            from: piece.position, 
            to: jumpPos, 
            isJump: true, 
            capturedPieceId: midPiece.id, 
            jumpedPosition: midPos 
          });
        }
      }
    });

    return moves;
  };

  const getAllValidMovesForPlayer = (player: Player, currentBoard: (Piece | null)[][]) => {
    let allMoves: { pieceId: string, move: Move }[] = [];
    let hasJump = false;

    // Iterate board to find all player pieces
    for(let r=0; r<BOARD_SIZE; r++){
      for(let c=0; c<BOARD_SIZE; c++){
        const p = currentBoard[r][c];
        if(p && p.player === player && !p.isCaptured){
          const moves = calculateValidMoves(p, currentBoard);
          moves.forEach(m => {
            if(m.isJump) hasJump = true;
            allMoves.push({ pieceId: p.id, move: m });
          });
        }
      }
    }

    // Forced capture rule: If a jump exists, remove non-jumps
    if (hasJump) {
      allMoves = allMoves.filter(m => m.move.isJump);
    }

    return { allMoves, hasJump };
  };

  // --- Interaction ---

  const handleSquareClick = (row: number, col: number) => {
    if (gameState !== 'playing') return;

    const clickedPiece = board[row][col];
    const isCurrentPlayerPiece = clickedPiece?.player === turn;

    // 1. Selecting a piece
    if (isCurrentPlayerPiece) {
      if (forcedCapture && forcedCapture !== clickedPiece.id) {
        playSound.error();
        return; // Must play the forced piece
      }

      // Calculate moves for this piece
      const { allMoves, hasJump } = getAllValidMovesForPlayer(turn, board);

      // If forced jumps exist globally, can only select pieces that can jump
      if (hasJump) {
         const canThisJump = allMoves.some(m => m.pieceId === clickedPiece.id && m.move.isJump);
         if (!canThisJump) {
            playSound.error();
            return;
         }
      }

      setSelectedPieceId(clickedPiece.id);

      // Filter valid moves for just this piece
      const movesForPiece = allMoves
        .filter(m => m.pieceId === clickedPiece.id)
        .map(m => m.move);

      setValidMoves(movesForPiece);
      playSound.move();
      return;
    }

    // 2. Moving to an empty square (executing a move)
    if (!clickedPiece && selectedPieceId) {
      const move = validMoves.find(m => m.to.row === row && m.to.col === col);
      if (move) {
        executeMove(move);
      } else {
        // Deselect if clicking invalid empty square
        setSelectedPieceId(null);
        setValidMoves([]);
      }
    }
  };

  const executeMove = (move: Move) => {
    const piece = getPieceAt(board, move.from);
    if (!piece) return;

    // Trigger global "look at" event
    setActiveMoveTarget(move.to);
    setTimeout(() => setActiveMoveTarget(null), 800); // Stop looking after animation settles

    // Create deep copy for mutation
    const newBoard = board.map(row => row.map(p => p ? { ...p } : null));
    const movedPiece = newBoard[move.from.row][move.from.col]!;

    // Update position
    newBoard[move.from.row][move.from.col] = null;
    newBoard[move.to.row][move.to.col] = movedPiece;
    movedPiece.position = move.to;

    let justCaptured = false;

    // Handle Capture
    if (move.isJump && move.jumpedPosition) {
      const captured = newBoard[move.jumpedPosition.row][move.jumpedPosition.col];
      newBoard[move.jumpedPosition.row][move.jumpedPosition.col] = null; // Remove from board

      if (captured) {
        spawnParticles(move.to.row, move.to.col, "+1");
        setScores(prev => ({
          ...prev,
          [captured.player]: prev[captured.player] - 1
        }));
        justCaptured = true;
        setComboCount(c => c + 1);
        playSound.capture();
      }
    } else {
      setComboCount(0);
      playSound.move();
    }

    // Handle Promotion
    let promoted = false;
    if (!movedPiece.isKing) {
      if ((movedPiece.player === 'red' && move.to.row === 0) ||
          (movedPiece.player === 'blue' && move.to.row === BOARD_SIZE - 1)) {
        movedPiece.isKing = true;
        promoted = true;
        playSound.king();
        spawnParticles(move.to.row, move.to.col, "KING!", true);
      }
    }

    setBoard(newBoard);
    setSelectedPieceId(null);
    setValidMoves([]);

    // Multi-jump Logic
    if (justCaptured && !promoted) {
      // Check if this specific piece can jump again
      const nextMoves = calculateValidMoves(movedPiece, newBoard).filter(m => m.isJump);
      if (nextMoves.length > 0) {
        // Must continue with this piece
        setForcedCapture(movedPiece.id);
        setSelectedPieceId(movedPiece.id);
        setValidMoves(nextMoves);
        return; // Turn does NOT change
      }
    }

    // End Turn
    endTurn(newBoard);
  };

  const endTurn = (currentBoard: (Piece | null)[][]) => {
    setForcedCapture(null);
    setComboCount(0);
    const nextPlayer = turn === 'red' ? 'blue' : 'red';

    // Check win condition (count pieces or no moves)
    const { allMoves } = getAllValidMovesForPlayer(nextPlayer, currentBoard);

    if (allMoves.length === 0) {
      setWinner(turn); // Current player wins because next has no moves
      setGameState('winner');
      playSound.win();
    } else {
      setTurn(nextPlayer);
    }
  };

  // --- Effects & Visuals ---

  const spawnParticles = (row: number, col: number, text?: string, gold: boolean = false) => {
    const id = Date.now().toString() + Math.random();
    setParticles(prev => [...prev, { id, row, col, color: gold ? '#FFD700' : '#FFF', text }]);

    // Cleanup
    setTimeout(() => {
      setParticles(prev => prev.filter(p => p.id !== id));
    }, 1200);
  };

  // Render Helpers
  const renderSquare = (row: number, col: number) => {
    const isBlack = (row + col) % 2 === 1;
    const piece = board[row][col];

    // Highlights
    const isPossibleMove = validMoves.some(m => m.to.row === row && m.to.col === col);
    const isSource = selectedPieceId && piece && piece.id === selectedPieceId;

    // Particles for this square
    const cellParticles = particles.filter(p => p.row === row && p.col === col);

    return (
      <div 
        key={`${row}-${col}`}
        onClick={() => handleSquareClick(row, col)}
        className={`
          relative w-full h-full flex items-center justify-center
          ${isBlack ? 'bg-slate-800' : 'bg-slate-200'}
          ${isPossibleMove ? 'ring-inset ring-4 ring-green-400 cursor-pointer' : ''}
          /* Subtle internal borders for texture */
          ${isBlack ? 'shadow-[inset_0_0_10px_rgba(0,0,0,0.5)]' : 'shadow-[inset_0_0_10px_rgba(255,255,255,0.5)]'}
        `}
      >
        {/* Cell Highlight for Possible Move */}
        {isPossibleMove && (
          <div className="absolute inset-2 bg-green-400 rounded-full animate-pulse opacity-40"></div>
        )}

        {/* Piece */}
        {piece && (
          <div className={`w-full h-full p-1.5 z-10 transition-transform duration-300 ${isSource ? 'scale-110' : ''}`}>
             <ToonPiece 
                piece={piece} 
                isSelected={!!isSource} 
                canMove={turn === piece.player}
                focusTarget={activeMoveTarget}
                onClick={() => handleSquareClick(row, col)} 
             />
          </div>
        )}

        {/* Floating Particles in Cell */}
        {cellParticles.map(p => (
           <div key={p.id} className="absolute inset-0 flex items-center justify-center z-50 pointer-events-none">
              <div className="animate-pop flex flex-col items-center">
                 {/* Sparkle graphic */}
                 <div className="text-3xl filter drop-shadow-md">💥</div>
                 {/* Text */}
                 {p.text && (
                   <span className="text-xl font-black text-white stroke-black drop-shadow-[0_2px_0_rgba(0,0,0,0.8)]" style={{color: p.color}}>
                     {p.text}
                   </span>
                 )}
              </div>
           </div>
        ))}
      </div>
    );
  };

  return (
    <div className="min-h-screen h-[100dvh] bg-slate-900 flex flex-col items-center justify-center text-white relative overflow-hidden select-none touch-none">

      {/* Background Ambience */}
      <div className="absolute inset-0 opacity-20 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900 via-slate-900 to-black pointer-events-none"></div>

      {/* Header / UI - Adaptive Flex Layout */}
      <div className="relative w-full max-w-4xl flex flex-col md:flex-row items-center justify-center md:justify-between gap-4 p-4 z-10 flex-shrink-0">

        {/* Blue Player Stats (Left/Top) */}
        <div className={`
          flex items-center gap-4 transition-all duration-300 order-2 md:order-1
          ${turn === 'blue' ? 'opacity-100 scale-105' : 'opacity-60 scale-95 grayscale'}
        `}>
          <div className="w-14 h-14 md:w-20 md:h-20 bg-sky-500 rounded-full border-4 border-white shadow-lg flex items-center justify-center relative overflow-hidden">
             <div className="absolute w-3 h-3 bg-white rounded-full top-3 left-3 opacity-50"></div>
             <span className="text-2xl md:text-3xl font-black">{scores.blue}</span>
          </div>
          <div className="hidden md:block font-bold text-sky-300 text-xl tracking-wider">BLUE</div>
        </div>

        {/* Title & Game Info (Center) */}
        <div className="flex flex-col items-center order-1 md:order-2 mb-2 md:mb-0">
          <h1 className="text-3xl md:text-5xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500 drop-shadow-sm tracking-tighter">
            CHECKERS
          </h1>
          <div className="bg-slate-800/80 backdrop-blur px-6 py-1.5 rounded-full text-xs md:text-sm font-bold text-slate-300 mt-2 uppercase tracking-widest border border-slate-700 shadow-xl">
             {gameState === 'playing' ? (
                <span className={turn === 'red' ? 'text-rose-400' : 'text-sky-400'}>
                   {turn.toUpperCase()}'S TURN
                </span>
             ) : 'GAME OVER'}
          </div>
        </div>

        {/* Red Player Stats (Right/Bottom) */}
        <div className={`
          flex items-center gap-4 transition-all duration-300 order-3
          ${turn === 'red' ? 'opacity-100 scale-105' : 'opacity-60 scale-95 grayscale'}
        `}>
          <div className="md:hidden font-bold text-rose-300 text-xl tracking-wider"></div> 
          <div className="hidden md:block font-bold text-rose-300 text-xl tracking-wider text-right">RED</div>
          <div className="w-14 h-14 md:w-20 md:h-20 bg-rose-500 rounded-full border-4 border-white shadow-lg flex items-center justify-center relative overflow-hidden">
            <div className="absolute w-3 h-3 bg-white rounded-full top-3 right-3 opacity-50"></div>
            <span className="text-2xl md:text-3xl font-black">{scores.red}</span>
          </div>
        </div>
      </div>

      {/* Combo Indicator */}
      {comboCount > 1 && (
        <div className="absolute top-[20%] z-50 animate-pop pointer-events-none">
          <span className="text-5xl md:text-6xl font-black text-yellow-400 drop-shadow-[0_4px_0_rgba(0,0,0,1)] stroke-black" style={{WebkitTextStroke: '2px black'}}>
            COMBO x{comboCount}!
          </span>
        </div>
      )}

      {/* Main Game Area - Perfectly Centered & Responsive */}
      <main className="relative z-10 flex items-center justify-center p-2 md:p-4 w-full h-full flex-grow">
        <div className={`
          relative
          /* The Magic Responsive Formula: */
          w-[min(90vw,90vw)]
          h-[min(90vw,90vw)]
          md:w-[min(600px,75vmin)] 
          md:h-[min(600px,75vmin)]
          bg-slate-950 p-3 rounded-2xl shadow-2xl border-b-[8px] border-slate-950
          transition-all duration-700
          perspective-board
          ${gameState === 'winner' ? 'scale-90 blur-sm' : ''}
        `}>
          <div className="w-full h-full bg-slate-800 rounded-xl overflow-hidden grid grid-cols-8 grid-rows-8 shadow-inner ring-4 ring-slate-800">
            {board.map((row, r) => row.map((_, c) => renderSquare(r, c)))}
          </div>
        </div>
      </main>

      {/* Menus / Overlays */}
      {gameState === 'menu' && (
        <div className="absolute inset-0 bg-slate-900/90 z-50 flex flex-col items-center justify-center backdrop-blur-md">
           <div className="text-5xl md:text-7xl font-black text-white mb-8 tracking-tighter drop-shadow-xl animate-float text-center px-4">
             TOON CHECKERS
           </div>
           <button 
             onClick={initGame}
             className="px-10 py-5 bg-green-500 hover:bg-green-400 text-white rounded-full font-black text-2xl shadow-[0_8px_0_rgb(21,128,61)] hover:shadow-[0_6px_0_rgb(21,128,61)] hover:translate-y-[2px] active:shadow-none active:translate-y-[8px] transition-all transform hover:scale-105"
           >
             PLAY GAME
           </button>
        </div>
      )}

      {gameState === 'winner' && (
        <div className="absolute inset-0 bg-slate-900/90 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in">
           <div className="text-yellow-400 text-8xl mb-6 animate-bounce">🏆</div>
           <h2 className="text-6xl font-black text-white mb-2 drop-shadow-lg text-center">
             {winner?.toUpperCase()} WINS!
           </h2>
           <p className="text-slate-300 mb-10 font-bold text-2xl">
             Incredible Strategy!
           </p>
           <button 
             onClick={initGame}
             className="px-10 py-5 bg-blue-500 hover:bg-blue-400 text-white rounded-full font-black text-2xl shadow-[0_8px_0_rgb(30,58,138)] hover:shadow-[0_6px_0_rgb(30,58,138)] hover:translate-y-[2px] active:shadow-none active:translate-y-[8px] transition-all transform hover:scale-105"
           >
             PLAY AGAIN
           </button>
        </div>
      )}

      {/* Footer Instructions */}
      <div className="absolute bottom-2 text-slate-500 text-[10px] md:text-xs font-bold tracking-widest uppercase opacity-50 pointer-events-none">
         {turn === 'blue' ? 'Blue' : 'Red'} to move
      </div>

    </div>
  );
};

export default App;

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { Piece, Position } from '../types';

interface ToonPieceProps {
  piece: Piece;
  isSelected: boolean;
  canMove: boolean;
  onClick: () => void;
  focusTarget: Position | null; // The tile currently being moved TO
}

type IdleAction = 'none' | 'look-left' | 'look-right' | 'smirk' | 'ooh' | 'suspicious' | 'wiggle';

const ToonPiece: React.FC<ToonPieceProps> = ({ piece, isSelected, onClick, canMove, focusTarget }) => {
  const [mood, setMood] = useState<'idle' | 'happy' | 'surprised' | 'focused'>('idle');
  const [idleAction, setIdleAction] = useState<IdleAction>('none');
  const timerRef = useRef<number>(0);

  // --- Logic: Random Idle Expressions ---
  useEffect(() => {
    // If active interaction is happening, cancel random behavior
    if (isSelected || focusTarget) {
      setIdleAction('none');
      if (timerRef.current) clearTimeout(timerRef.current);
      return;
    }

    const triggerRandomness = () => {
      // Random time between 2s and 6s
      const timeToNext = Math.random() * 4000 + 2000;

      timerRef.current = window.setTimeout(() => {
        // Pick a random action
        const actions: IdleAction[] = ['look-left', 'look-right', 'smirk', 'ooh', 'suspicious', 'wiggle', 'none', 'none'];
        const picked = actions[Math.floor(Math.random() * actions.length)];

        setIdleAction(picked);

        // Reset to none after a short duration (e.g. 1.5s glance)
        if (picked !== 'none') {
            setTimeout(() => {
                // Check if we are still allowed to change state (might have been selected in the meantime)
                setIdleAction(prev => (prev === picked ? 'none' : prev));
            }, 1000 + Math.random() * 1000);
        }

        // Recursively trigger next
        triggerRandomness();
      }, timeToNext);
    };

    triggerRandomness();

    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [isSelected, focusTarget, piece.id]);


  // --- Logic: Eye Tracking ---
  const lookAtStyle = useMemo(() => {
    // 1. Priority: Active Logic (Focus Target)
    if (focusTarget && !isSelected) {
      const dy = focusTarget.row - piece.position.row;
      const dx = focusTarget.col - piece.position.col;
      const distance = Math.sqrt(dx * dx + dy * dy) || 1;
      return { 
        x: (dx / distance) * 5, 
        y: (dy / distance) * 4, 
        rotate: (dx / distance) * 10 
      };
    }

    // 2. Priority: Random Idle Actions
    if (idleAction === 'look-left') return { x: -4, y: 0, rotate: -5 };
    if (idleAction === 'look-right') return { x: 4, y: 0, rotate: 5 };
    if (idleAction === 'suspicious') return { x: 0, y: -1, rotate: 0 }; // Squint look

    // Default
    return { x: 0, y: 0, rotate: 0 };
  }, [focusTarget, piece.position, isSelected, idleAction]);


  // --- Logic: Mood State ---
  useEffect(() => {
    if (isSelected) {
      setMood('surprised');
    } else if (piece.isKing) {
      setMood('happy');
    } else if (focusTarget) {
      setMood('focused');
    } else {
      setMood('idle');
    }
  }, [isSelected, piece.isKing, focusTarget]);

  // --- Visuals ---
  const baseColor = piece.player === 'red' ? 'bg-rose-500' : 'bg-sky-500';
  const rimColor = piece.player === 'red' ? 'border-rose-300' : 'border-sky-300';
  const glow = isSelected ? 'ring-4 ring-yellow-400 scale-110 z-20' : '';

  // Wiggle calculation
  const isWiggling = idleAction === 'wiggle' && !isSelected && !focusTarget;
  const wiggleStyle = isWiggling ? 'animate-[float_0.5s_ease-in-out_infinite]' : ''; // Reusing float or custom wiggle

  // Dynamic transform
  const bodyTransform = (focusTarget && !isSelected) || idleAction !== 'none'
    ? `rotate(${lookAtStyle.rotate}deg) scale(1.02)` 
    : 'rotate(0deg)';

  return (
    <div 
      onClick={(e) => {
        e.stopPropagation();
        onClick();
      }}
      className={`
        relative w-[80%] h-[80%] rounded-full cursor-pointer
        transition-all duration-500 ease-[cubic-bezier(0.34,1.56,0.64,1)]
        ${baseColor} ${rimColor} border-2
        shadow-[inset_-4px_-6px_10px_rgba(0,0,0,0.4),0_6px_0px_rgba(0,0,0,0.3)]
        ${glow}
        flex items-center justify-center
        group
        ${canMove ? 'hover:-translate-y-1 hover:brightness-110' : ''}
        ${wiggleStyle}
      `}
      style={{
        transform: isSelected ? undefined : bodyTransform 
      }}
    >
      {/* Glossy Reflection */}
      <div className="absolute top-2 left-1/4 w-1/2 h-1/3 bg-white opacity-20 rounded-full blur-[1px] pointer-events-none"></div>

      {/* Face Container */}
      <div className="relative w-full h-full flex flex-col items-center justify-center mt-1 pointer-events-none">

        {/* Eyes */}
        <div className="flex gap-2 mb-1 transition-transform duration-300" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
          {/* Left Eye */}
          <div className={`
             relative w-3 h-4 bg-white rounded-full overflow-hidden transition-all duration-300
             ${idleAction === 'suspicious' ? 'h-2 mt-1' : 'animate-blink'}
          `}>
            <div className={`absolute w-1.5 h-1.5 bg-black rounded-full top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 
              ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
          </div>
          {/* Right Eye */}
          <div className={`
             relative w-3 h-4 bg-white rounded-full overflow-hidden transition-all duration-300
             ${idleAction === 'suspicious' ? 'h-2 mt-1' : 'animate-blink'}
          `} style={{ animationDelay: '0.1s' }}>
            <div className={`absolute w-1.5 h-1.5 bg-black rounded-full top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 
              ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
          </div>
        </div>

        {/* Mouth */}
        <div className={`
          bg-black/70 transition-all duration-300
          ${mood === 'surprised' || idleAction === 'ooh' ? 'h-3 w-3 rounded-full' : 'w-4 h-2 rounded-b-full'}
