const ToonPiece: React.FC<ToonPieceProps> = ({ piece, isSelected, onClick, canMove, focusTarget }) => {
  const [mood, setMood] = useState<'idle' | 'happy' | 'surprised' | 'focused' | 'evil'>('idle');
  const [idleAction, setIdleAction] = useState<IdleAction>('none');
  const [justBecameKing, setJustBecameKing] = useState(false);
  const timerRef = useRef<number>(0);
  const prevIsKingRef = useRef(piece.isKing);

  // --- Logic: Detect Promotion ---
  useEffect(() => {
    if (piece.isKing && !prevIsKingRef.current) {
        setJustBecameKing(true);
        setTimeout(() => setJustBecameKing(false), 2000); // Reset after animation
    }
    prevIsKingRef.current = piece.isKing;
  }, [piece.isKing]);


  // --- Logic: Random Idle Expressions ---
  useEffect(() => {
    // If active interaction is happening, cancel random behavior
    if (isSelected || focusTarget) {
      setIdleAction('none');
      if (timerRef.current) clearTimeout(timerRef.current);
      return;
    }

    const triggerRandomness = () => {
      // Random time between 2s and 6s
      const timeToNext = Math.random() * 4000 + 2000;

      timerRef.current = window.setTimeout(() => {
        // Pick a random action
        const actions: IdleAction[] = ['look-left', 'look-right', 'smirk', 'ooh', 'suspicious', 'wiggle', 'none', 'none'];
        const picked = actions[Math.floor(Math.random() * actions.length)];

        setIdleAction(picked);

        // Reset to none after a short duration (e.g. 1.5s glance)
        if (picked !== 'none') {
            setTimeout(() => {
                // Check if we are still allowed to change state (might have been selected in the meantime)
                setIdleAction(prev => (prev === picked ? 'none' : prev));
            }, 1000 + Math.random() * 1000);
        }

        // Recursively trigger next
        triggerRandomness();
      }, timeToNext);
    };

    triggerRandomness();

    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [isSelected, focusTarget, piece.id]);


  // --- Logic: Eye Tracking ---
  const lookAtStyle = useMemo(() => {
    // 1. Priority: Active Logic (Focus Target)
    if (focusTarget && !isSelected) {
      const dy = focusTarget.row - piece.position.row;
      const dx = focusTarget.col - piece.position.col;
      const distance = Math.sqrt(dx * dx + dy * dy) || 1;
      return { 
        x: (dx / distance) * 6, 
        y: (dy / distance) * 5, 
        rotate: (dx / distance) * 10 
      };
    }

    // 2. Priority: Random Idle Actions
    if (idleAction === 'look-left') return { x: -5, y: 0, rotate: -5 };
    if (idleAction === 'look-right') return { x: 5, y: 0, rotate: 5 };
    if (idleAction === 'suspicious') return { x: 0, y: -1, rotate: 0 }; // Squint look

    // Default
    return { x: 0, y: 0, rotate: 0 };
  }, [focusTarget, piece.position, isSelected, idleAction]);


  // --- Logic: Mood State ---
  useEffect(() => {
    if (isSelected) {
      setMood('surprised');
    } else if (piece.isKing) {
      setMood('evil'); // Kings are evil/bossy!
    } else if (focusTarget) {
      setMood('focused');
    } else {
      setMood('idle');
    }
  }, [isSelected, piece.isKing, focusTarget]);

  // --- Visuals: 2.5D Styles ---
  const isRed = piece.player === 'red';

  // Gradients and Colors
  const bgGradient = isRed 
    ? 'bg-gradient-to-br from-rose-400 via-rose-500 to-rose-600' 
    : 'bg-gradient-to-br from-sky-400 via-sky-500 to-sky-600';

  const sideColor = isRed ? '#9f1239' : '#0369a1'; // darker shade for the "side" thickness

  // Wiggle calculation
  const isWiggling = idleAction === 'wiggle' && !isSelected && !focusTarget;
  // King Floating: Always float if King, unless selected
  const isKingFloating = piece.isKing && !isSelected;

  // Transform Logic
  // Merge the "Look At" rotation with the "Lift" selection state
  const baseRotation = (focusTarget && !isSelected) || idleAction !== 'none' ? lookAtStyle.rotate : 0;

  // We apply transforms via inline style to allow stacking
  const transformStyle = isSelected 
    ? `translateY(-12px) scale(1.1) rotate(${baseRotation}deg)` 
    : `translateY(0px) rotate(${baseRotation}deg)`;

  return (
    <div 
      onClick={(e) => {
        e.stopPropagation();
        onClick();
      }}
      className={`
        relative w-[85%] h-[85%] rounded-full cursor-pointer group
        transition-all duration-500 ease-[cubic-bezier(0.34,1.56,0.64,1)]
        flex items-center justify-center
        ${canMove ? 'hover:-translate-y-2' : ''} 
      `}
      style={{
        transform: transformStyle,
        zIndex: isSelected ? 50 : 10
      }}
    >
        {/* INNER CONTAINER: Handles Float Animations (Wiggle or King Float) and Visual Body */}
        <div className={`
            w-full h-full rounded-full flex items-center justify-center relative
            ${bgGradient}
            ${isWiggling ? 'animate-[float_0.5s_ease-in-out_infinite]' : ''}
            ${isKingFloating ? 'animate-king-float' : ''}
            ${justBecameKing ? 'animate-levitate-once' : ''}
        `}
        style={{
            // 2.5D CSS Shadow Stack applied here to move with the float
            boxShadow: isSelected 
            ? `inset 0 4px 10px rgba(255,255,255,0.5), inset 0 -6px 12px rgba(0,0,0,0.2), 0 16px 0 ${sideColor}, 0 24px 20px rgba(0,0,0,0.4)`
            : `inset 0 4px 6px rgba(255,255,255,0.4), inset 0 -4px 8px rgba(0,0,0,0.2), 0 6px 0 ${sideColor}, 0 8px 6px rgba(0,0,0,0.3)`,
        }}
        >

            {/* Texture: Checker Grooves (Concentric Circles) */}
            <div className="absolute inset-2 rounded-full border-4 border-black/10 opacity-50 pointer-events-none"></div>
            <div className="absolute inset-4 rounded-full border-2 border-white/10 opacity-30 pointer-events-none"></div>

            {/* Glossy Specular Highlight (The 'Plastic' look) */}
            <div className="absolute top-3 left-1/4 w-1/2 h-1/4 bg-gradient-to-b from-white to-transparent opacity-40 rounded-full blur-[2px] pointer-events-none"></div>

            {/* Selection Ring (Golden Glow) */}
            {isSelected && (
                <div className="absolute -inset-1 rounded-full border-4 border-yellow-300 animate-pulse opacity-70 pointer-events-none"></div>
            )}

            {/* Face Container */}
            <div className="relative w-full h-full flex flex-col items-center justify-center mt-1 pointer-events-none z-10">

                {/* Eyebrows for expressions (mainly Evil/King) */}
                <div className="absolute top-[30%] flex gap-2 transition-transform duration-300 z-20" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
                    {/* Left Brow */}
                    <div className={`w-2.5 h-1 bg-black/70 rounded-full transition-all duration-300 origin-right
                        ${mood === 'evil' ? 'rotate-[25deg] translate-y-0.5 opacity-100' : 'opacity-0'}
                        ${mood === 'focused' ? 'rotate-0 translate-y-0 opacity-0' : ''} 
                    `}></div>
                    {/* Right Brow */}
                    <div className={`w-2.5 h-1 bg-black/70 rounded-full transition-all duration-300 origin-left
                        ${mood === 'evil' ? '-rotate-[25deg] translate-y-0.5 opacity-100' : 'opacity-0'}
                        ${mood === 'focused' ? 'rotate-0 translate-y-0 opacity-0' : ''}
                    `}></div>
                </div>

                {/* Eyes */}
                <div className="flex gap-1 mb-1 transition-transform duration-300" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
                {/* Left Eye */}
                <div className={`
                    relative w-4 bg-white rounded-full overflow-hidden transition-all duration-300 shadow-sm border border-black/5
                    ${mood === 'evil' ? 'h-3.5 mt-1.5' : (idleAction === 'suspicious' ? 'h-2.5 mt-2.5' : 'h-5 animate-blink')}
                `}>
                    <div className={`absolute w-2 h-2 bg-slate-900 rounded-full top-[45%] left-1/2 transform -translate-x-1/2 -translate-y-1/2 
                    ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
                    {/* Eye glimmer */}
                    <div className="absolute top-0.5 right-0.5 w-1 h-1 bg-white rounded-full opacity-80"></div>
                </div>
                {/* Right Eye */}
                <div className={`
                    relative w-4 bg-white rounded-full overflow-hidden transition-all duration-300 shadow-sm border border-black/5
                    ${mood === 'evil' ? 'h-3.5 mt-1.5' : (idleAction === 'suspicious' ? 'h-2.5 mt-2.5' : 'h-5 animate-blink')}
                `} style={{ animationDelay: '0.1s' }}>
                    <div className={`absolute w-2 h-2 bg-slate-900 rounded-full top-[45%] left-1/2 transform -translate-x-1/2 -translate-y-1/2 
                    ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
                    {/* Eye glimmer */}
                    <div className="absolute top-0.5 right-0.5 w-1 h-1 bg-white rounded-full opacity-80"></div>
                </div>
                </div>

                {/* Mouth */}
                <div className={`
                bg-slate-900/80 transition-all duration-300 shadow-sm
                ${mood === 'surprised' || idleAction === 'ooh' ? 'h-3 w-3 rounded-full border-2 border-white/20' : 'w-4 h-2 rounded-b-full'}
                ${(mood === 'happy' || idleAction === 'smirk') ? 'h-3 w-6 rounded-b-xl border-t-0' : ''}
                ${mood === 'evil' ? 'w-5 h-2.5 rounded-b-full border-t-0' : ''}
                ${mood === 'focused' ? 'w-3 h-1.5 rounded-full scale-90' : ''}
                ${idleAction === 'suspicious' ? 'w-5 h-1 rounded-full' : ''}
                `}
                style={{ 
                    transform: `translate(${lookAtStyle.x * 0.5}px, ${lookAtStyle.y * 0.5}px) ${idleAction === 'smirk' || mood === 'evil' ? 'rotate(-5deg) translateX(1px)' : ''}` 
                }}>
                   {/* Evil Tooth */}
                   {mood === 'evil' && (
                       <div className="absolute top-0 left-0.5 w-1 h-1 bg-white rounded-b-full opacity-90"></div>
                   )}
                </div>

                {/* Blush */}
                {(mood === 'happy' || idleAction === 'smirk' || idleAction === 'ooh' || isSelected) && (
                    <>
                        <div className="absolute top-[65%] left-1 w-2.5 h-1.5 bg-rose-400 opacity-60 rounded-full blur-[2px]"></div>
                        <div className="absolute top-[65%] right-1 w-2.5 h-1.5 bg-rose-400 opacity-60 rounded-full blur-[2px]"></div>
                    </>
                )}

            </div>

            {/* Crown for King */}
            {piece.isKing && (
                <div className={`absolute -top-8 left-1/2 transform -translate-x-1/2 w-10 h-10 z-30 pointer-events-none ${justBecameKing ? 'animate-crown-enter' : 'animate-float'}`}>
                    {/* Glowing Aura for King */}
                    <div className="absolute inset-0 bg-yellow-400/30 rounded-full blur-md animate-pulse"></div>

                    <svg viewBox="0 0 24 24" fill="none" className="w-full h-full drop-shadow-xl filter animate-crown">
                        <path d="M2 18h20v2H2v-2zm0-2l4-8 4 6 4-6 4 8H2z" fill="url(#crownGradient)" stroke="#B8860B" strokeWidth="1" strokeLinejoin="round"/>
                        <defs>
                        <linearGradient id="crownGradient" x1="12" y1="2" x2="12" y2="20" gradientUnits="userSpaceOnUse">
                            <stop stopColor="#FFD700" />
                            <stop offset="1" stopColor="#F59E0B" />
                        </linearGradient>
                        </defs>
                        <circle cx="6" cy="6" r="1.5" fill="#FFF" className="animate-pulse" />
                        <circle cx="12" cy="10" r="1.5" fill="#FFF" className="animate-pulse" />
                        <circle cx="18" cy="6" r="1.5" fill="#FFF" className="animate-pulse" />
                    </svg>
                </div>
            )}
        </div>
    </div>
  );
};

export default ToonPiece;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import ToonPiece from './components/ToonPiece';
import { Piece, Position, Move, Player, GameState, Particle, GameMode, Difficulty } from './types';
import { playSound } from './utils/audio';

// --- Constants ---
const BOARD_SIZE = 8;
const AI_PLAYER: Player = 'blue';
const HUMAN_PLAYER: Player = 'red';

// --- Taunt Phrases (Zueira Lists) ---
const TAUNTS_SIMPLE = [
  "Tchau!", "Ops!", "Já era", "Vaza", "Perdeu", "Eita...", 
  "Xiu!", "Fácil", "Noob?", "Chora", "Sentou", "Sumiu", 
  "Kkkk", "Fraco", "Deu ruim", "Falou!", "Tankou?", "Ih..."
];

const TAUNTS_EPIC = [
  "SOLADO!", "AULA!", "RECEBA!", "QUE ISSO?", "SEGURA!", 
  "NEM VIU", "DESTRUIÇÃO", "CHORA MAIS", "COITADO", "MITO", 
  "LENDÁRIO", "NEM CLICOU", "DORMIU?", "TOMA!", "JOGA MUITO", "RESPEITA"
];

const App: React.FC = () => {
  // --- State ---
  const [gameState, setGameState] = useState<GameState>('menu');
  const [gameMode, setGameMode] = useState<GameMode>('pvp');
  const [difficulty, setDifficulty] = useState<Difficulty>('medium');
  const [showDifficultySelect, setShowDifficultySelect] = useState(false);

  const [board, setBoard] = useState<(Piece | null)[][]>([]);
  const [turn, setTurn] = useState<Player>('red'); // Red starts
  const [selectedPieceId, setSelectedPieceId] = useState<string | null>(null);
  const [validMoves, setValidMoves] = useState<Move[]>([]);
  const [forcedCapture, setForcedCapture] = useState<string | null>(null); // ID of piece that MUST double jump
  const [scores, setScores] = useState({ red: 0, blue: 0 });
  const [particles, setParticles] = useState<Particle[]>([]);
  const [winner, setWinner] = useState<Player | null>(null);
  const [comboCount, setComboCount] = useState(0);

  // Tracks where a move is currently landing so other pieces can look at it
  const [activeMoveTarget, setActiveMoveTarget] = useState<Position | null>(null);

  // AI Thinking State
  const [isAIThinking, setIsAIThinking] = useState(false);

  // --- Initialization ---
  const initGame = (mode: GameMode, diff: Difficulty = 'medium') => {
    const newBoard: (Piece | null)[][] = Array(BOARD_SIZE).fill(null).map(() => Array(BOARD_SIZE).fill(null));
    let idCounter = 0;

    for (let row = 0; row < BOARD_SIZE; row++) {
      for (let col = 0; col < BOARD_SIZE; col++) {
        if ((row + col) % 2 === 1) {
          if (row < 3) {
            newBoard[row][col] = { id: `blue-${idCounter++}`, player: 'blue', isKing: false, position: { row, col }, isCaptured: false };
          } else if (row > 4) {
            newBoard[row][col] = { id: `red-${idCounter++}`, player: 'red', isKing: false, position: { row, col }, isCaptured: false };
          }
        }
      }
    }
    setBoard(newBoard);
    setTurn('red');
    setGameMode(mode);
    setDifficulty(diff);
    setScores({ red: 12, blue: 12 });
    setGameState('playing');
    setWinner(null);
    setForcedCapture(null);
    setSelectedPieceId(null);
    setValidMoves([]);
    setComboCount(0);
    setActiveMoveTarget(null);
    setIsAIThinking(false);
    setShowDifficultySelect(false);
    playSound.move();
  };

  // --- Logic Helper Functions ---

  const getPieceAt = (b: (Piece | null)[][], pos: Position) => {
    if (pos.row < 0 || pos.row >= BOARD_SIZE || pos.col < 0 || pos.col >= BOARD_SIZE) return null;
    return b[pos.row][pos.col];
  };

  const calculateValidMoves = (piece: Piece, currentBoard: (Piece | null)[][]): Move[] => {
    const moves: Move[] = [];
    const directions = piece.isKing 
      ? [[-1, -1], [-1, 1], [1, -1], [1, 1]] 
      : piece.player === 'red' ? [[-1, -1], [-1, 1]] : [[1, -1], [1, 1]];

    directions.forEach(([dRow, dCol]) => {
      // 1. Simple Move
      const targetPos = { row: piece.position.row + dRow, col: piece.position.col + dCol };
      if (
        targetPos.row >= 0 && targetPos.row < BOARD_SIZE &&
        targetPos.col >= 0 && targetPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, targetPos)
      ) {
         moves.push({ from: piece.position, to: targetPos, isJump: false });
      }

      // 2. Jump (Capture)
      const jumpPos = { row: piece.position.row + (dRow * 2), col: piece.position.col + (dCol * 2) };
      if (
        jumpPos.row >= 0 && jumpPos.row < BOARD_SIZE &&
        jumpPos.col >= 0 && jumpPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, jumpPos)
      ) {
        const midPos = targetPos;
        const midPiece = getPieceAt(currentBoard, midPos);
        if (midPiece && midPiece.player !== piece.player) {
          moves.push({ 
            from: piece.position, 
            to: jumpPos, 
            isJump: true, 
            capturedPieceId: midPiece.id, 
            jumpedPosition: midPos 
          });
        }
      }
    });

    return moves;
  };

  const getAllValidMovesForPlayer = (player: Player, currentBoard: (Piece | null)[][]) => {
    let allMoves: { pieceId: string, move: Move }[] = [];
    let hasJump = false;

    // Iterate board to find all player pieces
    for(let r=0; r<BOARD_SIZE; r++){
      for(let c=0; c<BOARD_SIZE; c++){
        const p = currentBoard[r][c];
        if(p && p.player === player && !p.isCaptured){
          const moves = calculateValidMoves(p, currentBoard);
          moves.forEach(m => {
            if(m.isJump) hasJump = true;
            allMoves.push({ pieceId: p.id, move: m });
          });
        }
      }
    }

    // Forced capture rule: If a jump exists, remove non-jumps
    if (hasJump) {
      allMoves = allMoves.filter(m => m.move.isJump);
    }

    return { allMoves, hasJump };
  };

  // --- Interaction ---

  const handleSquareClick = (row: number, col: number) => {
    if (gameState !== 'playing') return;

    // Disable interaction if AI is thinking or if it's AI's turn in PvE
    if (gameMode === 'pve' && (turn === AI_PLAYER || isAIThinking)) return;

    const clickedPiece = board[row][col];
    const isCurrentPlayerPiece = clickedPiece?.player === turn;

    // 1. Selecting a piece
    if (isCurrentPlayerPiece) {
      if (forcedCapture && forcedCapture !== clickedPiece.id) {
        playSound.error();
        return; // Must play the forced piece
      }

      // Calculate moves for this piece
      const { allMoves, hasJump } = getAllValidMovesForPlayer(turn, board);

      // If forced jumps exist globally, can only select pieces that can jump
      if (hasJump) {
         const canThisJump = allMoves.some(m => m.pieceId === clickedPiece.id && m.move.isJump);
         if (!canThisJump) {
            playSound.error();
            return;
         }
      }

      setSelectedPieceId(clickedPiece.id);

      // Filter valid moves for just this piece
      const movesForPiece = allMoves
        .filter(m => m.pieceId === clickedPiece.id)
        .map(m => m.move);

      setValidMoves(movesForPiece);
      playSound.move();
      return;
    }

    // 2. Moving to an empty square (executing a move)
    if (!clickedPiece && selectedPieceId) {
      const move = validMoves.find(m => m.to.row === row && m.to.col === col);
      if (move) {
        executeMove(move);
      } else {
        // Deselect if clicking invalid empty square
        setSelectedPieceId(null);
        setValidMoves([]);
      }
    }
  };

  const executeMove = (move: Move) => {
    const piece = getPieceAt(board, move.from);
    if (!piece) return;

    // Trigger global "look at" event
    setActiveMoveTarget(move.to);
    setTimeout(() => setActiveMoveTarget(null), 800); // Stop looking after animation settles

    // Create deep copy for mutation
    const newBoard = board.map(row => row.map(p => p ? { ...p } : null));
    const movedPiece = newBoard[move.from.row][move.from.col]!;

    // Update position
    newBoard[move.from.row][move.from.col] = null;
    newBoard[move.to.row][move.to.col] = movedPiece;
    movedPiece.position = move.to;

    let justCaptured = false;

    // Handle Capture
    if (move.isJump && move.jumpedPosition) {
      const captured = newBoard[move.jumpedPosition.row][move.jumpedPosition.col];
      newBoard[move.jumpedPosition.row][move.jumpedPosition.col] = null; // Remove from board

      if (captured) {
        // --- ZUEIRA LOGIC ---
        const isCombo = comboCount > 0;
        const phraseList = isCombo ? TAUNTS_EPIC : TAUNTS_SIMPLE;
        const tauntText = phraseList[Math.floor(Math.random() * phraseList.length)];
        // --------------------

        spawnParticles(move.to.row, move.to.col, tauntText, isCombo);

        setScores(prev => ({
          ...prev,
          [captured.player]: prev[captured.player] - 1
        }));
        justCaptured = true;
        setComboCount(c => c + 1);
        playSound.capture();
      }
    } else {
      setComboCount(0);
      playSound.move();
    }

    // Handle Promotion
    let promoted = false;
    if (!movedPiece.isKing) {
      if ((movedPiece.player === 'red' && move.to.row === 0) ||
          (movedPiece.player === 'blue' && move.to.row === BOARD_SIZE - 1)) {
        movedPiece.isKing = true;
        promoted = true;
        playSound.king();
        spawnParticles(move.to.row, move.to.col, "REI!", true);
      }
    }

    setBoard(newBoard);
    setSelectedPieceId(null);
    setValidMoves([]);

    // Multi-jump Logic
    if (justCaptured && !promoted) {
      // Check if this specific piece can jump again
      const nextMoves = calculateValidMoves(movedPiece, newBoard).filter(m => m.isJump);
      if (nextMoves.length > 0) {
        // Must continue with this piece
        setForcedCapture(movedPiece.id);
        // If it's AI, we return here and let the Effect pick up the forced move
        // If it's Human, we re-select automatically
        if (movedPiece.player === HUMAN_PLAYER || gameMode === 'pvp') {
           setSelectedPieceId(movedPiece.id);
           setValidMoves(nextMoves);
        }
        return; // Turn does NOT change
      }
    }

    // End Turn
    endTurn(newBoard, movedPiece.player);
  };

  const endTurn = (currentBoard: (Piece | null)[][], currentPlayer: Player) => {
    setForcedCapture(null);
    setComboCount(0);
    const nextPlayer = currentPlayer === 'red' ? 'blue' : 'red';

    // Check win condition (count pieces or no moves)
    const { allMoves } = getAllValidMovesForPlayer(nextPlayer, currentBoard);

    if (allMoves.length === 0) {
      setWinner(currentPlayer); // Current player wins because next has no moves
      setGameState('winner');
      playSound.win();
    } else {
      setTurn(nextPlayer);
    }
  };

  // --- AI LOGIC ---
  useEffect(() => {
    if (gameState !== 'playing' || gameMode !== 'pve') return;
    if (turn !== AI_PLAYER) return;

    // AI Turn
    setIsAIThinking(true);

    const performAIMove = async () => {
        // "Think" delay based on difficulty
        const minDelay = difficulty === 'easy' ? 500 : difficulty === 'medium' ? 800 : 1000;
        const delay = Math.random() * 500 + minDelay;
        await new Promise(r => setTimeout(r, delay));

        const { allMoves } = getAllValidMovesForPlayer(AI_PLAYER, board);

        // Filter by forced capture if applicable
        let validAIMoves = allMoves.map(m => m.move);
        if (forcedCapture) {
             const forcingPieceMoves = allMoves
                .filter(m => m.pieceId === forcedCapture)
                .map(m => m.move);
             validAIMoves = forcingPieceMoves;
        }

        if (validAIMoves.length === 0) {
            // Should be handled by endTurn win check, but just in case
            return;
        }

        // Heuristic Scoring
        const scoredMoves = validAIMoves.map(move => {
            let score = 0;
            const piece = getPieceAt(board, move.from)!;

            // EASY: Mostly random
            if (difficulty === 'easy') {
                return { move, score: Math.random() * 100 };
            }

            // Common Heuristics (Medium & Hard)
            // 1. Always prioritize Jump (Game Rules usually force this, but ensures preference in logic)
            if (move.isJump) score += 100;

            // 2. Become King
            if (!piece.isKing && move.to.row === BOARD_SIZE - 1) score += 50;

            // 3. Safety Check
            const isSafe = !isPositionUnderAttack(move.to, board);

            if (difficulty === 'medium') {
                if (isSafe) score += 20;

                // Center Control (Light)
                if (move.to.col >= 2 && move.to.col <= 5 && move.to.row >= 2 && move.to.row <= 5) {
                    score += 5;
                }

                // Randomness
                score += Math.random() * 10;
            } else if (difficulty === 'hard') {
                // Hard Mode Heuristics
                if (isSafe) {
                    score += 30;
                } else {
                    score -= 50; // Heavily penalize danger
                }

                // Center Control (Strong)
                if (move.to.col >= 2 && move.to.col <= 5 && move.to.row >= 2 && move.to.row <= 5) {
                    score += 15;
                }

                // Back Row Protection (Don't move initial back row pieces unless necessary)
                // Blue starts at rows 0, 1, 2. Row 0 is the back row.
                if (piece.position.row === 0 && !piece.isKing) {
                   score -= 20; // Discourage moving back row
                }

                // Advancement
                score += move.to.row * 2; // Encourages moving down towards King row

                // Less Randomness
                score += Math.random() * 5;
            }

            return { move, score };
        });

        // Pick best move
        scoredMoves.sort((a, b) => b.score - a.score);
        const bestMove = scoredMoves[0].move;

        executeMove(bestMove);
        setIsAIThinking(false);
    };

    performAIMove();

  }, [turn, gameState, gameMode, forcedCapture, board, difficulty]);

  const isPositionUnderAttack = (pos: Position, currentBoard: (Piece | null)[][]): boolean => {
      // Very basic check: Is there an enemy diagonally adjacent that has an empty space behind me?
      const enemy: Player = 'red';
      const dirs = [[-1, -1], [-1, 1], [1, -1], [1, 1]];

      for (const [dr, dc] of dirs) {
          const enemyPos = { row: pos.row + dr, col: pos.col + dc };
          // Logic inverted relative to threat direction

          if (enemyPos.row >= 0 && enemyPos.row < BOARD_SIZE && enemyPos.col >= 0 && enemyPos.col < BOARD_SIZE) {
               const p = getPieceAt(currentBoard, enemyPos);
               if (p && p.player === enemy) {
                  // Enemy is next to target. Can they jump?
                  // If I move to `pos`, I occupy it.
                  // Can enemy at `enemyPos` jump over `pos`?
                  // Only if `pos` + (pos - enemyPos) is empty.
                  const jumpLandingRow = pos.row + (pos.row - enemyPos.row);
                  const jumpLandingCol = pos.col + (pos.col - enemyPos.col);

                  if (jumpLandingRow >= 0 && jumpLandingRow < BOARD_SIZE && 
                      jumpLandingCol >= 0 && jumpLandingCol < BOARD_SIZE) {
                      // Check if landing is empty. Note: "board" is current board. 
                      // In executing move, `pos` becomes occupied, but `jumpLanding` needs to be empty.
                       if (!getPieceAt(currentBoard, {row: jumpLandingRow, col: jumpLandingCol})) {
                           // High danger
                           return true;
                       }
                  }
               }
          }
      }
      return false;
  };


  // --- Effects & Visuals ---

  const spawnParticles = (row: number, col: number, text?: string, gold: boolean = false) => {
    const id = Date.now().toString() + Math.random();
    setParticles(prev => [...prev, { id, row, col, color: gold ? '#FFD700' : '#FFF', text }]);

    // Cleanup
    setTimeout(() => {
      setParticles(prev => prev.filter(p => p.id !== id));
    }, 1200);
  };

  // Render Helpers
  const renderSquare = (row: number, col: number) => {
    const isBlack = (row + col) % 2 === 1;
    const piece = board[row][col];

    // Highlights
    const isPossibleMove = validMoves.some(m => m.to.row === row && m.to.col === col);
    const isSource = selectedPieceId && piece && piece.id === selectedPieceId;

    // Particles for this square
    const cellParticles = particles.filter(p => p.row === row && p.col === col);

    return (
      <div 
        key={`${row}-${col}`}
        onClick={() => handleSquareClick(row, col)}
        className={`
          relative w-full h-full flex items-center justify-center
          ${isBlack ? 'bg-slate-800' : 'bg-slate-200'}
          ${isPossibleMove ? 'ring-inset ring-4 ring-green-400 cursor-pointer' : ''}
          /* Subtle internal borders for texture */
          ${isBlack ? 'shadow-[inset_0_0_10px_rgba(0,0,0,0.5)]' : 'shadow-[inset_0_0_10px_rgba(255,255,255,0.5)]'}
        `}
      >
        {/* Cell Highlight for Possible Move */}
        {isPossibleMove && (
          <div className="absolute inset-2 bg-green-400 rounded-full animate-pulse opacity-40"></div>
        )}

        {/* Piece */}
        {piece && (
          <div className={`w-full h-full p-1.5 z-10 transition-transform duration-300 ${isSource ? 'scale-110' : ''}`}>
             <ToonPiece 
                piece={piece} 
                isSelected={!!isSource} 
                canMove={turn === piece.player && !(gameMode === 'pve' && turn === AI_PLAYER)}
                focusTarget={activeMoveTarget}
                onClick={() => handleSquareClick(row, col)} 
             />
          </div>
        )}

        {/* Floating Particles in Cell */}
        {cellParticles.map(p => (
           <div key={p.id} className="absolute inset-0 flex items-center justify-center z-50 pointer-events-none">
              <div className="animate-pop flex flex-col items-center">
                 {/* Sparkle graphic */}
                 <div className="text-3xl filter drop-shadow-md">💥</div>
                 {/* Text */}
                 {p.text && (
                   <span className="text-xl md:text-2xl font-black text-white stroke-black drop-shadow-[0_3px_0_rgba(0,0,0,0.8)] whitespace-nowrap" 
                         style={{
                           color: p.color,
                           textShadow: '0 0 10px rgba(0,0,0,0.8)',
                           WebkitTextStroke: '1.5px black'
                         }}>
                     {p.text}
                   </span>
                 )}
              </div>
           </div>
        ))}
      </div>
    );
  };

  return (
    <div className="min-h-screen h-[100dvh] bg-slate-900 flex flex-col items-center justify-center text-white relative overflow-hidden select-none touch-none">

      {/* Background Ambience */}
      <div className="absolute inset-0 opacity-20 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900 via-slate-900 to-black pointer-events-none"></div>

      {/* Header / UI - Adaptive Flex Layout */}
      <div className="relative w-full max-w-4xl flex flex-col md:flex-row items-center justify-center md:justify-between gap-4 p-4 z-10 flex-shrink-0">

        {/* Blue Player Stats (Left/Top) */}
        <div className={`
          flex items-center gap-4 transition-all duration-300 order-2 md:order-1
          ${turn === 'blue' ? 'opacity-100 scale-105' : 'opacity-60 scale-95 grayscale'}
        `}>
          <div className="w-14 h-14 md:w-20 md:h-20 bg-sky-500 rounded-full border-4 border-white shadow-lg flex items-center justify-center relative overflow-hidden">
             <div className="absolute w-3 h-3 bg-white rounded-full top-3 left-3 opacity-50"></div>
             <span className="text-2xl md:text-3xl font-black">{scores.blue}</span>
          </div>
          <div className="hidden md:block">
            <div className="font-bold text-sky-300 text-xl tracking-wider">BLUE</div>
            {gameMode === 'pve' && (
              <div className="text-xs text-sky-400 font-bold uppercase flex flex-col">
                <span>(CPU)</span>
                <span className="text-[10px] opacity-75">{difficulty}</span>
              </div>
            )}
          </div>
        </div>

        {/* Title & Game Info (Center) */}
        <div className="flex flex-col items-center order-1 md:order-2 mb-2 md:mb-0">
          <h1 className="text-3xl md:text-5xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500 drop-shadow-sm tracking-tighter">
            CHECKERS
          </h1>
          <div className="bg-slate-800/80 backdrop-blur px-6 py-1.5 rounded-full text-xs md:text-sm font-bold text-slate-300 mt-2 uppercase tracking-widest border border-slate-700 shadow-xl min-w-[140px] text-center">
             {gameState === 'playing' ? (
                <span className={turn === 'red' ? 'text-rose-400' : 'text-sky-400'}>
                   {isAIThinking ? 'THINKING...' : `${turn.toUpperCase()}'S TURN`}
                </span>
             ) : 'GAME OVER'}
          </div>
        </div>

        {/* Red Player Stats (Right/Bottom) */}
        <div className={`
          flex items-center gap-4 transition-all duration-300 order-3
          ${turn === 'red' ? 'opacity-100 scale-105' : 'opacity-60 scale-95 grayscale'}
        `}>
          <div className="hidden md:block text-right"> 
             <div className="font-bold text-rose-300 text-xl tracking-wider">RED</div>
             {gameMode === 'pve' && <div className="text-xs text-rose-400 font-bold uppercase">(YOU)</div>}
          </div>
          <div className="w-14 h-14 md:w-20 md:h-20 bg-rose-500 rounded-full border-4 border-white shadow-lg flex items-center justify-center relative overflow-hidden">
            <div className="absolute w-3 h-3 bg-white rounded-full top-3 right-3 opacity-50"></div>
            <span className="text-2xl md:text-3xl font-black">{scores.red}</span>
          </div>
        </div>
      </div>

      {/* Combo Indicator */}
      {comboCount > 1 && (
        <div className="absolute top-[20%] z-50 animate-pop pointer-events-none">
          <span className="text-5xl md:text-6xl font-black text-yellow-400 drop-shadow-[0_4px_0_rgba(0,0,0,1)] stroke-black" style={{WebkitTextStroke: '2px black'}}>
            COMBO x{comboCount}!
          </span>
        </div>
      )}

      {/* Main Game Area - Perfectly Centered & Responsive */}
      <main className="relative z-10 flex items-center justify-center p-2 md:p-4 w-full h-full flex-grow">
        <div className={`
          relative
          /* The Magic Responsive Formula: */
          w-[min(90vw,90vw)]
          h-[min(90vw,90vw)]
          md:w-[min(600px,75vmin)] 
          md:h-[min(600px,75vmin)]
          bg-slate-950 p-3 rounded-2xl shadow-2xl border-b-[8px] border-slate-950
          transition-all duration-700
          perspective-board
          ${gameState === 'winner' ? 'scale-90 blur-sm' : ''}
        `}>
          <div className="w-full h-full bg-slate-800 rounded-xl overflow-hidden grid grid-cols-8 grid-rows-8 shadow-inner ring-4 ring-slate-800">
            {board.map((row, r) => row.map((_, c) => renderSquare(r, c)))}
          </div>
        </div>
      </main>

      {/* Menus / Overlays */}
      {gameState === 'menu' && !showDifficultySelect && (
        <div className="absolute inset-0 bg-slate-900/90 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in">
           <div className="text-5xl md:text-7xl font-black text-white mb-8 tracking-tighter drop-shadow-xl animate-float text-center px-4">
             TOON CHECKERS
           </div>

           <div className="flex flex-col gap-4">
             <button 
               onClick={() => setShowDifficultySelect(true)}
               className="w-64 px-8 py-4 bg-purple-500 hover:bg-purple-400 text-white rounded-full font-black text-xl shadow-[0_6px_0_rgb(107,33,168)] hover:shadow-[0_4px_0_rgb(107,33,168)] hover:translate-y-[2px] active:shadow-none active:translate-y-[6px] transition-all transform hover:scale-105 flex items-center justify-center gap-2"
             >
               <span>🤖</span> 1 PLAYER
             </button>

             <button 
               onClick={() => initGame('pvp')}
               className="w-64 px-8 py-4 bg-green-500 hover:bg-green-400 text-white rounded-full font-black text-xl shadow-[0_6px_0_rgb(21,128,61)] hover:shadow-[0_4px_0_rgb(21,128,61)] hover:translate-y-[2px] active:shadow-none active:translate-y-[6px] transition-all transform hover:scale-105 flex items-center justify-center gap-2"
             >
               <span>👥</span> 2 PLAYERS
             </button>
           </div>
        </div>
      )}

      {/* Difficulty Selection Overlay */}
      {gameState === 'menu' && showDifficultySelect && (
        <div className="absolute inset-0 bg-slate-900/90 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in">
           <div className="text-3xl md:text-5xl font-black text-white mb-8 tracking-tighter drop-shadow-xl text-center px-4">
             SELECT DIFFICULTY
           </div>

           <div className="flex flex-col gap-4">
             <button 
               onClick={() => initGame('pve', 'easy')}
               className="w-64 px-8 py-3 bg-teal-400 hover:bg-teal-300 text-slate-900 rounded-full font-black text-lg shadow-[0_5px_0_rgb(20,184,166)] hover:translate-y-[2px] active:translate-y-[5px] active:shadow-none transition-all"
             >
               EASY
             </button>
             <button 
               onClick={() => initGame('pve', 'medium')}
               className="w-64 px-8 py-3 bg-orange-400 hover:bg-orange-300 text-slate-900 rounded-full font-black text-lg shadow-[0_5px_0_rgb(249,115,22)] hover:translate-y-[2px] active:translate-y-[5px] active:shadow-none transition-all"
             >
               MEDIUM
             </button>
             <button 
               onClick={() => initGame('pve', 'hard')}
               className="w-64 px-8 py-3 bg-red-500 hover:bg-red-400 text-white rounded-full font-black text-lg shadow-[0_5px_0_rgb(185,28,28)] hover:translate-y-[2px] active:translate-y-[5px] active:shadow-none transition-all"
             >
               HARD
             </button>

             <button 
               onClick={() => setShowDifficultySelect(false)}
               className="mt-4 text-slate-400 font-bold hover:text-white transition-colors"
             >
               ← BACK
             </button>
           </div>
        </div>
      )}

      {gameState === 'winner' && (
        <div className="absolute inset-0 bg-slate-900/90 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in">
           <div className="text-yellow-400 text-8xl mb-6 animate-bounce">🏆</div>
           <h2 className="text-6xl font-black text-white mb-2 drop-shadow-lg text-center">
             {winner?.toUpperCase()} WINS!
           </h2>
           <p className="text-slate-300 mb-10 font-bold text-2xl">
             Incredible Strategy!
           </p>
           <div className="flex gap-4">
             <button 
               onClick={() => setGameState('menu')}
               className="px-8 py-4 bg-slate-600 hover:bg-slate-500 text-white rounded-full font-black text-xl shadow-[0_6px_0_rgb(51,65,85)] transition-all transform hover:scale-105"
             >
               MENU
             </button>
             <button 
               onClick={() => initGame(gameMode, difficulty)}
               className="px-8 py-4 bg-blue-500 hover:bg-blue-400 text-white rounded-full font-black text-xl shadow-[0_6px_0_rgb(30,58,138)] transition-all transform hover:scale-105"
             >
               PLAY AGAIN
             </button>
           </div>
        </div>
      )}

      {/* Footer Instructions */}
      <div className="absolute bottom-2 text-slate-500 text-[10px] md:text-xs font-bold tracking-widest uppercase opacity-50 pointer-events-none">
         {gameState === 'playing' && gameMode === 'pve' 
            ? `Play as RED vs AI (${difficulty.toUpperCase()})` 
            : `${turn === 'blue' ? 'Blue' : 'Red'} to move`
         }
      </div>

    </div>
  );
};

export default App;

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { Piece, Position } from '../types';

interface ToonPieceProps {
  piece: Piece;
  isSelected: boolean;
  canMove: boolean;
  onClick: () => void;
  focusTarget: Position | null; // The tile currently being moved TO
}

type IdleAction = 'none' | 'look-left' | 'look-right' | 'smirk' | 'ooh' | 'suspicious' | 'wiggle';

const ToonPiece: React.FC<ToonPieceProps> = ({ piece, isSelected, onClick, canMove, focusTarget }) => {
  const [mood, setMood] = useState<'idle' | 'happy' | 'surprised' | 'focused' | 'evil'>('idle');
  const [idleAction, setIdleAction] = useState<IdleAction>('none');
  const [justBecameKing, setJustBecameKing] = useState(false);
  const timerRef = useRef<number>(0);
  const prevIsKingRef = useRef(piece.isKing);

  // --- Logic: Detect Promotion ---
  useEffect(() => {
    if (piece.isKing && !prevIsKingRef.current) {
        setJustBecameKing(true);
        setTimeout(() => setJustBecameKing(false), 2000); // Reset after animation
    }
    prevIsKingRef.current = piece.isKing;
  }, [piece.isKing]);


  // --- Logic: Random Idle Expressions ---
  useEffect(() => {
    // If active interaction is happening, cancel random behavior
    if (isSelected || focusTarget) {
      setIdleAction('none');
      if (timerRef.current) clearTimeout(timerRef.current);
      return;
    }

    const triggerRandomness = () => {
      // Random time between 2s and 6s
      const timeToNext = Math.random() * 4000 + 2000;

      timerRef.current = window.setTimeout(() => {
        // Pick a random action
        const actions: IdleAction[] = ['look-left', 'look-right', 'smirk', 'ooh', 'suspicious', 'wiggle', 'none', 'none'];
        const picked = actions[Math.floor(Math.random() * actions.length)];

        setIdleAction(picked);

        // Reset to none after a short duration (e.g. 1.5s glance)
        if (picked !== 'none') {
            setTimeout(() => {
                // Check if we are still allowed to change state (might have been selected in the meantime)
                setIdleAction(prev => (prev === picked ? 'none' : prev));
            }, 1000 + Math.random() * 1000);
        }

        // Recursively trigger next
        triggerRandomness();
      }, timeToNext);
    };

    triggerRandomness();

    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [isSelected, focusTarget, piece.id]);


  // --- Logic: Eye Tracking ---
  const lookAtStyle = useMemo(() => {
    // 1. Priority: Active Logic (Focus Target)
    if (focusTarget && !isSelected) {
      const dy = focusTarget.row - piece.position.row;
      const dx = focusTarget.col - piece.position.col;
      const distance = Math.sqrt(dx * dx + dy * dy) || 1;
      return { 
        x: (dx / distance) * 6, 
        y: (dy / distance) * 5, 
        rotate: (dx / distance) * 10 
      };
    }

    // 2. Priority: Random Idle Actions
    if (idleAction === 'look-left') return { x: -5, y: 0, rotate: -5 };
    if (idleAction === 'look-right') return { x: 5, y: 0, rotate: 5 };
    if (idleAction === 'suspicious') return { x: 0, y: -1, rotate: 0 }; // Squint look

    // Default
    return { x: 0, y: 0, rotate: 0 };
  }, [focusTarget, piece.position, isSelected, idleAction]);


  // --- Logic: Mood State ---
  useEffect(() => {
    if (isSelected) {
      setMood('surprised');
    } else if (piece.isKing) {
      setMood('evil'); // Kings are evil/bossy!
    } else if (focusTarget) {
      setMood('focused');
    } else {
      setMood('idle');
    }
  }, [isSelected, piece.isKing, focusTarget]);

  // --- Visuals: 2.5D Styles ---
  const isRed = piece.player === 'red';

  // Gradients and Colors
  const bgGradient = isRed 
    ? 'bg-gradient-to-br from-rose-400 via-rose-500 to-rose-600' 
    : 'bg-gradient-to-br from-sky-400 via-sky-500 to-sky-600';

  const sideColor = isRed ? '#9f1239' : '#0369a1'; // darker shade for the "side" thickness

  // Wiggle calculation
  const isWiggling = idleAction === 'wiggle' && !isSelected && !focusTarget;
  // King Floating: Always float if King, unless selected
  const isKingFloating = piece.isKing && !isSelected;

  // Transform Logic
  // Merge the "Look At" rotation with the "Lift" selection state
  const baseRotation = (focusTarget && !isSelected) || idleAction !== 'none' ? lookAtStyle.rotate : 0;

  // We apply transforms via inline style to allow stacking
  const transformStyle = isSelected 
    ? `translateY(-12px) scale(1.1) rotate(${baseRotation}deg)` 
    : `translateY(0px) rotate(${baseRotation}deg)`;

  return (
    <div 
      onClick={(e) => {
        e.stopPropagation();
        onClick();
      }}
      className={`
        relative w-[92%] h-[92%] rounded-full cursor-pointer group
        transition-all duration-500 ease-[cubic-bezier(0.34,1.56,0.64,1)]
        flex items-center justify-center
        ${canMove ? 'hover:-translate-y-2' : ''} 
      `}
      style={{
        transform: transformStyle,
        zIndex: isSelected ? 50 : 10
      }}
    >
        {/* INNER CONTAINER: Handles Float Animations (Wiggle or King Float) and Visual Body */}
        <div className={`
            w-full h-full rounded-full flex items-center justify-center relative
            ${bgGradient}
            ${isWiggling ? 'animate-[float_0.5s_ease-in-out_infinite]' : ''}
            ${isKingFloating ? 'animate-king-float' : ''}
            ${justBecameKing ? 'animate-levitate-once' : ''}
        `}
        style={{
            // 2.5D CSS Shadow Stack applied here to move with the float
            boxShadow: isSelected 
            ? `inset 0 4px 10px rgba(255,255,255,0.5), inset 0 -6px 12px rgba(0,0,0,0.2), 0 16px 0 ${sideColor}, 0 24px 20px rgba(0,0,0,0.4)`
            : `inset 0 4px 6px rgba(255,255,255,0.4), inset 0 -4px 8px rgba(0,0,0,0.2), 0 6px 0 ${sideColor}, 0 8px 6px rgba(0,0,0,0.3)`,
        }}
        >

            {/* Texture: Checker Grooves (Concentric Circles) */}
            <div className="absolute inset-1.5 md:inset-2 rounded-full border-2 md:border-4 border-black/10 opacity-50 pointer-events-none"></div>
            <div className="absolute inset-3 md:inset-4 rounded-full border border-white/10 opacity-30 pointer-events-none"></div>

            {/* Glossy Specular Highlight (The 'Plastic' look) */}
            <div className="absolute top-2 left-1/4 w-1/2 h-1/5 bg-gradient-to-b from-white to-transparent opacity-40 rounded-full blur-[2px] pointer-events-none"></div>

            {/* Selection Ring (Golden Glow) */}
            {isSelected && (
                <div className="absolute -inset-1 rounded-full border-4 border-yellow-300 animate-pulse opacity-70 pointer-events-none"></div>
            )}

            {/* Face Container */}
            <div className="relative w-full h-full flex flex-col items-center justify-center mt-1 pointer-events-none z-10">

                {/* Eyebrows for expressions (mainly Evil/King) */}
                <div className="absolute top-[28%] flex gap-2 transition-transform duration-300 z-20" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
                    {/* Left Brow */}
                    <div className={`w-2.5 h-1 bg-black/70 rounded-full transition-all duration-300 origin-right
                        ${mood === 'evil' ? 'rotate-[25deg] translate-y-0.5 opacity-100' : 'opacity-0'}
                        ${mood === 'focused' ? 'rotate-0 translate-y-0 opacity-0' : ''} 
                    `}></div>
                    {/* Right Brow */}
                    <div className={`w-2.5 h-1 bg-black/70 rounded-full transition-all duration-300 origin-left
                        ${mood === 'evil' ? '-rotate-[25deg] translate-y-0.5 opacity-100' : 'opacity-0'}
                        ${mood === 'focused' ? 'rotate-0 translate-y-0 opacity-0' : ''}
                    `}></div>
                </div>

                {/* Eyes */}
                <div className="flex gap-1 mb-1 transition-transform duration-300" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
                {/* Left Eye */}
                <div className={`
                    relative w-4 bg-white rounded-full overflow-hidden transition-all duration-300 shadow-sm border border-black/5
                    ${mood === 'evil' ? 'h-3.5 mt-1.5' : (idleAction === 'suspicious' ? 'h-2.5 mt-2.5' : 'h-5 animate-blink')}
                `}>
                    <div className={`absolute w-2 h-2 bg-slate-900 rounded-full top-[45%] left-1/2 transform -translate-x-1/2 -translate-y-1/2 
                    ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
                    {/* Eye glimmer */}
                    <div className="absolute top-0.5 right-0.5 w-1 h-1 bg-white rounded-full opacity-80"></div>
                </div>
                {/* Right Eye */}
                <div className={`
                    relative w-4 bg-white rounded-full overflow-hidden transition-all duration-300 shadow-sm border border-black/5
                    ${mood === 'evil' ? 'h-3.5 mt-1.5' : (idleAction === 'suspicious' ? 'h-2.5 mt-2.5' : 'h-5 animate-blink')}
                `} style={{ animationDelay: '0.1s' }}>
                    <div className={`absolute w-2 h-2 bg-slate-900 rounded-full top-[45%] left-1/2 transform -translate-x-1/2 -translate-y-1/2 
                    ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
                    {/* Eye glimmer */}
                    <div className="absolute top-0.5 right-0.5 w-1 h-1 bg-white rounded-full opacity-80"></div>
                </div>
                </div>

                {/* Mouth */}
                <div className={`
                bg-slate-900/80 transition-all duration-300 shadow-sm
                ${mood === 'surprised' || idleAction === 'ooh' ? 'h-3 w-3 rounded-full border-2 border-white/20' : 'w-4 h-2 rounded-b-full'}
                ${(mood === 'happy' || idleAction === 'smirk') ? 'h-3 w-6 rounded-b-xl border-t-0' : ''}
                ${mood === 'evil' ? 'w-5 h-2.5 rounded-b-full border-t-0' : ''}
                ${mood === 'focused' ? 'w-3 h-1.5 rounded-full scale-90' : ''}
                ${idleAction === 'suspicious' ? 'w-5 h-1 rounded-full' : ''}
                `}
                style={{ 
                    transform: `translate(${lookAtStyle.x * 0.5}px, ${lookAtStyle.y * 0.5}px) ${idleAction === 'smirk' || mood === 'evil' ? 'rotate(-5deg) translateX(1px)' : ''}` 
                }}>
                   {/* Evil Tooth */}
                   {mood === 'evil' && (
                       <div className="absolute top-0 left-0.5 w-1 h-1 bg-white rounded-b-full opacity-90"></div>
                   )}
                </div>

                {/* Blush */}
                {(mood === 'happy' || idleAction === 'smirk' || idleAction === 'ooh' || isSelected) && (
                    <>
                        <div className="absolute top-[65%] left-1 w-2.5 h-1.5 bg-rose-400 opacity-60 rounded-full blur-[2px]"></div>
                        <div className="absolute top-[65%] right-1 w-2.5 h-1.5 bg-rose-400 opacity-60 rounded-full blur-[2px]"></div>
                    </>
                )}

            </div>

            {/* Crown for King */}
            {piece.isKing && (
                <div className={`absolute -top-6 md:-top-8 left-1/2 transform -translate-x-1/2 w-8 h-8 md:w-10 md:h-10 z-30 pointer-events-none ${justBecameKing ? 'animate-crown-enter' : 'animate-float'}`}>
                    {/* Glowing Aura for King */}
                    <div className="absolute inset-0 bg-yellow-400/30 rounded-full blur-md animate-pulse"></div>

                    <svg viewBox="0 0 24 24" fill="none" className="w-full h-full drop-shadow-xl filter animate-crown">
                        <path d="M2 18h20v2H2v-2zm0-2l4-8 4 6 4-6 4 8H2z" fill="url(#crownGradient)" stroke="#B8860B" strokeWidth="1" strokeLinejoin="round"/>
                        <defs>
                        <linearGradient id="crownGradient" x1="12" y1="2" x2="12" y2="20" gradientUnits="userSpaceOnUse">
                            <stop stopColor="#FFD700" />
                            <stop offset="1" stopColor="#F59E0B" />
                        </linearGradient>
                        </defs>
                        <circle cx="6" cy="6" r="1.5" fill="#FFF" className="animate-pulse" />
                        <circle cx="12" cy="10" r="1.5" fill="#FFF" className="animate-pulse" />
                        <circle cx="18" cy="6" r="1.5" fill="#FFF" className="animate-pulse" />
                    </svg>
                </div>
            )}
        </div>
    </div>
  );
};

export default ToonPiece;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import ToonPiece from './components/ToonPiece';
import { Piece, Position, Move, Player, GameState, Particle, GameMode, Difficulty } from './types';
import { playSound } from './utils/audio';

// --- Constants ---
const BOARD_SIZE = 8;
const AI_PLAYER: Player = 'blue';
const HUMAN_PLAYER: Player = 'red';

// --- Taunt Phrases (Zueira Lists) ---
const TAUNTS_SIMPLE = [
  "Tchau!", "Ops!", "Já era", "Vaza", "Perdeu", "Eita...", 
  "Xiu!", "Fácil", "Noob?", "Chora", "Sentou", "Sumiu", 
  "Kkkk", "Fraco", "Deu ruim", "Falou!", "Tankou?", "Ih..."
];

const TAUNTS_EPIC = [
  "SOLADO!", "AULA!", "RECEBA!", "QUE ISSO?", "SEGURA!", 
  "NEM VIU", "DESTRUIÇÃO", "CHORA MAIS", "COITADO", "MITO", 
  "LENDÁRIO", "NEM CLICOU", "DORMIU?", "TOMA!", "JOGA MUITO", "RESPEITA"
];

const App: React.FC = () => {
  // --- State ---
  const [gameState, setGameState] = useState<GameState>('menu');
  const [gameMode, setGameMode] = useState<GameMode>('pvp');
  const [difficulty, setDifficulty] = useState<Difficulty>('medium');
  const [showDifficultySelect, setShowDifficultySelect] = useState(false);

  const [board, setBoard] = useState<(Piece | null)[][]>([]);
  const [turn, setTurn] = useState<Player>('red'); // Red starts
  const [selectedPieceId, setSelectedPieceId] = useState<string | null>(null);
  const [validMoves, setValidMoves] = useState<Move[]>([]);
  const [forcedCapture, setForcedCapture] = useState<string | null>(null); // ID of piece that MUST double jump
  const [scores, setScores] = useState({ red: 0, blue: 0 });
  const [particles, setParticles] = useState<Particle[]>([]);
  const [winner, setWinner] = useState<Player | null>(null);
  const [comboCount, setComboCount] = useState(0);

  // Tracks where a move is currently landing so other pieces can look at it
  const [activeMoveTarget, setActiveMoveTarget] = useState<Position | null>(null);

  // AI Thinking State
  const [isAIThinking, setIsAIThinking] = useState(false);

  // --- Initialization ---
  const initGame = (mode: GameMode, diff: Difficulty = 'medium') => {
    const newBoard: (Piece | null)[][] = Array(BOARD_SIZE).fill(null).map(() => Array(BOARD_SIZE).fill(null));
    let idCounter = 0;

    for (let row = 0; row < BOARD_SIZE; row++) {
      for (let col = 0; col < BOARD_SIZE; col++) {
        if ((row + col) % 2 === 1) {
          if (row < 3) {
            newBoard[row][col] = { id: `blue-${idCounter++}`, player: 'blue', isKing: false, position: { row, col }, isCaptured: false };
          } else if (row > 4) {
            newBoard[row][col] = { id: `red-${idCounter++}`, player: 'red', isKing: false, position: { row, col }, isCaptured: false };
          }
        }
      }
    }
    setBoard(newBoard);
    setTurn('red');
    setGameMode(mode);
    setDifficulty(diff);
    setScores({ red: 12, blue: 12 });
    setGameState('playing');
    setWinner(null);
    setForcedCapture(null);
    setSelectedPieceId(null);
    setValidMoves([]);
    setComboCount(0);
    setActiveMoveTarget(null);
    setIsAIThinking(false);
    setShowDifficultySelect(false);
    playSound.move();
  };

  // --- Logic Helper Functions ---

  const getPieceAt = (b: (Piece | null)[][], pos: Position) => {
    if (pos.row < 0 || pos.row >= BOARD_SIZE || pos.col < 0 || pos.col >= BOARD_SIZE) return null;
    return b[pos.row][pos.col];
  };

  const calculateValidMoves = (piece: Piece, currentBoard: (Piece | null)[][]): Move[] => {
    const moves: Move[] = [];
    const directions = piece.isKing 
      ? [[-1, -1], [-1, 1], [1, -1], [1, 1]] 
      : piece.player === 'red' ? [[-1, -1], [-1, 1]] : [[1, -1], [1, 1]];

    directions.forEach(([dRow, dCol]) => {
      // 1. Simple Move
      const targetPos = { row: piece.position.row + dRow, col: piece.position.col + dCol };
      if (
        targetPos.row >= 0 && targetPos.row < BOARD_SIZE &&
        targetPos.col >= 0 && targetPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, targetPos)
      ) {
         moves.push({ from: piece.position, to: targetPos, isJump: false });
      }

      // 2. Jump (Capture)
      const jumpPos = { row: piece.position.row + (dRow * 2), col: piece.position.col + (dCol * 2) };
      if (
        jumpPos.row >= 0 && jumpPos.row < BOARD_SIZE &&
        jumpPos.col >= 0 && jumpPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, jumpPos)
      ) {
        const midPos = targetPos;
        const midPiece = getPieceAt(currentBoard, midPos);
        if (midPiece && midPiece.player !== piece.player) {
          moves.push({ 
            from: piece.position, 
            to: jumpPos, 
            isJump: true, 
            capturedPieceId: midPiece.id, 
            jumpedPosition: midPos 
          });
        }
      }
    });

    return moves;
  };

  const getAllValidMovesForPlayer = (player: Player, currentBoard: (Piece | null)[][]) => {
    let allMoves: { pieceId: string, move: Move }[] = [];
    let hasJump = false;

    // Iterate board to find all player pieces
    for(let r=0; r<BOARD_SIZE; r++){
      for(let c=0; c<BOARD_SIZE; c++){
        const p = currentBoard[r][c];
        if(p && p.player === player && !p.isCaptured){
          const moves = calculateValidMoves(p, currentBoard);
          moves.forEach(m => {
            if(m.isJump) hasJump = true;
            allMoves.push({ pieceId: p.id, move: m });
          });
        }
      }
    }

    // Forced capture rule: If a jump exists, remove non-jumps
    if (hasJump) {
      allMoves = allMoves.filter(m => m.move.isJump);
    }

    return { allMoves, hasJump };
  };

  // --- Interaction ---

  const handleSquareClick = (row: number, col: number) => {
    if (gameState !== 'playing') return;

    // Disable interaction if AI is thinking or if it's AI's turn in PvE
    if (gameMode === 'pve' && (turn === AI_PLAYER || isAIThinking)) return;

    const clickedPiece = board[row][col];
    const isCurrentPlayerPiece = clickedPiece?.player === turn;

    // 1. Selecting a piece
    if (isCurrentPlayerPiece) {
      if (forcedCapture && forcedCapture !== clickedPiece.id) {
        playSound.error();
        return; // Must play the forced piece
      }

      // Calculate moves for this piece
      const { allMoves, hasJump } = getAllValidMovesForPlayer(turn, board);

      // If forced jumps exist globally, can only select pieces that can jump
      if (hasJump) {
         const canThisJump = allMoves.some(m => m.pieceId === clickedPiece.id && m.move.isJump);
         if (!canThisJump) {
            playSound.error();
            return;
         }
      }

      setSelectedPieceId(clickedPiece.id);

      // Filter valid moves for just this piece
      const movesForPiece = allMoves
        .filter(m => m.pieceId === clickedPiece.id)
        .map(m => m.move);

      setValidMoves(movesForPiece);
      playSound.move();
      return;
    }

    // 2. Moving to an empty square (executing a move)
    if (!clickedPiece && selectedPieceId) {
      const move = validMoves.find(m => m.to.row === row && m.to.col === col);
      if (move) {
        executeMove(move);
      } else {
        // Deselect if clicking invalid empty square
        setSelectedPieceId(null);
        setValidMoves([]);
      }
    }
  };

  const executeMove = (move: Move) => {
    const piece = getPieceAt(board, move.from);
    if (!piece) return;

    // Trigger global "look at" event
    setActiveMoveTarget(move.to);
    setTimeout(() => setActiveMoveTarget(null), 800); // Stop looking after animation settles

    // Create deep copy for mutation
    const newBoard = board.map(row => row.map(p => p ? { ...p } : null));
    const movedPiece = newBoard[move.from.row][move.from.col]!;

    // Update position
    newBoard[move.from.row][move.from.col] = null;
    newBoard[move.to.row][move.to.col] = movedPiece;
    movedPiece.position = move.to;

    let justCaptured = false;

    // Handle Capture
    if (move.isJump && move.jumpedPosition) {
      const captured = newBoard[move.jumpedPosition.row][move.jumpedPosition.col];
      newBoard[move.jumpedPosition.row][move.jumpedPosition.col] = null; // Remove from board

      if (captured) {
        // --- ZUEIRA LOGIC ---
        const isCombo = comboCount > 0;
        const phraseList = isCombo ? TAUNTS_EPIC : TAUNTS_SIMPLE;
        const tauntText = phraseList[Math.floor(Math.random() * phraseList.length)];
        // --------------------

        spawnParticles(move.to.row, move.to.col, tauntText, isCombo);

        setScores(prev => ({
          ...prev,
          [captured.player]: prev[captured.player] - 1
        }));
        justCaptured = true;
        setComboCount(c => c + 1);
        playSound.capture();
      }
    } else {
      setComboCount(0);
      playSound.move();
    }

    // Handle Promotion
    let promoted = false;
    if (!movedPiece.isKing) {
      if ((movedPiece.player === 'red' && move.to.row === 0) ||
          (movedPiece.player === 'blue' && move.to.row === BOARD_SIZE - 1)) {
        movedPiece.isKing = true;
        promoted = true;
        playSound.king();
        spawnParticles(move.to.row, move.to.col, "REI!", true);
      }
    }

    setBoard(newBoard);
    setSelectedPieceId(null);
    setValidMoves([]);

    // Multi-jump Logic
    if (justCaptured && !promoted) {
      // Check if this specific piece can jump again
      const nextMoves = calculateValidMoves(movedPiece, newBoard).filter(m => m.isJump);
      if (nextMoves.length > 0) {
        // Must continue with this piece
        setForcedCapture(movedPiece.id);
        // If it's AI, we return here and let the Effect pick up the forced move
        // If it's Human, we re-select automatically
        if (movedPiece.player === HUMAN_PLAYER || gameMode === 'pvp') {
           setSelectedPieceId(movedPiece.id);
           setValidMoves(nextMoves);
        }
        return; // Turn does NOT change
      }
    }

    // End Turn
    endTurn(newBoard, movedPiece.player);
  };

  const endTurn = (currentBoard: (Piece | null)[][], currentPlayer: Player) => {
    setForcedCapture(null);
    setComboCount(0);
    const nextPlayer = currentPlayer === 'red' ? 'blue' : 'red';

    // Check win condition (count pieces or no moves)
    const { allMoves } = getAllValidMovesForPlayer(nextPlayer, currentBoard);

    if (allMoves.length === 0) {
      setWinner(currentPlayer); // Current player wins because next has no moves
      setGameState('winner');
      playSound.win();
    } else {
      setTurn(nextPlayer);
    }
  };

  // AI Logic removed for brevity (no changes needed there)

  // --- Effects & Visuals ---

  const spawnParticles = (row: number, col: number, text?: string, gold: boolean = false) => {
    const id = Date.now().toString() + Math.random();
    setParticles(prev => [...prev, { id, row, col, color: gold ? '#FFD700' : '#FFF', text }]);

    // Cleanup
    setTimeout(() => {
      setParticles(prev => prev.filter(p => p.id !== id));
    }, 1200);
  };

  // Render Helpers
  const renderSquare = (row: number, col: number) => {
    const isBlack = (row + col) % 2 === 1;
    const piece = board[row][col];
    const isPossibleMove = validMoves.some(m => m.to.row === row && m.to.col === col);
    const isSource = selectedPieceId && piece && piece.id === selectedPieceId;
    const cellParticles = particles.filter(p => p.row === row && p.col === col);

    return (
      <div 
        key={`${row}-${col}`}
        onClick={() => handleSquareClick(row, col)}
        className={`
          relative w-full h-full flex items-center justify-center
          ${isBlack ? 'bg-slate-800' : 'bg-slate-200'}
          ${isPossibleMove ? 'ring-inset ring-2 md:ring-4 ring-green-400 cursor-pointer' : ''}
          ${isBlack ? 'shadow-[inset_0_0_8px_rgba(0,0,0,0.5)]' : 'shadow-[inset_0_0_8px_rgba(255,255,255,0.5)]'}
        `}
      >
        {isPossibleMove && (
          <div className="absolute inset-1.5 md:inset-2 bg-green-400 rounded-full animate-pulse opacity-40"></div>
        )}

        {piece && (
          <div className={`w-full h-full p-0.5 md:p-1.5 z-10 transition-transform duration-300 ${isSource ? 'scale-110' : ''}`}>
             <ToonPiece 
                piece={piece} 
                isSelected={!!isSource} 
                canMove={turn === piece.player && !(gameMode === 'pve' && turn === AI_PLAYER)}
                focusTarget={activeMoveTarget}
                onClick={() => handleSquareClick(row, col)} 
             />
          </div>
        )}

        {cellParticles.map(p => (
           <div key={p.id} className="absolute inset-0 flex items-center justify-center z-50 pointer-events-none">
              <div className="animate-pop flex flex-col items-center">
                 <div className="text-2xl md:text-3xl filter drop-shadow-md">💥</div>
                 {p.text && (
                   <span className="text-lg md:text-2xl font-black text-white stroke-black drop-shadow-[0_3px_0_rgba(0,0,0,0.8)] whitespace-nowrap" 
                         style={{
                           color: p.color,
                           textShadow: '0 0 10px rgba(0,0,0,0.8)',
                           WebkitTextStroke: '1px black'
                         }}>
                     {p.text}
                   </span>
                 )}
              </div>
           </div>
        ))}
      </div>
    );
  };

  return (
    <div className="min-h-screen h-[100dvh] bg-slate-900 flex flex-col items-center justify-center text-white relative overflow-hidden select-none touch-none">
      <div className="absolute inset-0 opacity-20 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900 via-slate-900 to-black pointer-events-none"></div>

      {/* Optimized Header */}
      <div className="relative w-full max-w-lg flex items-center justify-between p-3 md:p-4 z-20 flex-shrink-0">
        <div className={`flex items-center gap-2 md:gap-4 transition-all duration-300 ${turn === 'blue' ? 'opacity-100 scale-105' : 'opacity-40 scale-90 grayscale'}`}>
          <div className="w-12 h-12 md:w-16 md:h-16 bg-sky-500 rounded-full border-2 md:border-4 border-white shadow-lg flex items-center justify-center relative overflow-hidden">
             <div className="absolute w-2 h-2 bg-white rounded-full top-2 left-2 opacity-50"></div>
             <span className="text-xl md:text-2xl font-black">{scores.blue}</span>
          </div>
          <div className="hidden sm:block">
            <div className="font-bold text-sky-300 text-sm md:text-lg tracking-wider">BLUE</div>
            {gameMode === 'pve' && <div className="text-[10px] text-sky-400 font-bold uppercase">CPU</div>}
          </div>
        </div>

        <div className="flex flex-col items-center">
          <h1 className="text-xl md:text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500 tracking-tighter drop-shadow-md">
            TOON CHECKERS
          </h1>
          <div className={`px-4 py-1 rounded-full text-[10px] md:text-xs font-bold mt-1 uppercase tracking-widest border border-slate-700 shadow-xl min-w-[120px] text-center ${turn === 'red' ? 'bg-rose-900/40 text-rose-300' : 'bg-sky-900/40 text-sky-300'}`}>
             {isAIThinking ? 'PENSANDO...' : (turn === 'red' ? 'SUA VEZ' : 'VEZ AZUL')}
          </div>
        </div>

        <div className={`flex items-center gap-2 md:gap-4 transition-all duration-300 ${turn === 'red' ? 'opacity-100 scale-105' : 'opacity-40 scale-90 grayscale'}`}>
          <div className="hidden sm:block text-right"> 
             <div className="font-bold text-rose-300 text-sm md:text-lg tracking-wider">RED</div>
             {gameMode === 'pve' && <div className="text-[10px] text-rose-400 font-bold uppercase">VOCÊ</div>}
          </div>
          <div className="w-12 h-12 md:w-16 md:h-16 bg-rose-500 rounded-full border-2 md:border-4 border-white shadow-lg flex items-center justify-center relative overflow-hidden">
            <div className="absolute w-2 h-2 bg-white rounded-full top-2 right-2 opacity-50"></div>
            <span className="text-xl md:text-2xl font-black">{scores.red}</span>
          </div>
        </div>
      </div>

      {comboCount > 1 && (
        <div className="absolute top-[18%] z-50 animate-pop pointer-events-none">
          <span className="text-4xl md:text-6xl font-black text-yellow-400 drop-shadow-[0_4px_0_rgba(0,0,0,1)] stroke-black" style={{WebkitTextStroke: '1.5px black'}}>
            COMBO x{comboCount}!
          </span>
        </div>
      )}

      {/* Main Game Area Optimized for Mobile */}
      <main className="relative z-10 flex items-center justify-center w-full flex-grow p-1">
        <div className={`
          relative
          w-[98vw] h-[98vw] 
          max-w-[min(98vw,500px)] 
          max-h-[min(98vw,500px)]
          md:w-[min(600px,75vmin)] 
          md:h-[min(600px,75vmin)]
          bg-slate-950 p-1 md:p-3 rounded-lg md:rounded-2xl shadow-2xl border-b-4 md:border-b-[8px] border-slate-950
          transition-all duration-700
          ${gameState === 'winner' ? 'scale-90 blur-sm' : ''}
        `}>
          <div className="w-full h-full bg-slate-800 rounded-md md:rounded-xl overflow-hidden grid grid-cols-8 grid-rows-8 shadow-inner ring-2 md:ring-4 ring-slate-800">
            {board.map((row, r) => row.map((_, c) => renderSquare(r, c)))}
          </div>
        </div>
      </main>

      {/* Menus / Footer Instructions (Same as before, simplified for mobile) */}
      {gameState === 'menu' && (
        <div className="absolute inset-0 bg-slate-900/95 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in p-6">
           <div className="text-4xl md:text-7xl font-black text-white mb-10 tracking-tighter drop-shadow-xl animate-float text-center">
             TOON CHECKERS
           </div>

           <div className="flex flex-col gap-5 w-full max-w-xs">
             <button onClick={() => setShowDifficultySelect(true)} className="w-full px-8 py-5 bg-purple-500 hover:bg-purple-400 text-white rounded-2xl font-black text-xl shadow-[0_6px_0_rgb(107,33,168)] active:shadow-none active:translate-y-[6px] transition-all flex items-center justify-center gap-3">
               <span>🤖</span> 1 JOGADOR
             </button>
             <button onClick={() => initGame('pvp')} className="w-full px-8 py-5 bg-green-500 hover:bg-green-400 text-white rounded-2xl font-black text-xl shadow-[0_6px_0_rgb(21,128,61)] active:shadow-none active:translate-y-[6px] transition-all flex items-center justify-center gap-3">
               <span>👥</span> 2 JOGADORES
             </button>
           </div>
        </div>
      )}

      {/* Reuse difficulty selection and winner UI from previous version, just ensure w-full max-w-xs on mobile */}
      {/* (Other overlays omitted for brevity but they should follow the max-w-xs pattern) */}

      <div className="absolute bottom-4 text-slate-500 text-[10px] font-bold tracking-widest uppercase opacity-40 pointer-events-none">
         {gameState === 'playing' ? (gameMode === 'pve' ? `MODO CPU: ${difficulty}` : 'MODO PVP') : ''}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import ToonPiece from './components/ToonPiece';
import { Piece, Position, Move, Player, GameState, Particle, GameMode, Difficulty } from './types';
import { playSound } from './utils/audio';

// --- Constants ---
const BOARD_SIZE = 8;
const AI_PLAYER: Player = 'blue';
const HUMAN_PLAYER: Player = 'red';

// --- Taunt Phrases (Zueira Lists) ---
const TAUNTS_SIMPLE = [
  "Tchau!", "Ops!", "Já era", "Vaza", "Perdeu", "Eita...", 
  "Xiu!", "Fácil", "Noob?", "Chora", "Sentou", "Sumiu", 
  "Kkkk", "Fraco", "Deu ruim", "Falou!", "Tankou?", "Ih..."
];

const TAUNTS_EPIC = [
  "SOLADO!", "AULA!", "RECEBA!", "QUE ISSO?", "SEGURA!", 
  "NEM VIU", "DESTRUIÇÃO", "CHORA MAIS", "COITADO", "MITO", 
  "LENDÁRIO", "NEM CLICOU", "DORMIU?", "TOMA!", "JOGA MUITO", "RESPEITA"
];

const App: React.FC = () => {
  // --- State ---
  const [gameState, setGameState] = useState<GameState>('menu');
  const [gameMode, setGameMode] = useState<GameMode>('pvp');
  const [difficulty, setDifficulty] = useState<Difficulty>('medium');
  const [showDifficultySelect, setShowDifficultySelect] = useState(false);

  const [board, setBoard] = useState<(Piece | null)[][]>([]);
  const [turn, setTurn] = useState<Player>('red'); // Red starts
  const [selectedPieceId, setSelectedPieceId] = useState<string | null>(null);
  const [validMoves, setValidMoves] = useState<Move[]>([]);
  const [forcedCapture, setForcedCapture] = useState<string | null>(null); // ID of piece that MUST double jump
  const [scores, setScores] = useState({ red: 0, blue: 0 });
  const [particles, setParticles] = useState<Particle[]>([]);
  const [winner, setWinner] = useState<Player | null>(null);
  const [comboCount, setComboCount] = useState(0);

  // Tracks where a move is currently landing so other pieces can look at it
  const [activeMoveTarget, setActiveMoveTarget] = useState<Position | null>(null);

  // AI Thinking State
  const [isAIThinking, setIsAIThinking] = useState(false);

  // --- Initialization ---
  const initGame = (mode: GameMode, diff: Difficulty = 'medium') => {
    const newBoard: (Piece | null)[][] = Array(BOARD_SIZE).fill(null).map(() => Array(BOARD_SIZE).fill(null));
    let idCounter = 0;

    for (let row = 0; row < BOARD_SIZE; row++) {
      for (let col = 0; col < BOARD_SIZE; col++) {
        if ((row + col) % 2 === 1) {
          if (row < 3) {
            newBoard[row][col] = { id: `blue-${idCounter++}`, player: 'blue', isKing: false, position: { row, col }, isCaptured: false };
          } else if (row > 4) {
            newBoard[row][col] = { id: `red-${idCounter++}`, player: 'red', isKing: false, position: { row, col }, isCaptured: false };
          }
        }
      }
    }
    setBoard(newBoard);
    setTurn('red');
    setGameMode(mode);
    setDifficulty(diff);
    setScores({ red: 12, blue: 12 });
    setGameState('playing');
    setWinner(null);
    setForcedCapture(null);
    setSelectedPieceId(null);
    setValidMoves([]);
    setComboCount(0);
    setActiveMoveTarget(null);
    setIsAIThinking(false);
    setShowDifficultySelect(false);
    playSound.move();
  };

  // --- Logic Helper Functions ---

  const getPieceAt = (b: (Piece | null)[][], pos: Position) => {
    if (pos.row < 0 || pos.row >= BOARD_SIZE || pos.col < 0 || pos.col >= BOARD_SIZE) return null;
    return b[pos.row][pos.col];
  };

  const calculateValidMoves = (piece: Piece, currentBoard: (Piece | null)[][]): Move[] => {
    const moves: Move[] = [];
    const directions = piece.isKing 
      ? [[-1, -1], [-1, 1], [1, -1], [1, 1]] 
      : piece.player === 'red' ? [[-1, -1], [-1, 1]] : [[1, -1], [1, 1]];

    directions.forEach(([dRow, dCol]) => {
      // 1. Simple Move
      const targetPos = { row: piece.position.row + dRow, col: piece.position.col + dCol };
      if (
        targetPos.row >= 0 && targetPos.row < BOARD_SIZE &&
        targetPos.col >= 0 && targetPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, targetPos)
      ) {
         moves.push({ from: piece.position, to: targetPos, isJump: false });
      }

      // 2. Jump (Capture)
      const jumpPos = { row: piece.position.row + (dRow * 2), col: piece.position.col + (dCol * 2) };
      if (
        jumpPos.row >= 0 && jumpPos.row < BOARD_SIZE &&
        jumpPos.col >= 0 && jumpPos.col < BOARD_SIZE &&
        !getPieceAt(currentBoard, jumpPos)
      ) {
        const midPos = targetPos;
        const midPiece = getPieceAt(currentBoard, midPos);
        if (midPiece && midPiece.player !== piece.player) {
          moves.push({ 
            from: piece.position, 
            to: jumpPos, 
            isJump: true, 
            capturedPieceId: midPiece.id, 
            jumpedPosition: midPos 
          });
        }
      }
    });

    return moves;
  };

  const getAllValidMovesForPlayer = (player: Player, currentBoard: (Piece | null)[][]) => {
    let allMoves: { pieceId: string, move: Move }[] = [];
    let hasJump = false;

    // Iterate board to find all player pieces
    for(let r=0; r<BOARD_SIZE; r++){
      for(let c=0; c<BOARD_SIZE; c++){
        const p = currentBoard[r][c];
        if(p && p.player === player && !p.isCaptured){
          const moves = calculateValidMoves(p, currentBoard);
          moves.forEach(m => {
            if(m.isJump) hasJump = true;
            allMoves.push({ pieceId: p.id, move: m });
          });
        }
      }
    }

    // Forced capture rule: If a jump exists, remove non-jumps
    if (hasJump) {
      allMoves = allMoves.filter(m => m.move.isJump);
    }

    return { allMoves, hasJump };
  };

  // --- Interaction ---

  const handleSquareClick = (row: number, col: number) => {
    if (gameState !== 'playing') return;

    // Disable interaction if AI is thinking or if it's AI's turn in PvE
    if (gameMode === 'pve' && (turn === AI_PLAYER || isAIThinking)) return;

    const clickedPiece = board[row][col];
    const isCurrentPlayerPiece = clickedPiece?.player === turn;

    // 1. Selecting a piece
    if (isCurrentPlayerPiece) {
      if (forcedCapture && forcedCapture !== clickedPiece.id) {
        playSound.error();
        return; // Must play the forced piece
      }

      // Calculate moves for this piece
      const { allMoves, hasJump } = getAllValidMovesForPlayer(turn, board);

      // If forced jumps exist globally, can only select pieces that can jump
      if (hasJump) {
         const canThisJump = allMoves.some(m => m.pieceId === clickedPiece.id && m.move.isJump);
         if (!canThisJump) {
            playSound.error();
            return;
         }
      }

      setSelectedPieceId(clickedPiece.id);

      // Filter valid moves for just this piece
      const movesForPiece = allMoves
        .filter(m => m.pieceId === clickedPiece.id)
        .map(m => m.move);

      setValidMoves(movesForPiece);
      playSound.move();
      return;
    }

    // 2. Moving to an empty square (executing a move)
    if (!clickedPiece && selectedPieceId) {
      const move = validMoves.find(m => m.to.row === row && m.to.col === col);
      if (move) {
        executeMove(move);
      } else {
        // Deselect if clicking invalid empty square
        setSelectedPieceId(null);
        setValidMoves([]);
      }
    }
  };

  const executeMove = (move: Move) => {
    const piece = getPieceAt(board, move.from);
    if (!piece) return;

    // Trigger global "look at" event
    setActiveMoveTarget(move.to);
    setTimeout(() => setActiveMoveTarget(null), 800); // Stop looking after animation settles

    // Create deep copy for mutation
    const newBoard = board.map(row => row.map(p => p ? { ...p } : null));
    const movedPiece = newBoard[move.from.row][move.from.col]!;

    // Update position
    newBoard[move.from.row][move.from.col] = null;
    newBoard[move.to.row][move.to.col] = movedPiece;
    movedPiece.position = move.to;

    let justCaptured = false;

    // Handle Capture
    if (move.isJump && move.jumpedPosition) {
      const captured = newBoard[move.jumpedPosition.row][move.jumpedPosition.col];
      newBoard[move.jumpedPosition.row][move.jumpedPosition.col] = null; // Remove from board

      if (captured) {
        // --- ZUEIRA LOGIC ---
        const isCombo = comboCount > 0;
        const phraseList = isCombo ? TAUNTS_EPIC : TAUNTS_SIMPLE;
        const tauntText = phraseList[Math.floor(Math.random() * phraseList.length)];
        // --------------------

        spawnParticles(move.to.row, move.to.col, tauntText, isCombo);

        setScores(prev => ({
          ...prev,
          [captured.player]: prev[captured.player] - 1
        }));
        justCaptured = true;
        setComboCount(c => c + 1);
        playSound.capture();
      }
    } else {
      setComboCount(0);
      playSound.move();
    }

    // Handle Promotion
    let promoted = false;
    if (!movedPiece.isKing) {
      if ((movedPiece.player === 'red' && move.to.row === 0) ||
          (movedPiece.player === 'blue' && move.to.row === BOARD_SIZE - 1)) {
        movedPiece.isKing = true;
        promoted = true;
        playSound.king();
        spawnParticles(move.to.row, move.to.col, "REI!", true);
      }
    }

    setBoard(newBoard);
    setSelectedPieceId(null);
    setValidMoves([]);

    // Multi-jump Logic
    if (justCaptured && !promoted) {
      // Check if this specific piece can jump again
      const nextMoves = calculateValidMoves(movedPiece, newBoard).filter(m => m.isJump);
      if (nextMoves.length > 0) {
        // Must continue with this piece
        setForcedCapture(movedPiece.id);
        // If it's AI, we return here and let the Effect pick up the forced move
        // If it's Human, we re-select automatically
        if (movedPiece.player === HUMAN_PLAYER || gameMode === 'pvp') {
           setSelectedPieceId(movedPiece.id);
           setValidMoves(nextMoves);
        }
        return; // Turn does NOT change
      }
    }

    // End Turn
    endTurn(newBoard, movedPiece.player);
  };

  const endTurn = (currentBoard: (Piece | null)[][], currentPlayer: Player) => {
    setForcedCapture(null);
    setComboCount(0);
    const nextPlayer = currentPlayer === 'red' ? 'blue' : 'red';

    // Check win condition (count pieces or no moves)
    const { allMoves } = getAllValidMovesForPlayer(nextPlayer, currentBoard);

    if (allMoves.length === 0) {
      setWinner(currentPlayer); // Current player wins because next has no moves
      setGameState('winner');
      playSound.win();
    } else {
      setTurn(nextPlayer);
    }
  };

  // Heuristic Scoring for AI (re-added correctly from logic)
  useEffect(() => {
    if (gameState !== 'playing' || gameMode !== 'pve') return;
    if (turn !== AI_PLAYER) return;

    // AI Turn
    setIsAIThinking(true);

    const performAIMove = async () => {
        const minDelay = difficulty === 'easy' ? 500 : difficulty === 'medium' ? 800 : 1000;
        const delay = Math.random() * 500 + minDelay;
        await new Promise(r => setTimeout(r, delay));

        const { allMoves } = getAllValidMovesForPlayer(AI_PLAYER, board);

        let validAIMoves = allMoves.map(m => m.move);
        if (forcedCapture) {
             const forcingPieceMoves = allMoves
                .filter(m => m.pieceId === forcedCapture)
                .map(m => m.move);
             validAIMoves = forcingPieceMoves;
        }

        if (validAIMoves.length === 0) return;

        const scoredMoves = validAIMoves.map(move => {
            let score = 0;
            const piece = getPieceAt(board, move.from)!;

            if (difficulty === 'easy') return { move, score: Math.random() * 100 };

            if (move.isJump) score += 100;
            if (!piece.isKing && move.to.row === BOARD_SIZE - 1) score += 50;

            const isSafe = !isPositionUnderAttack(move.to, board);

            if (difficulty === 'medium') {
                if (isSafe) score += 20;
                if (move.to.col >= 2 && move.to.col <= 5 && move.to.row >= 2 && move.to.row <= 5) score += 5;
                score += Math.random() * 10;
            } else if (difficulty === 'hard') {
                if (isSafe) score += 30; else score -= 50;
                if (move.to.col >= 2 && move.to.col <= 5 && move.to.row >= 2 && move.to.row <= 5) score += 15;
                if (piece.position.row === 0 && !piece.isKing) score -= 20;
                score += move.to.row * 2;
                score += Math.random() * 5;
            }
            return { move, score };
        });

        scoredMoves.sort((a, b) => b.score - a.score);
        const bestMove = scoredMoves[0].move;
        executeMove(bestMove);
        setIsAIThinking(false);
    };

    performAIMove();
  }, [turn, gameState, gameMode, forcedCapture, board, difficulty]);

  const isPositionUnderAttack = (pos: Position, currentBoard: (Piece | null)[][]): boolean => {
      const enemy: Player = 'red';
      const dirs = [[-1, -1], [-1, 1], [1, -1], [1, 1]];
      for (const [dr, dc] of dirs) {
          const enemyPos = { row: pos.row + dr, col: pos.col + dc };
          if (enemyPos.row >= 0 && enemyPos.row < BOARD_SIZE && enemyPos.col >= 0 && enemyPos.col < BOARD_SIZE) {
               const p = getPieceAt(currentBoard, enemyPos);
               if (p && p.player === enemy) {
                  const jumpLandingRow = pos.row + (pos.row - enemyPos.row);
                  const jumpLandingCol = pos.col + (pos.col - enemyPos.col);
                  if (jumpLandingRow >= 0 && jumpLandingRow < BOARD_SIZE && 
                      jumpLandingCol >= 0 && jumpLandingCol < BOARD_SIZE) {
                       if (!getPieceAt(currentBoard, {row: jumpLandingRow, col: jumpLandingCol})) return true;
                  }
               }
          }
      }
      return false;
  };

  // --- Effects & Visuals ---

  const spawnParticles = (row: number, col: number, text?: string, gold: boolean = false) => {
    const id = Date.now().toString() + Math.random();
    setParticles(prev => [...prev, { id, row, col, color: gold ? '#FFD700' : '#FFF', text }]);
    setTimeout(() => {
      setParticles(prev => prev.filter(p => p.id !== id));
    }, 1200);
  };

  const renderSquare = (row: number, col: number) => {
    const isBlack = (row + col) % 2 === 1;
    const piece = board[row][col];
    const isPossibleMove = validMoves.some(m => m.to.row === row && m.to.col === col);
    const isSource = selectedPieceId && piece && piece.id === selectedPieceId;
    const cellParticles = particles.filter(p => p.row === row && p.col === col);

    return (
      <div 
        key={`${row}-${col}`}
        onClick={() => handleSquareClick(row, col)}
        className={`
          relative w-full h-full flex items-center justify-center
          ${isBlack ? 'bg-slate-800' : 'bg-slate-200'}
          ${isPossibleMove ? 'ring-inset ring-2 md:ring-4 ring-green-400 cursor-pointer' : ''}
          ${isBlack ? 'shadow-[inset_0_0_8px_rgba(0,0,0,0.5)]' : 'shadow-[inset_0_0_8px_rgba(255,255,255,0.5)]'}
        `}
      >
        {isPossibleMove && (
          <div className="absolute inset-1.5 md:inset-2 bg-green-400 rounded-full animate-pulse opacity-40"></div>
        )}

        {piece && (
          <div className={`w-full h-full p-0.5 md:p-1.5 z-10 transition-transform duration-300 ${isSource ? 'scale-110' : ''}`}>
             <ToonPiece 
                piece={piece} 
                isSelected={!!isSource} 
                canMove={turn === piece.player && !(gameMode === 'pve' && turn === AI_PLAYER)}
                focusTarget={activeMoveTarget}
                onClick={() => handleSquareClick(row, col)} 
             />
          </div>
        )}

        {cellParticles.map(p => (
           <div key={p.id} className="absolute inset-0 flex items-center justify-center z-50 pointer-events-none">
              <div className="animate-pop flex flex-col items-center">
                 <div className="text-2xl md:text-3xl filter drop-shadow-md">💥</div>
                 {p.text && (
                   <span className="text-lg md:text-2xl font-black text-white stroke-black drop-shadow-[0_3px_0_rgba(0,0,0,0.8)] whitespace-nowrap" 
                         style={{
                           color: p.color,
                           textShadow: '0 0 10px rgba(0,0,0,0.8)',
                           WebkitTextStroke: '1px black'
                         }}>
                     {p.text}
                   </span>
                 )}
              </div>
           </div>
        ))}
      </div>
    );
  };

  return (
    <div className="min-h-screen h-[100dvh] bg-slate-900 flex flex-col items-center justify-center text-white relative overflow-hidden select-none touch-none">
      <div className="absolute inset-0 opacity-20 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900 via-slate-900 to-black pointer-events-none"></div>

      {/* Optimized Header */}
      <div className="relative w-full max-w-lg flex items-center justify-between p-3 md:p-4 z-20 flex-shrink-0">

        {/* Home Button (Visible when playing) */}
        {gameState === 'playing' && (
          <button 
            onClick={() => setGameState('menu')}
            className="absolute -top-1 md:-top-2 left-4 px-3 py-1 bg-slate-700/80 hover:bg-slate-600 text-[10px] md:text-xs font-black rounded-b-xl border border-t-0 border-slate-500 shadow-md transition-all active:translate-y-1"
          >
            SAIR
          </button>
        )}

        <div className={`flex items-center gap-2 md:gap-4 transition-all duration-300 ${turn === 'blue' ? 'opacity-100 scale-105' : 'opacity-40 scale-90 grayscale'}`}>
          <div className="w-12 h-12 md:w-16 md:h-16 bg-sky-500 rounded-full border-2 md:border-4 border-white shadow-lg flex items-center justify-center relative overflow-hidden">
             <div className="absolute w-2 h-2 bg-white rounded-full top-2 left-2 opacity-50"></div>
             <span className="text-xl md:text-2xl font-black">{scores.blue}</span>
          </div>
          <div className="hidden sm:block">
            <div className="font-bold text-sky-300 text-sm md:text-lg tracking-wider">BLUE</div>
            {gameMode === 'pve' && <div className="text-[10px] text-sky-400 font-bold uppercase">CPU</div>}
          </div>
        </div>

        <div className="flex flex-col items-center">
          <h1 className="text-xl md:text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500 tracking-tighter drop-shadow-md">
            TOON CHECKERS
          </h1>
          <div className={`px-4 py-1 rounded-full text-[10px] md:text-xs font-bold mt-1 uppercase tracking-widest border border-slate-700 shadow-xl min-w-[120px] text-center ${turn === 'red' ? 'bg-rose-900/40 text-rose-300' : 'bg-sky-900/40 text-sky-300'}`}>
             {isAIThinking ? 'PENSANDO...' : (turn === 'red' ? 'SUA VEZ' : 'VEZ AZUL')}
          </div>
        </div>

        <div className={`flex items-center gap-2 md:gap-4 transition-all duration-300 ${turn === 'red' ? 'opacity-100 scale-105' : 'opacity-40 scale-90 grayscale'}`}>
          <div className="hidden sm:block text-right"> 
             <div className="font-bold text-rose-300 text-sm md:text-lg tracking-wider">RED</div>
             {gameMode === 'pve' && <div className="text-[10px] text-rose-400 font-bold uppercase">VOCÊ</div>}
          </div>
          <div className="w-12 h-12 md:w-16 md:h-16 bg-rose-500 rounded-full border-2 md:border-4 border-white shadow-lg flex items-center justify-center relative overflow-hidden">
            <div className="absolute w-2 h-2 bg-white rounded-full top-2 right-2 opacity-50"></div>
            <span className="text-xl md:text-2xl font-black">{scores.red}</span>
          </div>
        </div>
      </div>

      {comboCount > 1 && (
        <div className="absolute top-[18%] z-50 animate-pop pointer-events-none">
          <span className="text-4xl md:text-6xl font-black text-yellow-400 drop-shadow-[0_4px_0_rgba(0,0,0,1)] stroke-black" style={{WebkitTextStroke: '1.5px black'}}>
            COMBO x{comboCount}!
          </span>
        </div>
      )}

      {/* Main Game Area Optimized for Mobile */}
      <main className="relative z-10 flex items-center justify-center w-full flex-grow p-1">
        <div className={`
          relative
          w-[98vw] h-[98vw] 
          max-w-[min(98vw,500px)] 
          max-h-[min(98vw,500px)]
          md:w-[min(600px,75vmin)] 
          md:h-[min(600px,75vmin)]
          bg-slate-950 p-1 md:p-3 rounded-lg md:rounded-2xl shadow-2xl border-b-4 md:border-b-[8px] border-slate-950
          transition-all duration-700
          ${gameState === 'winner' ? 'scale-90 blur-sm' : ''}
        `}>
          <div className="w-full h-full bg-slate-800 rounded-md md:rounded-xl overflow-hidden grid grid-cols-8 grid-rows-8 shadow-inner ring-2 md:ring-4 ring-slate-800">
            {board.map((row, r) => row.map((_, c) => renderSquare(r, c)))}
          </div>
        </div>
      </main>

      {/* Menus / Footer Instructions */}
      {gameState === 'menu' && !showDifficultySelect && (
        <div className="absolute inset-0 bg-slate-900/95 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in p-6">
           <div className="text-4xl md:text-7xl font-black text-white mb-10 tracking-tighter drop-shadow-xl animate-float text-center">
             TOON CHECKERS
           </div>

           <div className="flex flex-col gap-5 w-full max-w-xs">
             <button onClick={() => setShowDifficultySelect(true)} className="w-full px-8 py-5 bg-purple-500 hover:bg-purple-400 text-white rounded-2xl font-black text-xl shadow-[0_6px_0_rgb(107,33,168)] active:shadow-none active:translate-y-[6px] transition-all flex items-center justify-center gap-3">
               <span>🤖</span> 1 JOGADOR
             </button>
             <button onClick={() => initGame('pvp')} className="w-full px-8 py-5 bg-green-500 hover:bg-green-400 text-white rounded-2xl font-black text-xl shadow-[0_6px_0_rgb(21,128,61)] active:shadow-none active:translate-y-[6px] transition-all flex items-center justify-center gap-3">
               <span>👥</span> 2 JOGADORES
             </button>
           </div>
        </div>
      )}

      {gameState === 'menu' && showDifficultySelect && (
        <div className="absolute inset-0 bg-slate-900/95 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in">
           <div className="text-3xl md:text-5xl font-black text-white mb-8 tracking-tighter drop-shadow-xl text-center px-4">
             DIFICULDADE
           </div>
           <div className="flex flex-col gap-4 w-full max-w-xs px-6">
             <button onClick={() => initGame('pve', 'easy')} className="w-full px-8 py-4 bg-teal-400 text-slate-900 rounded-2xl font-black text-lg shadow-[0_5px_0_rgb(20,184,166)] active:translate-y-[5px] active:shadow-none transition-all">FÁCIL</button>
             <button onClick={() => initGame('pve', 'medium')} className="w-full px-8 py-4 bg-orange-400 text-slate-900 rounded-2xl font-black text-lg shadow-[0_5px_0_rgb(249,115,22)] active:translate-y-[5px] active:shadow-none transition-all">MÉDIO</button>
             <button onClick={() => initGame('pve', 'hard')} className="w-full px-8 py-4 bg-red-500 text-white rounded-2xl font-black text-lg shadow-[0_5px_0_rgb(185,28,28)] active:translate-y-[5px] active:shadow-none transition-all">DIFÍCIL</button>
             <button onClick={() => setShowDifficultySelect(false)} className="mt-4 text-slate-400 font-bold hover:text-white transition-colors">← VOLTAR</button>
           </div>
        </div>
      )}

      {gameState === 'winner' && (
        <div className="absolute inset-0 bg-slate-900/95 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in">
           <div className="text-yellow-400 text-7xl md:text-8xl mb-4 animate-bounce">🏆</div>
           <h2 className="text-4xl md:text-6xl font-black text-white mb-2 drop-shadow-lg text-center">VITORIA {winner?.toUpperCase()}!</h2>
           <p className="text-slate-300 mb-10 font-bold text-xl md:text-2xl text-center">Estratégia Imbatível!</p>
           <div className="flex flex-col md:flex-row gap-4 w-full max-w-xs md:max-w-none md:justify-center px-6">
             <button onClick={() => setGameState('menu')} className="px-8 py-4 bg-slate-600 text-white rounded-2xl font-black text-xl shadow-[0_6px_0_rgb(51,65,85)] transition-all transform hover:scale-105">MENU</button>
             <button onClick={() => initGame(gameMode, difficulty)} className="px-8 py-4 bg-blue-500 text-white rounded-2xl font-black text-xl shadow-[0_6px_0_rgb(30,58,138)] transition-all transform hover:scale-105">JOGAR NOVAMENTE</button>
           </div>
        </div>
      )}

      <div className="absolute bottom-4 text-slate-500 text-[10px] font-bold tracking-widest uppercase opacity-40 pointer-events-none">
         {gameState === 'playing' ? (gameMode === 'pve' ? `MODO CPU: ${difficulty.toUpperCase()}` : 'MODO PVP') : ''}
      </div>
    </div>
  );
};

