  player: Player;
  isKing: boolean;
  position: Position;
  isCaptured: boolean; // Visual state
}

export interface Move {
  from: Position;
  to: Position;
  isJump: boolean;
  capturedPieceId?: string;
  jumpedPosition?: Position;
}

export type GameState = 'menu' | 'playing' | 'winner';
export type GameMode = 'pvp' | 'pve';
export type Difficulty = 'easy' | 'medium' | 'hard';

export interface Particle {
  id: string;
  row: number;
  col: number;
  color: string;
  text?: string;
}

export interface PlayerTheme {
  from: string;
  via: string;
  to: string;
  side: string;
}

export interface Theme {
  id: string;
  name: string;
  icon: string;
  boardDark: string;
  boardLight: string;
  red: PlayerTheme;
  blue: PlayerTheme;
}

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { Piece, Position, PlayerTheme } from '../types';

interface ToonPieceProps {
  piece: Piece;
  isSelected: boolean;
  canMove: boolean;
  onClick: () => void;
  focusTarget: Position | null;
  theme: PlayerTheme;
}

type IdleAction = 'none' | 'look-left' | 'look-right' | 'smirk' | 'ooh' | 'suspicious' | 'wiggle';

const ToonPiece: React.FC<ToonPieceProps> = ({ piece, isSelected, onClick, canMove, focusTarget, theme }) => {
  const [mood, setMood] = useState<'idle' | 'happy' | 'surprised' | 'focused' | 'evil'>('idle');
  const [idleAction, setIdleAction] = useState<IdleAction>('none');
  const [justBecameKing, setJustBecameKing] = useState(false);
  const timerRef = useRef<number>(0);
  const prevIsKingRef = useRef(piece.isKing);

  useEffect(() => {
    if (piece.isKing && !prevIsKingRef.current) {
        setJustBecameKing(true);
        setTimeout(() => setJustBecameKing(false), 2000);
    }
    prevIsKingRef.current = piece.isKing;
  }, [piece.isKing]);

  useEffect(() => {
    if (isSelected || focusTarget) {
      setIdleAction('none');
      if (timerRef.current) clearTimeout(timerRef.current);
      return;
    }

    const triggerRandomness = () => {
      const timeToNext = Math.random() * 4000 + 2000;
      timerRef.current = window.setTimeout(() => {
        const actions: IdleAction[] = ['look-left', 'look-right', 'smirk', 'ooh', 'suspicious', 'wiggle', 'none', 'none'];
        const picked = actions[Math.floor(Math.random() * actions.length)];
        setIdleAction(picked);
        if (picked !== 'none') {
            setTimeout(() => {
                setIdleAction(prev => (prev === picked ? 'none' : prev));
            }, 1000 + Math.random() * 1000);
        }
        triggerRandomness();
      }, timeToNext);
    };

    triggerRandomness();
    return () => { if (timerRef.current) clearTimeout(timerRef.current); };
  }, [isSelected, focusTarget, piece.id]);

  const lookAtStyle = useMemo(() => {
    if (focusTarget && !isSelected) {
      const dy = focusTarget.row - piece.position.row;
      const dx = focusTarget.col - piece.position.col;
      const distance = Math.sqrt(dx * dx + dy * dy) || 1;
      return { x: (dx / distance) * 6, y: (dy / distance) * 5, rotate: (dx / distance) * 10 };
    }
    if (idleAction === 'look-left') return { x: -5, y: 0, rotate: -5 };
    if (idleAction === 'look-right') return { x: 5, y: 0, rotate: 5 };
    if (idleAction === 'suspicious') return { x: 0, y: -1, rotate: 0 };
    return { x: 0, y: 0, rotate: 0 };
  }, [focusTarget, piece.position, isSelected, idleAction]);

  useEffect(() => {
    if (isSelected) setMood('surprised');
    else if (piece.isKing) setMood('evil');
    else if (focusTarget) setMood('focused');
    else setMood('idle');
  }, [isSelected, piece.isKing, focusTarget]);

  const isWiggling = idleAction === 'wiggle' && !isSelected && !focusTarget;
  const isKingFloating = piece.isKing && !isSelected;
  const baseRotation = (focusTarget && !isSelected) || idleAction !== 'none' ? lookAtStyle.rotate : 0;
  const transformStyle = isSelected 
    ? `translateY(-12px) scale(1.1) rotate(${baseRotation}deg)` 
    : `translateY(0px) rotate(${baseRotation}deg)`;

  // Create dynamic gradient style
  const bodyStyle: React.CSSProperties = {
    background: `linear-gradient(135deg, ${theme.from}, ${theme.via}, ${theme.to})`,
    boxShadow: isSelected 
      ? `inset 0 4px 10px rgba(255,255,255,0.5), inset 0 -6px 12px rgba(0,0,0,0.2), 0 16px 0 ${theme.side}, 0 24px 20px rgba(0,0,0,0.4)`
      : `inset 0 4px 6px rgba(255,255,255,0.4), inset 0 -4px 8px rgba(0,0,0,0.2), 0 6px 0 ${theme.side}, 0 8px 6px rgba(0,0,0,0.3)`,
  };

  return (
    <div 
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      className={`relative w-[92%] h-[92%] rounded-full cursor-pointer group transition-all duration-500 ease-[cubic-bezier(0.34,1.56,0.64,1)] flex items-center justify-center ${canMove ? 'hover:-translate-y-2' : ''}`}
      style={{ transform: transformStyle, zIndex: isSelected ? 50 : 10 }}
    >
        <div className={`w-full h-full rounded-full flex items-center justify-center relative ${isWiggling ? 'animate-[float_0.5s_ease-in-out_infinite]' : ''} ${isKingFloating ? 'animate-king-float' : ''} ${justBecameKing ? 'animate-levitate-once' : ''}`}
             style={bodyStyle}>
            <div className="absolute inset-1.5 md:inset-2 rounded-full border-2 md:border-4 border-black/10 opacity-50 pointer-events-none"></div>
            <div className="absolute inset-3 md:inset-4 rounded-full border border-white/10 opacity-30 pointer-events-none"></div>
            <div className="absolute top-2 left-1/4 w-1/2 h-1/5 bg-gradient-to-b from-white to-transparent opacity-40 rounded-full blur-[2px] pointer-events-none"></div>
            {isSelected && <div className="absolute -inset-1 rounded-full border-4 border-yellow-300 animate-pulse opacity-70 pointer-events-none"></div>}

            <div className="relative w-full h-full flex flex-col items-center justify-center mt-1 pointer-events-none z-10">
                <div className="absolute top-[28%] flex gap-2 transition-transform duration-300 z-20" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
                    <div className={`w-2.5 h-1 bg-black/70 rounded-full transition-all duration-300 origin-right ${mood === 'evil' ? 'rotate-[25deg] translate-y-0.5 opacity-100' : 'opacity-0'}`}></div>
                    <div className={`w-2.5 h-1 bg-black/70 rounded-full transition-all duration-300 origin-left ${mood === 'evil' ? '-rotate-[25deg] translate-y-0.5 opacity-100' : 'opacity-0'}`}></div>
                </div>
                <div className="flex gap-1 mb-1 transition-transform duration-300" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
                  <div className={`relative w-4 bg-white rounded-full overflow-hidden transition-all duration-300 shadow-sm border border-black/5 ${mood === 'evil' ? 'h-3.5 mt-1.5' : (idleAction === 'suspicious' ? 'h-2.5 mt-2.5' : 'h-5 animate-blink')}`}>
                    <div className={`absolute w-2 h-2 bg-slate-900 rounded-full top-[45%] left-1/2 transform -translate-x-1/2 -translate-y-1/2 ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
                    <div className="absolute top-0.5 right-0.5 w-1 h-1 bg-white rounded-full opacity-80"></div>
                  </div>
                  <div className={`relative w-4 bg-white rounded-full overflow-hidden transition-all duration-300 shadow-sm border border-black/5 ${mood === 'evil' ? 'h-3.5 mt-1.5' : (idleAction === 'suspicious' ? 'h-2.5 mt-2.5' : 'h-5 animate-blink')}`} style={{ animationDelay: '0.1s' }}>
                    <div className={`absolute w-2 h-2 bg-slate-900 rounded-full top-[45%] left-1/2 transform -translate-x-1/2 -translate-y-1/2 ${isSelected ? 'scale-125' : ''} transition-transform`}></div>
                    <div className="absolute top-0.5 right-0.5 w-1 h-1 bg-white rounded-full opacity-80"></div>
                  </div>
                </div>
                <div className={`bg-slate-900/80 transition-all duration-300 shadow-sm ${mood === 'surprised' || idleAction === 'ooh' ? 'h-3 w-3 rounded-full border-2 border-white/20' : 'w-4 h-2 rounded-b-full'} ${(mood === 'happy' || idleAction === 'smirk') ? 'h-3 w-6 rounded-b-xl border-t-0' : ''} ${mood === 'evil' ? 'w-5 h-2.5 rounded-b-full border-t-0' : ''} ${mood === 'focused' ? 'w-3 h-1.5 rounded-full scale-90' : ''} ${idleAction === 'suspicious' ? 'w-5 h-1 rounded-full' : ''}`}
                style={{ transform: `translate(${lookAtStyle.x * 0.5}px, ${lookAtStyle.y * 0.5}px) ${idleAction === 'smirk' || mood === 'evil' ? 'rotate(-5deg) translateX(1px)' : ''}` }}>
                   {mood === 'evil' && <div className="absolute top-0 left-0.5 w-1 h-1 bg-white rounded-b-full opacity-90"></div>}
                </div>
                {(mood === 'happy' || idleAction === 'smirk' || idleAction === 'ooh' || isSelected) && (
                    <>
                        <div className="absolute top-[65%] left-1 w-2.5 h-1.5 bg-rose-400 opacity-60 rounded-full blur-[2px]"></div>
                        <div className="absolute top-[65%] right-1 w-2.5 h-1.5 bg-rose-400 opacity-60 rounded-full blur-[2px]"></div>
                    </>
                )}
            </div>
            {piece.isKing && (
                <div className={`absolute -top-6 md:-top-8 left-1/2 transform -translate-x-1/2 w-8 h-8 md:w-10 md:h-10 z-30 pointer-events-none ${justBecameKing ? 'animate-crown-enter' : 'animate-float'}`}>
                    <div className="absolute inset-0 bg-yellow-400/30 rounded-full blur-md animate-pulse"></div>
                    <svg viewBox="0 0 24 24" fill="none" className="w-full h-full drop-shadow-xl filter animate-crown">
                        <path d="M2 18h20v2H2v-2zm0-2l4-8 4 6 4-6 4 8H2z" fill="url(#crownGradient)" stroke="#B8860B" strokeWidth="1" strokeLinejoin="round"/>
                        <defs>
                        <linearGradient id="crownGradient" x1="12" y1="2" x2="12" y2="20" gradientUnits="userSpaceOnUse">
                            <stop stopColor="#FFD700" />
                            <stop offset="1" stopColor="#F59E0B" />
                        </linearGradient>
                        </defs>
                        <circle cx="6" cy="6" r="1.5" fill="#FFF" className="animate-pulse" />
                        <circle cx="12" cy="10" r="1.5" fill="#FFF" className="animate-pulse" />
                        <circle cx="18" cy="6" r="1.5" fill="#FFF" className="animate-pulse" />
                    </svg>
                </div>
            )}
        </div>
    </div>
  );
};

