const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>('menu');
  const [gameMode, setGameMode] = useState<GameMode>('pvp');
  const [difficulty, setDifficulty] = useState<Difficulty>('medium');
  const [showDifficultySelect, setShowDifficultySelect] = useState(false);
  const [currentTheme, setCurrentTheme] = useState<Theme>(THEMES[0]);

  const [board, setBoard] = useState<(Piece | null)[][]>([]);
  const [turn, setTurn] = useState<Player>('red');
  const [selectedPieceId, setSelectedPieceId] = useState<string | null>(null);
  const [validMoves, setValidMoves] = useState<Move[]>([]);
  const [forcedCapture, setForcedCapture] = useState<string | null>(null);
  const [scores, setScores] = useState({ red: INITIAL_PIECES, blue: INITIAL_PIECES });
  const [particles, setParticles] = useState<Particle[]>([]);
  const [winner, setWinner] = useState<Player | null>(null);
  const [comboCount, setComboCount] = useState(0);
  const [activeMoveTarget, setActiveMoveTarget] = useState<Position | null>(null);
  const [isAIThinking, setIsAIThinking] = useState(false);

  const initGame = (mode: GameMode, diff: Difficulty = 'medium') => {
    const newBoard: (Piece | null)[][] = Array(BOARD_SIZE).fill(null).map(() => Array(BOARD_SIZE).fill(null));
    let idCounter = 0;

    for (let row = 0; row < BOARD_SIZE; row++) {
      for (let col = 0; col < BOARD_SIZE; col++) {
        if ((row + col) % 2 === 1) {
          if (row < 3) {
            newBoard[row][col] = { id: `blue-${idCounter++}`, player: 'blue', isKing: false, position: { row, col }, isCaptured: false };
          } else if (row > 4) {
            newBoard[row][col] = { id: `red-${idCounter++}`, player: 'red', isKing: false, position: { row, col }, isCaptured: false };
          }
        }
      }
    }
    setBoard(newBoard);
    setTurn('red');
    setGameMode(mode);
    setDifficulty(diff);
    setScores({ red: INITIAL_PIECES, blue: INITIAL_PIECES });
    setGameState('playing');
    setWinner(null);
    setForcedCapture(null);
    setSelectedPieceId(null);
    setValidMoves([]);
    setComboCount(0);
    setActiveMoveTarget(null);
    setIsAIThinking(false);
    setShowDifficultySelect(false);
    playSound.move();
  };

  const getPieceAt = (b: (Piece | null)[][], pos: Position) => {
    if (pos.row < 0 || pos.row >= BOARD_SIZE || pos.col < 0 || pos.col >= BOARD_SIZE) return null;
    return b[pos.row][pos.col];
  };

  const calculateValidMoves = (piece: Piece, currentBoard: (Piece | null)[][]): Move[] => {
    const moves: Move[] = [];
    const directions = piece.isKing 
      ? [[-1, -1], [-1, 1], [1, -1], [1, 1]] 
      : piece.player === 'red' ? [[-1, -1], [-1, 1]] : [[1, -1], [1, 1]];

    directions.forEach(([dRow, dCol]) => {
      const targetPos = { row: piece.position.row + dRow, col: piece.position.col + dCol };
      if (targetPos.row >= 0 && targetPos.row < BOARD_SIZE && targetPos.col >= 0 && targetPos.col < BOARD_SIZE && !getPieceAt(currentBoard, targetPos)) {
         moves.push({ from: piece.position, to: targetPos, isJump: false });
      }
      const jumpPos = { row: piece.position.row + (dRow * 2), col: piece.position.col + (dCol * 2) };
      if (jumpPos.row >= 0 && jumpPos.row < BOARD_SIZE && jumpPos.col >= 0 && jumpPos.col < BOARD_SIZE && !getPieceAt(currentBoard, jumpPos)) {
        const midPos = targetPos;
        const midPiece = getPieceAt(currentBoard, midPos);
        if (midPiece && midPiece.player !== piece.player) {
          moves.push({ from: piece.position, to: jumpPos, isJump: true, capturedPieceId: midPiece.id, jumpedPosition: midPos });
        }
      }
    });
    return moves;
  };

  const getAllValidMovesForPlayer = (player: Player, currentBoard: (Piece | null)[][]) => {
    let allMoves: { pieceId: string, move: Move }[] = [];
    let hasJump = false;
    for(let r=0; r<BOARD_SIZE; r++){
      for(let c=0; c<BOARD_SIZE; c++){
        const p = currentBoard[r][c];
        if(p && p.player === player && !p.isCaptured){
          const moves = calculateValidMoves(p, currentBoard);
          moves.forEach(m => {
            if(m.isJump) hasJump = true;
            allMoves.push({ pieceId: p.id, move: m });
          });
        }
      }
    }
    if (hasJump) allMoves = allMoves.filter(m => m.move.isJump);
    return { allMoves, hasJump };
  };

  const handleSquareClick = (row: number, col: number) => {
    if (gameState !== 'playing') return;
    if (gameMode === 'pve' && (turn === AI_PLAYER || isAIThinking)) return;
    const clickedPiece = board[row][col];
    const isCurrentPlayerPiece = clickedPiece?.player === turn;
    if (isCurrentPlayerPiece) {
      if (forcedCapture && forcedCapture !== clickedPiece.id) { playSound.error(); return; }
      const { allMoves, hasJump } = getAllValidMovesForPlayer(turn, board);
      if (hasJump && !allMoves.some(m => m.pieceId === clickedPiece.id && m.move.isJump)) { playSound.error(); return; }
      setSelectedPieceId(clickedPiece.id);
      const movesForPiece = allMoves.filter(m => m.pieceId === clickedPiece.id).map(m => m.move);
      setValidMoves(movesForPiece);
      playSound.move();
      return;
    }
    if (!clickedPiece && selectedPieceId) {
      const move = validMoves.find(m => m.to.row === row && m.to.col === col);
      if (move) executeMove(move);
      else { setSelectedPieceId(null); setValidMoves([]); }
    }
  };

  const executeMove = (move: Move) => {
    const piece = getPieceAt(board, move.from);
    if (!piece) return;
    setActiveMoveTarget(move.to);
    setTimeout(() => setActiveMoveTarget(null), 800);
    const newBoard = board.map(row => row.map(p => p ? { ...p } : null));
    const movedPiece = newBoard[move.from.row][move.from.col]!;
    newBoard[move.from.row][move.from.col] = null;
    newBoard[move.to.row][move.to.col] = movedPiece;
    movedPiece.position = move.to;
    let justCaptured = false;
    if (move.isJump && move.jumpedPosition) {
      const captured = newBoard[move.jumpedPosition.row][move.jumpedPosition.col];
      newBoard[move.jumpedPosition.row][move.jumpedPosition.col] = null;
      if (captured) {
        const isCombo = comboCount > 0;
        const phraseList = isCombo ? TAUNTS_EPIC : TAUNTS_SIMPLE;
        const tauntText = phraseList[Math.floor(Math.random() * phraseList.length)];
        spawnParticles(move.to.row, move.to.col, tauntText, isCombo);
        setScores(prev => ({ ...prev, [captured.player]: Math.max(0, prev[captured.player] - 1) }));
        justCaptured = true;
        setComboCount(c => c + 1);
        playSound.capture();
      }
    } else { setComboCount(0); playSound.move(); }
    let promoted = false;
    if (!movedPiece.isKing) {
      if ((movedPiece.player === 'red' && move.to.row === 0) || (movedPiece.player === 'blue' && move.to.row === BOARD_SIZE - 1)) {
        movedPiece.isKing = true;
        promoted = true;
        playSound.king();
        spawnParticles(move.to.row, move.to.col, "REI!", true);
      }
    }
    setBoard(newBoard);
    setSelectedPieceId(null);
    setValidMoves([]);
    if (justCaptured && !promoted) {
      const nextMoves = calculateValidMoves(movedPiece, newBoard).filter(m => m.isJump);
      if (nextMoves.length > 0) {
        setForcedCapture(movedPiece.id);
        if (movedPiece.player === HUMAN_PLAYER || gameMode === 'pvp') {
           setSelectedPieceId(movedPiece.id);
           setValidMoves(nextMoves);
        }
        return;
      }
    }
    endTurn(newBoard, movedPiece.player);
  };

  const endTurn = (currentBoard: (Piece | null)[][], currentPlayer: Player) => {
    setForcedCapture(null);
    setComboCount(0);
    const nextPlayer = currentPlayer === 'red' ? 'blue' : 'red';
    const { allMoves } = getAllValidMovesForPlayer(nextPlayer, currentBoard);

    // Win condition check by pieces count first
    const nextPlayerScore = nextPlayer === 'red' ? scores.red : scores.blue;
    if (nextPlayerScore <= 0 || allMoves.length === 0) {
      setWinner(currentPlayer);
      setGameState('winner');
      playSound.win();
    } else { setTurn(nextPlayer); }
  };

  useEffect(() => {
    if (gameState !== 'playing' || gameMode !== 'pve') return;
    if (turn !== AI_PLAYER) return;
    setIsAIThinking(true);
    const performAIMove = async () => {
        const minDelay = difficulty === 'easy' ? 500 : difficulty === 'medium' ? 800 : 1000;
        const delay = Math.random() * 500 + minDelay;
        await new Promise(r => setTimeout(r, delay));
        const { allMoves } = getAllValidMovesForPlayer(AI_PLAYER, board);
        let validAIMoves = allMoves.map(m => m.move);
        if (forcedCapture) {
             validAIMoves = allMoves.filter(m => m.pieceId === forcedCapture).map(m => m.move);
        }
        if (validAIMoves.length === 0) return;
        const scoredMoves = validAIMoves.map(move => {
            let score = 0;
            const piece = getPieceAt(board, move.from)!;
            if (difficulty === 'easy') return { move, score: Math.random() * 100 };
            if (move.isJump) score += 100;
            if (!piece.isKing && move.to.row === BOARD_SIZE - 1) score += 50;
            const isSafe = !isPositionUnderAttack(move.to, board);
            if (difficulty === 'medium') {
                if (isSafe) score += 20;
                if (move.to.col >= 2 && move.to.col <= 5 && move.to.row >= 2 && move.to.row <= 5) score += 5;
                score += Math.random() * 10;
            } else if (difficulty === 'hard') {
                if (isSafe) score += 30; else score -= 50;
                if (move.to.col >= 2 && move.to.col <= 5 && move.to.row >= 2 && move.to.row <= 5) score += 15;
                if (piece.position.row === 0 && !piece.isKing) score -= 20;
                score += move.to.row * 2;
                score += Math.random() * 5;
            }
            return { move, score };
        });
        scoredMoves.sort((a, b) => b.score - a.score);
        executeMove(scoredMoves[0].move);
        setIsAIThinking(false);
    };
    performAIMove();
  }, [turn, gameState, gameMode, forcedCapture, board, difficulty]);

  const isPositionUnderAttack = (pos: Position, currentBoard: (Piece | null)[][]): boolean => {
      const enemy: Player = 'red';
      const dirs = [[-1, -1], [-1, 1], [1, -1], [1, 1]];
      for (const [dr, dc] of dirs) {
          const enemyPos = { row: pos.row + dr, col: pos.col + dc };
          if (enemyPos.row >= 0 && enemyPos.row < BOARD_SIZE && enemyPos.col >= 0 && enemyPos.col < BOARD_SIZE) {
               const p = getPieceAt(currentBoard, enemyPos);
               if (p && p.player === enemy) {
                  const jumpLandingRow = pos.row + (pos.row - enemyPos.row);
                  const jumpLandingCol = pos.col + (pos.col - enemyPos.col);
                  if (jumpLandingRow >= 0 && jumpLandingRow < BOARD_SIZE && jumpLandingCol >= 0 && jumpLandingCol < BOARD_SIZE) {
                       if (!getPieceAt(currentBoard, {row: jumpLandingRow, col: jumpLandingCol})) return true;
                  }
               }
          }
      }
      return false;
  };

  const spawnParticles = (row: number, col: number, text?: string, gold: boolean = false) => {
    const id = Date.now().toString() + Math.random();
    setParticles(prev => [...prev, { id, row, col, color: gold ? '#FFD700' : '#FFF', text }]);
    setTimeout(() => { setParticles(prev => prev.filter(p => p.id !== id)); }, 1200);
  };

  const renderSquare = (row: number, col: number) => {
    const isBlack = (row + col) % 2 === 1;
    const piece = board[row][col];
    const isPossibleMove = validMoves.some(m => m.to.row === row && m.to.col === col);
    const isSource = selectedPieceId && piece && piece.id === selectedPieceId;
    const cellParticles = particles.filter(p => p.row === row && p.col === col);

    return (
      <div 
        key={`${row}-${col}`}
        onClick={() => handleSquareClick(row, col)}
        className="relative w-full h-full flex items-center justify-center transition-colors duration-500"
        style={{ backgroundColor: isBlack ? currentTheme.boardDark : currentTheme.boardLight, boxShadow: isBlack ? 'inset 0 0 8px rgba(0,0,0,0.5)' : 'inset 0 0 8px rgba(255,255,255,0.5)' }}
      >
        {isPossibleMove && <div className="absolute inset-1.5 md:inset-2 bg-green-400 rounded-full animate-pulse opacity-40"></div>}
        {piece && (
          <div className={`w-full h-full p-0.5 md:p-1.5 z-10 transition-transform duration-300 ${isSource ? 'scale-110' : ''}`}>
             <ToonPiece 
                piece={piece} 
                isSelected={!!isSource} 
                canMove={turn === piece.player && !(gameMode === 'pve' && turn === AI_PLAYER)}
                focusTarget={activeMoveTarget}
                onClick={() => handleSquareClick(row, col)} 
                theme={piece.player === 'red' ? currentTheme.red : currentTheme.blue}
             />
          </div>
        )}
        {cellParticles.map(p => (
           <div key={p.id} className="absolute inset-0 flex items-center justify-center z-50 pointer-events-none">
              <div className="animate-pop flex flex-col items-center">
                 <div className="text-2xl md:text-3xl filter drop-shadow-md">💥</div>
                 {p.text && (
                   <span className="text-lg md:text-2xl font-black text-white stroke-black drop-shadow-[0_3px_0_rgba(0,0,0,0.8)] whitespace-nowrap" 
                         style={{ color: p.color, textShadow: '0 0 10px rgba(0,0,0,0.8)', WebkitTextStroke: '1px black' }}>
                     {p.text}
                   </span>
                 )}
              </div>
           </div>
        ))}
      </div>
    );
  };

  return (
    <div className="min-h-screen h-[100dvh] bg-slate-900 flex flex-col items-center justify-center text-white relative overflow-hidden select-none touch-none transition-colors duration-1000">
      <div className="absolute inset-0 opacity-20 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900 via-slate-900 to-black pointer-events-none"></div>

      {/* Battle UI Header */}
      <div className="relative w-full max-w-4xl flex items-center justify-between p-3 md:p-6 z-20 flex-shrink-0">
        <BattleBar player="blue" score={scores.blue} theme={currentTheme} active={turn === 'blue'} />

        <div className="flex flex-col items-center mx-4 flex-shrink-0">
          <h1 className="text-xl md:text-3xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500 tracking-tighter drop-shadow-md text-center">TOON FIGHT!</h1>
          <div className="text-[10px] md:text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">ROUND 1</div>
          {isAIThinking && <div className="text-[8px] md:text-[10px] text-yellow-400 font-bold uppercase animate-pulse">CPU PENSANDO...</div>}
        </div>

        <BattleBar player="red" score={scores.red} theme={currentTheme} reverse active={turn === 'red'} />

        {gameState === 'playing' && (
          <button onClick={() => setGameState('menu')} className="absolute -bottom-8 left-1/2 -translate-x-1/2 px-4 py-1 bg-slate-800/80 hover:bg-red-600 text-[10px] font-black rounded-b-xl border border-t-0 border-slate-700 shadow-md transition-all active:translate-y-1 z-30 opacity-60 hover:opacity-100">
            DESISTIR
          </button>
        )}
      </div>

      {comboCount > 1 && <div className="absolute top-[22%] z-50 animate-pop pointer-events-none"><span className="text-4xl md:text-6xl font-black text-yellow-400 drop-shadow-[0_4px_0_rgba(0,0,0,1)] stroke-black" style={{WebkitTextStroke: '1.5px black'}}>COMBO x{comboCount}!</span></div>}

      <main className="relative z-10 flex items-center justify-center w-full flex-grow p-1">
        <div className={`relative w-[96vw] h-[96vw] max-w-[min(96vw,500px)] max-h-[min(96vw,500px)] md:w-[min(600px,70vmin)] md:h-[min(600px,70vmin)] bg-slate-950 p-1 md:p-4 rounded-lg md:rounded-2xl shadow-2xl border-b-4 md:border-b-[12px] border-slate-950 transition-all duration-700 ${gameState === 'winner' ? 'scale-90 blur-sm' : ''}`}>
          <div className="w-full h-full rounded-md md:rounded-xl overflow-hidden grid grid-cols-8 grid-rows-8 shadow-inner ring-4 md:ring-8 ring-slate-800" style={{ borderColor: currentTheme.boardDark }}>
            {board.map((row, r) => row.map((_, c) => renderSquare(r, c)))}
          </div>
        </div>
      </main>

      {gameState === 'menu' && !showDifficultySelect && (
        <div className="absolute inset-0 bg-slate-900/98 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in p-6 overflow-y-auto">
           <div className="text-5xl md:text-8xl font-black text-white mb-8 tracking-tighter drop-shadow-2xl animate-float text-center flex flex-col">
             <span className="text-yellow-400 scale-75 md:scale-90">TOON</span>
             <span className="mt-[-1rem] md:mt-[-2rem]">CHECKERS</span>
           </div>

           <div className="flex flex-col gap-4 w-full max-w-xs mb-8">
             <button onClick={() => setShowDifficultySelect(true)} className="w-full px-8 py-5 bg-purple-600 hover:bg-purple-500 text-white rounded-2xl font-black text-xl shadow-[0_6px_0_rgb(88,28,135)] active:shadow-none active:translate-y-[6px] transition-all flex items-center justify-center gap-3">🤖 MODO ARCADE</button>
             <button onClick={() => initGame('pvp')} className="w-full px-8 py-5 bg-green-600 hover:bg-green-500 text-white rounded-2xl font-black text-xl shadow-[0_6px_0_rgb(20,83,45)] active:shadow-none active:translate-y-[6px] transition-all flex items-center justify-center gap-3">👥 MODO VERSUS</button>
           </div>

           <div className="w-full max-w-sm">
             <p className="text-slate-500 font-bold text-xs uppercase tracking-widest text-center mb-4">Selecione Arena</p>
             <div className="grid grid-cols-4 gap-4">
               {THEMES.map(t => (
                 <button 
                  key={t.id} 
                  onClick={() => setCurrentTheme(t)} 
                  className={`
                    flex flex-col items-center justify-center p-3 rounded-2xl transition-all border-2 
                    ${currentTheme.id === t.id 
                      ? 'border-yellow-400 bg-slate-800 scale-110 shadow-[0_0_15px_rgba(250,204,21,0.4)]' 
                      : 'border-transparent bg-slate-800/30 grayscale opacity-50 hover:opacity-100 hover:grayscale-0'
                    }
                  `}
                 >
                   <span className="text-2xl mb-1">{t.icon}</span>
                   <span className="text-[10px] font-black uppercase tracking-tighter">{t.name}</span>
                 </button>
               ))}
             </div>
           </div>
        </div>
      )}

      {gameState === 'menu' && showDifficultySelect && (
        <div className="absolute inset-0 bg-slate-900/98 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in">
           <div className="text-4xl md:text-6xl font-black text-white mb-10 tracking-tighter drop-shadow-xl text-center px-4">ESCOLHA SEU OPONENTE</div>
           <div className="flex flex-col gap-4 w-full max-w-xs px-6">
             <button onClick={() => initGame('pve', 'easy')} className="w-full px-8 py-5 bg-teal-500 text-white rounded-2xl font-black text-xl shadow-[0_5px_0_rgb(13,148,136)] active:translate-y-[5px] active:shadow-none transition-all">ESTAGIÁRIO (FÁCIL)</button>
             <button onClick={() => initGame('pve', 'medium')} className="w-full px-8 py-5 bg-orange-500 text-white rounded-2xl font-black text-xl shadow-[0_5px_0_rgb(194,65,12)] active:translate-y-[5px] active:shadow-none transition-all">GUERREIRO (MÉDIO)</button>
             <button onClick={() => initGame('pve', 'hard')} className="w-full px-8 py-5 bg-red-600 text-white rounded-2xl font-black text-xl shadow-[0_5px_0_rgb(153,27,27)] active:translate-y-[5px] active:shadow-none transition-all">MESTRE (DIFÍCIL)</button>
             <button onClick={() => setShowDifficultySelect(false)} className="mt-8 text-slate-500 font-bold hover:text-white transition-colors flex items-center gap-2">← VOLTAR AO MENU</button>
           </div>
        </div>
      )}

      {gameState === 'winner' && (
        <div className="absolute inset-0 bg-slate-900/95 z-50 flex flex-col items-center justify-center backdrop-blur-md animate-fade-in">
           <div className="text-yellow-400 text-8xl md:text-9xl mb-4 animate-bounce drop-shadow-2xl">KO!</div>
           <h2 className={`text-4xl md:text-7xl font-black mb-2 drop-shadow-lg text-center uppercase tracking-tighter ${winner === 'red' ? 'text-rose-500' : 'text-sky-500'}`}>
             {winner === 'red' ? 'PLAYER 1 VENCEU!' : 'PLAYER 2 VENCEU!'}
           </h2>
           <p className="text-slate-300 mb-12 font-bold text-xl md:text-2xl text-center uppercase tracking-widest opacity-80">Finalização Perfeita!</p>
           <div className="flex flex-col md:flex-row gap-6 w-full max-w-xs md:max-w-none md:justify-center px-6">
             <button onClick={() => setGameState('menu')} className="px-10 py-5 bg-slate-700 text-white rounded-2xl font-black text-2xl shadow-[0_8px_0_rgb(31,41,55)] transition-all transform hover:scale-105 active:translate-y-2 active:shadow-none">MENU</button>
             <button onClick={() => initGame(gameMode, difficulty)} className="px-10 py-5 bg-yellow-500 text-slate-900 rounded-2xl font-black text-2xl shadow-[0_8px_0_rgb(161,98,7)] transition-all transform hover:scale-105 active:translate-y-2 active:shadow-none">REVANCHE</button>
           </div>
        </div>
      )}

      <div className="absolute bottom-4 text-slate-600 text-[10px] font-bold tracking-widest uppercase opacity-30 pointer-events-none flex gap-4">
         <span>MODO: {gameMode === 'pve' ? `ARCADE (${difficulty.toUpperCase()})` : 'VERSUS'}</span>
         <span>|</span>
         <span>TEMA: {currentTheme.name.toUpperCase()}</span>
      </div>
    </div>
  );
};

export default App;

export type Player = 'red' | 'blue';

export interface Position {
  row: number;
  col: number;
}

export interface Piece {
  id: string;
  player: Player;
  isKing: boolean;
  position: Position;
  isCaptured: boolean;
}

export interface Move {
  from: Position;
  to: Position;
  isJump: boolean;
  capturedPieceId?: string;
  jumpedPosition?: Position;
}

export type GameState = 'menu' | 'playing' | 'winner' | 'settings';
export type GameMode = 'pvp' | 'pve';
export type Difficulty = 'easy' | 'medium' | 'hard';

export interface Particle {
  id: string;
  row: number;
  col: number;
  color: string;
  text?: string;
}

export interface PlayerTheme {
  from: string;
  via: string;
  to: string;
  side: string;
}

export interface Theme {
  id: string;
  name: string;
  icon: string;
  boardDark: string;
  boardLight: string;
  red: PlayerTheme;
  blue: PlayerTheme;
}

export interface GameRules {
  flyingKings: boolean;
  backwardCapture: boolean;
  forcedCapture: boolean;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import ToonPiece from './components/ToonPiece';
import { Piece, Position, Move, Player, GameState, Particle, GameMode, Difficulty, Theme, GameRules } from './types';
import { playSound } from './utils/audio';

// --- Themes ---
const THEMES: Theme[] = [
  {
    id: 'classic',
    name: 'Clássico',
