};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>('menu');
  const [gameMode, setGameMode] = useState<GameMode>('pvp');
  const [difficulty, setDifficulty] = useState<Difficulty>('medium');
  const [showDifficultySelect, setShowDifficultySelect] = useState(false);
  const [currentTheme, setCurrentTheme] = useState<Theme>(THEMES[0]);
  const [rules, setRules] = useState<GameRules>(() => {
    const saved = localStorage.getItem('toon_checkers_rules');
    return saved ? JSON.parse(saved) : { flyingKings: true, backwardCapture: true, forcedCapture: true, pieceModel: 'classic' };
  });
  const [saveFeedback, setSaveFeedback] = useState(false);

  const [board, setBoard] = useState<(Piece | null)[][]>([]);
  const [turn, setTurn] = useState<Player>('red');
  const [selectedPieceId, setSelectedPieceId] = useState<string | null>(null);
  const [validMoves, setValidMoves] = useState<Move[]>([]);
  const [forcedCapture, setForcedCapture] = useState<string | null>(null);
  const [scores, setScores] = useState({ red: INITIAL_PIECES, blue: INITIAL_PIECES });
  const [particles, setParticles] = useState<Particle[]>([]);
  const [winner, setWinner] = useState<Player | null>(null);
  const [comboCount, setComboCount] = useState(0);
  const [activeMoveTarget, setActiveMoveTarget] = useState<Position | null>(null);
  const [isAIThinking, setIsAIThinking] = useState(false);

  const handleSaveSettings = () => {
    localStorage.setItem('toon_checkers_rules', JSON.stringify(rules));
    setSaveFeedback(true);
    playSound.king();
    setTimeout(() => {
      setSaveFeedback(false);
      setGameState('menu');
    }, 800);
  };

  const initGame = (mode: GameMode, diff: Difficulty = 'medium') => {
    const newBoard: (Piece | null)[][] = Array(BOARD_SIZE).fill(null).map(() => Array(BOARD_SIZE).fill(null));
    let idCounter = 0;
    for (let row = 0; row < BOARD_SIZE; row++) {
      for (let col = 0; col < BOARD_SIZE; col++) {
        if ((row + col) % 2 === 1) {
          if (row < 3) newBoard[row][col] = { id: `blue-${idCounter++}`, player: 'blue', isKing: false, position: { row, col }, isCaptured: false };
          else if (row > 4) newBoard[row][col] = { id: `red-${idCounter++}`, player: 'red', isKing: false, position: { row, col }, isCaptured: false };
        }
      }
    }
    setBoard(newBoard);
    setTurn('red');
    setGameMode(mode);
    setDifficulty(diff);
    setScores({ red: INITIAL_PIECES, blue: INITIAL_PIECES });
    setGameState('playing');
    setWinner(null);
    setForcedCapture(null);
    setSelectedPieceId(null);
    setValidMoves([]);
    setComboCount(0);
    setActiveMoveTarget(null);
    setIsAIThinking(false);
    setShowDifficultySelect(false);
    playSound.move();
  };

  const getPieceAt = (b: (Piece | null)[][], pos: Position) => {
    if (pos.row < 0 || pos.row >= BOARD_SIZE || pos.col < 0 || pos.col >= BOARD_SIZE) return null;
    return b[pos.row][pos.col];
  };

  const calculateValidMoves = (piece: Piece, currentBoard: (Piece | null)[][]): Move[] => {
    const moves: Move[] = [];
    const directions = [[-1, -1], [-1, 1], [1, -1], [1, 1]];

    if (piece.isKing && rules.flyingKings) {
      directions.forEach(([dr, dc]) => {
        let r = piece.position.row + dr;
        let c = piece.position.col + dc;
        let enemyFound: Piece | null = null;
        while (r >= 0 && r < BOARD_SIZE && c >= 0 && c < BOARD_SIZE) {
          const targetPiece = currentBoard[r][c];
          if (!targetPiece) {
            if (!enemyFound) moves.push({ from: piece.position, to: { row: r, col: c }, isJump: false });
            else moves.push({ from: piece.position, to: { row: r, col: c }, isJump: true, capturedPieceId: enemyFound.id, jumpedPosition: enemyFound.position });
          } else {
            if (targetPiece.player === piece.player) break;
            if (enemyFound) break;
            enemyFound = targetPiece;
          }
          r += dr; c += dc;
        }
      });
    } else {
      directions.forEach(([dr, dc]) => {
        const isForward = piece.player === 'red' ? dr < 0 : dr > 0;
        const canMoveDir = piece.isKing || isForward;
        const canJumpDir = piece.isKing || isForward || rules.backwardCapture;
        const targetPos = { row: piece.position.row + dr, col: piece.position.col + dc };
        const jumpPos = { row: piece.position.row + dr * 2, col: piece.position.col + dc * 2 };
        if (canMoveDir && targetPos.row >= 0 && targetPos.row < BOARD_SIZE && targetPos.col >= 0 && targetPos.col < BOARD_SIZE && !getPieceAt(currentBoard, targetPos)) {
            moves.push({ from: piece.position, to: targetPos, isJump: false });
        }
        if (canJumpDir && jumpPos.row >= 0 && jumpPos.row < BOARD_SIZE && jumpPos.col >= 0 && jumpPos.col < BOARD_SIZE) {
          const midPiece = getPieceAt(currentBoard, targetPos);
          if (midPiece && midPiece.player !== piece.player && !getPieceAt(currentBoard, jumpPos)) {
            moves.push({ from: piece.position, to: jumpPos, isJump: true, capturedPieceId: midPiece.id, jumpedPosition: targetPos });
          }
        }
      });
    }
    return moves;
  };

  const getAllValidMovesForPlayer = (player: Player, currentBoard: (Piece | null)[][]) => {
    let allMoves: { pieceId: string, move: Move }[] = [];
    let hasJump = false;
    for (let r = 0; r < BOARD_SIZE; r++) {
      for (let c = 0; c < BOARD_SIZE; c++) {
        const p = currentBoard[r][c];
        if (p && p.player === player && !p.isCaptured) {
          const moves = calculateValidMoves(p, currentBoard);
          moves.forEach(m => {
            if (m.isJump) hasJump = true;
            allMoves.push({ pieceId: p.id, move: m });
          });
        }
      }
    }
    if (hasJump && rules.forcedCapture) allMoves = allMoves.filter(m => m.move.isJump);
    return { allMoves, hasJump };
  };

  const handleSquareClick = (row: number, col: number) => {
    if (gameState !== 'playing' || (gameMode === 'pve' && turn === AI_PLAYER)) return;
    const clickedPiece = board[row][col];
    if (clickedPiece?.player === turn) {
      if (forcedCapture && forcedCapture !== clickedPiece.id) { playSound.error(); return; }
      const { allMoves, hasJump } = getAllValidMovesForPlayer(turn, board);
      if (hasJump && rules.forcedCapture && !allMoves.some(m => m.pieceId === clickedPiece.id && m.move.isJump)) { playSound.error(); return; }
      setSelectedPieceId(clickedPiece.id);
      setValidMoves(allMoves.filter(m => m.pieceId === clickedPiece.id).map(m => m.move));
      playSound.move();
    } else if (!clickedPiece && selectedPieceId) {
      const move = validMoves.find(m => m.to.row === row && m.to.col === col);
      if (move) executeMove(move);
      else { setSelectedPieceId(null); setValidMoves([]); }
    }
  };

  const executeMove = (move: Move) => {
    const piece = getPieceAt(board, move.from);
    if (!piece) return;
    setActiveMoveTarget(move.to);
    setTimeout(() => setActiveMoveTarget(null), 600);
    const newBoard = board.map(row => row.map(p => p ? { ...p } : null));
    const movedPiece = newBoard[move.from.row][move.from.col]!;
    newBoard[move.from.row][move.from.col] = null;
    newBoard[move.to.row][move.to.col] = movedPiece;
    movedPiece.position = move.to;

    let justCaptured = false;
    if (move.isJump && move.jumpedPosition) {
      newBoard[move.jumpedPosition.row][move.jumpedPosition.col] = null;
      setScores(prev => ({ ...prev, [turn === 'red' ? 'blue' : 'red']: Math.max(0, prev[turn === 'red' ? 'blue' : 'red'] - 1) }));
      justCaptured = true;
      setComboCount(c => c + 1);
      spawnParticles(move.to.row, move.to.col, comboCount > 0 ? TAUNTS_EPIC[Math.floor(Math.random()*TAUNTS_EPIC.length)] : TAUNTS_SIMPLE[Math.floor(Math.random()*TAUNTS_SIMPLE.length)], comboCount > 0);
      playSound.capture();
    } else { setComboCount(0); playSound.move(); }

    if (!movedPiece.isKing) {
      if ((movedPiece.player === 'red' && move.to.row === 0) || (movedPiece.player === 'blue' && move.to.row === BOARD_SIZE - 1)) {
        movedPiece.isKing = true;
        playSound.king();
        spawnParticles(move.to.row, move.to.col, "REI!", true);
      }
    }
    setBoard(newBoard);
    setSelectedPieceId(null);
    setValidMoves([]);
    if (justCaptured) {
      const nextMoves = calculateValidMoves(movedPiece, newBoard).filter(m => m.isJump);
      if (nextMoves.length > 0) {
        setForcedCapture(movedPiece.id);
        if (movedPiece.player === HUMAN_PLAYER || gameMode === 'pvp') {
          setSelectedPieceId(movedPiece.id);
          setValidMoves(nextMoves);
        }
        return;
      }
    }
    endTurn(newBoard, movedPiece.player);
  };

  const endTurn = (currentBoard: (Piece | null)[][], currentPlayer: Player) => {
    setForcedCapture(null);
    setComboCount(0);
    const nextPlayer = currentPlayer === 'red' ? 'blue' : 'red';
    const { allMoves } = getAllValidMovesForPlayer(nextPlayer, currentBoard);
    if (allMoves.length === 0) {
      setWinner(currentPlayer);
      setGameState('winner');
      playSound.win();
    } else { setTurn(nextPlayer); }
  };

  useEffect(() => {
    if (gameState !== 'playing' || gameMode !== 'pve' || turn !== AI_PLAYER) return;
    setIsAIThinking(true);
    const timer = setTimeout(async () => {
      const { allMoves } = getAllValidMovesForPlayer(AI_PLAYER, board);
      const candidates = forcedCapture ? allMoves.filter(m => m.pieceId === forcedCapture) : allMoves;
      if (candidates.length > 0) {
        const best = candidates.sort((a,b) => (b.move.isJump ? 10 : 0) - (a.move.isJump ? 10 : 0))[0];
        executeMove(best.move);
      }
      setIsAIThinking(false);
    }, 1000);
    return () => clearTimeout(timer);
  }, [turn, gameState, gameMode, forcedCapture]);

  const spawnParticles = (row: number, col: number, text?: string, gold: boolean = false) => {
    const id = Date.now().toString() + Math.random();
    setParticles(prev => [...prev, { id, row, col, color: gold ? '#FFD700' : '#FFF', text }]);
    setTimeout(() => { setParticles(prev => prev.filter(p => p.id !== id)); }, 1200);
  };

  const renderSquare = (row: number, col: number) => {
    const isBlack = (row + col) % 2 === 1;
    const piece = board[row][col];
    const isPossibleMove = validMoves.some(m => m.to.row === row && m.to.col === col);
    return (
      <div key={`${row}-${col}`} onClick={() => handleSquareClick(row, col)} className="relative w-full h-full flex items-center justify-center transition-colors duration-500" 
           style={{ backgroundColor: isBlack ? currentTheme.boardDark : currentTheme.boardLight, boxShadow: isBlack ? 'inset 0 0 8px rgba(0,0,0,0.5)' : 'inset 0 0 8px rgba(255,255,255,0.5)' }}>
        {isPossibleMove && <div className="absolute inset-1 bg-green-400 rounded-full animate-pulse opacity-40"></div>}
        {piece && <ToonPiece piece={piece} isSelected={selectedPieceId === piece.id} canMove={turn === piece.player && !(gameMode === 'pve' && turn === AI_PLAYER)} focusTarget={activeMoveTarget} onClick={() => handleSquareClick(row, col)} theme={piece.player === 'red' ? currentTheme.red : currentTheme.blue} model={rules.pieceModel} />}
        {particles.filter(p => p.row === row && p.col === col).map(p => (
           <div key={p.id} className="absolute inset-0 flex items-center justify-center z-50 pointer-events-none animate-pop">
              <span className="text-xl md:text-2xl font-black text-white drop-shadow-[0_2px_0_rgba(0,0,0,1)]" style={{ color: p.color }}>{p.text}</span>
           </div>
        ))}
      </div>
    );
  };

  const Toggle: React.FC<{ label: string, desc: string, active: boolean, onToggle: () => void }> = ({ label, desc, active, onToggle }) => (
    <div className="flex items-center justify-between p-4 bg-slate-800/50 rounded-2xl border border-slate-700 w-full hover:border-yellow-400 hover:shadow-[0_0_15px_rgba(250,204,21,0.4)] transition-all">
      <div className="flex flex-col">
        <span className="font-black text-white">{label}</span>
        <span className="text-[10px] text-slate-400 uppercase font-bold tracking-widest">{desc}</span>
      </div>
      <button onClick={onToggle} className={`relative w-14 h-8 rounded-full transition-colors duration-300 ${active ? 'bg-green-500 shadow-[0_0_15px_rgba(34,197,94,0.4)]' : 'bg-slate-600'}`}>
        <div className={`absolute top-1 left-1 w-6 h-6 bg-white rounded-full transition-transform duration-300 shadow-md ${active ? 'translate-x-6' : ''}`} />
      </button>
    </div>
  );

  return (
    <div className="min-h-screen h-[100dvh] bg-slate-900 flex flex-col items-center justify-center text-white relative overflow-hidden select-none touch-none">
      <div className="absolute inset-0 opacity-20 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900 via-slate-900 to-black pointer-events-none" />

      {/* Header Battle UI */}
      {gameState === 'playing' && (
        <div className="relative w-full max-w-4xl flex items-center justify-between p-3 md:p-6 z-20 flex-shrink-0">
          <BattleBar player="blue" score={scores.blue} theme={currentTheme} active={turn === 'blue'} />
          <div className="flex flex-col items-center mx-4">
            <h1 className="text-xl md:text-3xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500 tracking-tighter drop-shadow-md">TOON FIGHT!</h1>
            <div className="text-[8px] md:text-[10px] text-yellow-400 font-bold uppercase animate-pulse">{isAIThinking ? 'CPU PENSANDO...' : 'ROUND 1'}</div>
          </div>
          <BattleBar player="red" score={scores.red} theme={currentTheme} reverse active={turn === 'red'} />
          <button onClick={() => setGameState('menu')} className="absolute -bottom-10 left-1/2 -translate-x-1/2 px-4 py-1 bg-slate-800 hover:bg-red-600 text-[10px] font-black rounded-b-xl transition-all">DESISTIR</button>
        </div>
      )}

      {/* Main Content */}
      <main className="relative z-10 flex items-center justify-center w-full flex-grow p-1">
        {gameState === 'playing' ? (
          <div className="relative w-[96vw] h-[96vw] max-w-[500px] max-h-[500px] md:w-[min(600px,70vmin)] md:h-[min(600px,70vmin)] bg-slate-950 p-1 md:p-4 rounded-lg md:rounded-2xl shadow-2xl border-b-8 border-slate-950">
            <div className="w-full h-full rounded-md md:rounded-xl overflow-hidden grid grid-cols-8 grid-rows-8 shadow-inner ring-4 md:ring-8 ring-slate-800" style={{ borderColor: currentTheme.boardDark }}>
              {board.map((row, r) => row.map((_, c) => renderSquare(r, c)))}
            </div>
          </div>
        ) : gameState === 'menu' ? (
          <div className="flex flex-col items-center justify-center animate-fade-in p-6 w-full max-w-md">
            <div className="text-6xl md:text-9xl font-black text-white mb-8 tracking-tighter drop-shadow-2xl animate-float flex flex-col text-center">
              <span className="text-yellow-400 scale-75">TOON</span>
              <span className="mt-[-1rem]">CHECKERS</span>
            </div>
            <div className="flex flex-col gap-4 w-full mb-10">
              <button onClick={() => setShowDifficultySelect(true)} className="w-full px-8 py-5 bg-purple-600 hover:bg-purple-500 text-white rounded-2xl font-black text-xl shadow-[0_6px_0_rgb(88,28,135)] active:translate-y-[6px] active:shadow-none transition-all hover:ring-4 hover:ring-yellow-400">🤖 MODO ARCADE</button>
              <button onClick={() => initGame('pvp')} className="w-full px-8 py-5 bg-green-600 hover:bg-green-500 text-white rounded-2xl font-black text-xl shadow-[0_6px_0_rgb(20,83,45)] active:translate-y-[6px] active:shadow-none transition-all hover:ring-4 hover:ring-yellow-400">👥 MODO VERSUS</button>
              <button onClick={() => setGameState('settings')} className="w-full px-8 py-4 bg-slate-700 hover:bg-slate-600 text-white rounded-2xl font-black text-lg shadow-[0_5px_0_rgb(31,41,55)] active:translate-y-[5px] active:shadow-none transition-all flex items-center justify-center gap-2 hover:ring-4 hover:ring-yellow-400">⚙️ REGRAS & TEMAS</button>
            </div>
          </div>
        ) : gameState === 'settings' ? (
          <div className="absolute inset-0 bg-slate-900/98 z-50 flex flex-col items-center p-6 overflow-y-auto backdrop-blur-xl">
            <div className="w-full max-w-md pb-24">
              <div className="flex items-center justify-between mb-8 mt-4">
                <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter">CONFIGS</h2>
                <button onClick={() => setGameState('menu')} className="p-3 bg-rose-500 rounded-full font-black text-lg hover:scale-110 transition-transform">✖️</button>
              </div>

              <p className="text-slate-500 font-bold text-xs uppercase tracking-widest text-left mb-4 px-2">Regras da Partida</p>
              <div className="flex flex-col gap-4 mb-10">
                <Toggle label="Damas Voadoras" desc="REI DESLIZA PELO TABULEIRO" active={rules.flyingKings} onToggle={() => setRules({...rules, flyingKings: !rules.flyingKings})} />
                <Toggle label="Captura Traseira" desc="PEÇAS NORMAIS CAPTURAM PARA TRÁS" active={rules.backwardCapture} onToggle={() => setRules({...rules, backwardCapture: !rules.backwardCapture})} />
                <Toggle label="Sopro (Forçada)" desc="CAPTURA É OBRIGATÓRIA SE POSSÍVEL" active={rules.forcedCapture} onToggle={() => setRules({...rules, forcedCapture: !rules.forcedCapture})} />
              </div>

              <p className="text-slate-500 font-bold text-xs uppercase tracking-widest text-left mb-4 px-2">Visual das Peças (Skins)</p>
              <div className="grid grid-cols-2 gap-4 mb-10">
                {PIECE_MODELS.map(m => (
                  <button key={m.id} onClick={() => setRules({...rules, pieceModel: m.id})} className={`flex flex-col items-center p-4 rounded-3xl transition-all border-4 ${rules.pieceModel === m.id ? 'border-yellow-400 bg-slate-800 shadow-[0_0_20px_rgba(250,204,21,0.3)] scale-105' : 'border-transparent bg-slate-800/40 opacity-60 hover:opacity-100 hover:border-yellow-400 hover:shadow-[0_0_15px_rgba(250,204,21,0.4)]'}`}>
                    <span className="text-4xl mb-2">{m.icon}</span>
                    <span className="font-black text-xs uppercase tracking-tighter">{m.name}</span>
                    <span className="text-[8px] text-slate-400 uppercase font-bold tracking-widest mt-1">{m.desc}</span>
                  </button>
                ))}
              </div>

              <p className="text-slate-500 font-bold text-xs uppercase tracking-widest text-left mb-4 px-2">Visual da Arena</p>
              <div className="grid grid-cols-2 gap-4 mb-20">
                {THEMES.map(t => (
                  <button key={t.id} onClick={() => setCurrentTheme(t)} className={`flex flex-col items-center p-4 rounded-3xl transition-all border-4 ${currentTheme.id === t.id ? 'border-yellow-400 bg-slate-800 shadow-[0_0_20px_rgba(250,204,21,0.3)] scale-105' : 'border-transparent bg-slate-800/40 grayscale opacity-60 hover:opacity-100 hover:grayscale-0 hover:border-yellow-400 hover:shadow-[0_0_15px_rgba(250,204,21,0.4)]'}`}>
                    <span className="text-4xl mb-2">{t.icon}</span>
                    <span className="font-black text-xs uppercase tracking-tighter">{t.name}</span>
                  </button>
                ))}
              </div>
            </div>

            {/* Bottom Bar Settings */}
            <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-slate-950 to-transparent z-[60] flex justify-center">
              <button 
                onClick={handleSaveSettings}
                className={`w-full max-w-md py-5 rounded-2xl font-black text-2xl transition-all transform active:scale-95 shadow-2xl flex items-center justify-center gap-3 ${saveFeedback ? 'bg-green-500 animate-pulse' : 'bg-yellow-500 text-slate-900 hover:ring-4 hover:ring-white'}`}
              >
                {saveFeedback ? '✅ SALVO!' : '💾 SALVAR CONFIGS'}
              </button>
            </div>
          </div>
        ) : null}
      </main>

      {/* Difficulty Overlay */}
      {showDifficultySelect && (
        <div className="absolute inset-0 bg-slate-900/98 z-[60] flex flex-col items-center justify-center p-6 backdrop-blur-md">
           <h2 className="text-4xl font-black mb-10 text-center uppercase tracking-tighter">QUAL SEU NÍVEL?</h2>
           <div className="flex flex-col gap-4 w-full max-w-xs">
             <button onClick={() => initGame('pve', 'easy')} className="w-full px-8 py-5 bg-teal-500 rounded-2xl font-black text-xl shadow-[0_5px_0_rgb(13,148,136)] active:translate-y-2 active:shadow-none transition-all hover:ring-4 hover:ring-yellow-400">FÁCIL</button>
             <button onClick={() => initGame('pve', 'medium')} className="w-full px-8 py-5 bg-orange-500 rounded-2xl font-black text-xl shadow-[0_5px_0_rgb(194,65,12)] active:translate-y-2 active:shadow-none transition-all hover:ring-4 hover:ring-yellow-400">MÉDIO</button>
             <button onClick={() => initGame('pve', 'hard')} className="w-full px-8 py-5 bg-red-600 rounded-2xl font-black text-xl shadow-[0_5px_0_rgb(153,27,27)] active:translate-y-2 active:shadow-none transition-all hover:ring-4 hover:ring-yellow-400">DIFÍCIL</button>
             <button onClick={() => setShowDifficultySelect(false)} className="mt-8 text-slate-500 font-bold hover:text-white uppercase tracking-widest text-xs">← VOLTAR</button>
           </div>
        </div>
      )}

      {/* Winner Overlay */}
      {gameState === 'winner' && (
        <div className="absolute inset-0 bg-slate-900/95 z-[70] flex flex-col items-center justify-center p-6 backdrop-blur-xl animate-fade-in">
           <div className="text-yellow-400 text-8xl md:text-9xl mb-4 animate-bounce drop-shadow-2xl">KO!</div>
           <h2 className={`text-4xl md:text-7xl font-black mb-12 text-center uppercase tracking-tighter ${winner === 'red' ? 'text-rose-500' : 'text-sky-500'}`}>
             {winner === 'red' ? 'P1 DOMINOU!' : 'P2 DOMINOU!'}
           </h2>
           <div className="flex flex-col gap-6 w-full max-w-xs">
             <button onClick={() => initGame(gameMode, difficulty)} className="w-full px-10 py-5 bg-yellow-500 text-slate-900 rounded-2xl font-black text-2xl shadow-[0_8px_0_rgb(161,98,7)] active:translate-y-2 active:shadow-none transition-all transform hover:scale-105 hover:ring-4 hover:ring-yellow-400">REVANCHE</button>
             <button onClick={() => setGameState('menu')} className="w-full px-10 py-5 bg-slate-700 rounded-2xl font-black text-2xl shadow-[0_8px_0_rgb(31,41,55)] active:translate-y-2 active:shadow-none transition-all hover:ring-4 hover:ring-yellow-400">SAIR</button>
           </div>
        </div>
      )}

      <div className="absolute bottom-4 text-slate-700 text-[10px] font-bold tracking-widest uppercase opacity-40">
        ARENA: {currentTheme.name} | MODELO: {rules.pieceModel.toUpperCase()}
      </div>
    </div>
  );
};

export default App;

export type Player = 'red' | 'blue';

export type PieceModelId = 'classic' | 'robot' | 'slime' | 'alien' | 'vampy' | 'ghosty' | 'ninja' | 'bear';

export interface Position {
  row: number;
  col: number;
}

export interface Piece {
  id: string;
  player: Player;
  isKing: boolean;
  position: Position;
  isCaptured: boolean;
}

export interface Move {
  from: Position;
  to: Position;
  isJump: boolean;
  capturedPieceId?: string;
  jumpedPosition?: Position;
}

export type GameState = 'menu' | 'playing' | 'winner' | 'settings';
export type GameMode = 'pvp' | 'pve';
export type Difficulty = 'easy' | 'medium' | 'hard';

export interface Particle {
  id: string;
  row: number;
  col: number;
  color: string;
  text?: string;
}

export interface PlayerTheme {
  from: string;
  via: string;
  to: string;
  side: string;
}

export interface Theme {
  id: string;
  name: string;
  icon: string;
  boardDark: string;
  boardLight: string;
  red: PlayerTheme;
  blue: PlayerTheme;
}

export interface GameRules {
  flyingKings: boolean;
  backwardCapture: boolean;
  forcedCapture: boolean;
  pieceModel: PieceModelId;
}

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { Piece, Position, PlayerTheme, PieceModelId } from '../types';

interface ToonPieceProps {
  piece: Piece;
  isSelected: boolean;
  canMove: boolean;
  onClick: () => void;
  focusTarget: Position | null;
  theme: PlayerTheme;
  model: PieceModelId;
}

type IdleAction = 'none' | 'look-left' | 'look-right' | 'smirk' | 'ooh' | 'suspicious' | 'wiggle';

const ToonPiece: React.FC<ToonPieceProps> = ({ piece, isSelected, onClick, canMove, focusTarget, theme, model }) => {
  const [mood, setMood] = useState<'idle' | 'happy' | 'surprised' | 'focused' | 'evil'>('idle');
  const [idleAction, setIdleAction] = useState<IdleAction>('none');
  const [justBecameKing, setJustBecameKing] = useState(false);
  const timerRef = useRef<number>(0);
  const prevIsKingRef = useRef(piece.isKing);

  useEffect(() => {
    if (piece.isKing && !prevIsKingRef.current) {
        setJustBecameKing(true);
        setTimeout(() => setJustBecameKing(false), 2000);
    }
    prevIsKingRef.current = piece.isKing;
  }, [piece.isKing]);

  useEffect(() => {
    if (isSelected || focusTarget) {
      setIdleAction('none');
      if (timerRef.current) clearTimeout(timerRef.current);
      return;
    }

    const triggerRandomness = () => {
      const timeToNext = Math.random() * 4000 + 2000;
      timerRef.current = window.setTimeout(() => {
        const actions: IdleAction[] = ['look-left', 'look-right', 'smirk', 'ooh', 'suspicious', 'wiggle', 'none'];
        const picked = actions[Math.floor(Math.random() * actions.length)];
        setIdleAction(picked);
        if (picked !== 'none') {
            setTimeout(() => {
                setIdleAction(prev => (prev === picked ? 'none' : prev));
            }, 1000 + Math.random() * 1000);
        }
        triggerRandomness();
      }, timeToNext);
    };

    triggerRandomness();
    return () => { if (timerRef.current) clearTimeout(timerRef.current); };
  }, [isSelected, focusTarget, piece.id]);

  const lookAtStyle = useMemo(() => {
    const factor = model === 'alien' ? 8 : 5;
    if (focusTarget && !isSelected) {
      const dy = focusTarget.row - piece.position.row;
      const dx = focusTarget.col - piece.position.col;
      const distance = Math.sqrt(dx * dx + dy * dy) || 1;
      return { x: (dx / distance) * factor, y: (dy / distance) * (factor - 1), rotate: (dx / distance) * 10 };
    }
    if (idleAction === 'look-left') return { x: -factor, y: 0, rotate: -5 };
    if (idleAction === 'look-right') return { x: factor, y: 0, rotate: 5 };
    return { x: 0, y: 0, rotate: 0 };
  }, [focusTarget, piece.position, isSelected, idleAction, model]);

  useEffect(() => {
    if (isSelected) setMood('surprised');
    else if (piece.isKing) setMood('evil');
    else if (focusTarget) setMood('focused');
    else setMood('idle');
  }, [isSelected, piece.isKing, focusTarget]);

  const isWiggling = (idleAction === 'wiggle' || model === 'slime') && !isSelected && !focusTarget;
  const isKingFloating = piece.isKing && !isSelected;

  const baseRotation = (focusTarget && !isSelected) || idleAction !== 'none' ? lookAtStyle.rotate : 0;
  const transformStyle = isSelected 
    ? `translateY(-12px) scale(1.1) rotate(${baseRotation}deg)` 
    : `translateY(0px) rotate(${baseRotation}deg)`;

  const renderFaces = () => {
    const eyeBaseClass = "bg-white rounded-full overflow-hidden transition-all duration-300 shadow-sm border border-black/5";
    const pupilClass = `absolute bg-slate-900 rounded-full top-[45%] left-1/2 transform -translate-x-1/2 -translate-y-1/2 ${isSelected ? 'scale-125' : ''} transition-transform`;

    switch (model) {
      case 'robot':
        return (
          <div className="flex flex-col items-center">
            <div className="flex gap-2 mb-1" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
              {[1, 2].map(i => (
                <div key={i} className={`w-4 h-4 bg-cyan-400 border-2 border-cyan-700 rounded-sm shadow-[0_0_8px_rgba(34,211,238,0.6)] ${mood === 'surprised' ? 'scale-125' : 'animate-pulse'}`}>
                  <div className="w-1 h-1 bg-white rounded-full m-0.5 opacity-80"></div>
                </div>
              ))}
            </div>
            <div className={`w-6 h-1.5 bg-cyan-900/50 rounded-full border border-cyan-400/30 overflow-hidden`}>
               <div className="w-full h-full bg-cyan-400/20 animate-pulse"></div>
            </div>
          </div>
        );
      case 'alien':
        return (
          <div className="flex flex-col items-center">
            <div className={`relative w-8 h-8 ${eyeBaseClass} border-2 border-black/20`} style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
               <div className={`${pupilClass} w-4 h-4`}></div>
               <div className="absolute top-1 right-1 w-2 h-2 bg-white rounded-full opacity-60"></div>
            </div>
            <div className={`w-4 h-2 bg-black/40 rounded-full mt-1 ${mood === 'surprised' ? 'scale-150' : ''}`}></div>
          </div>
        );
      case 'slime':
        return (
          <div className="flex flex-col items-center opacity-80">
            <div className="flex gap-1 mb-1" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
              {[1, 2].map(i => (
                <div key={i} className={`w-3 h-3 bg-white rounded-full relative`}>
                  <div className="absolute inset-0.5 bg-black rounded-full"></div>
                </div>
              ))}
            </div>
            <div className="w-3 h-1 bg-black/20 rounded-full"></div>
            <div className="absolute inset-0 flex items-center justify-center opacity-20">
               <div className="w-2 h-2 bg-white rounded-full absolute top-2 left-2 animate-ping"></div>
               <div className="w-1 h-1 bg-white rounded-full absolute bottom-4 right-3 animate-pulse"></div>
            </div>
          </div>
        );
      case 'vampy':
        return (
          <div className="flex flex-col items-center">
            <div className="flex gap-1 mb-1" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
              {[1, 2].map(i => (
                <div key={i} className={`relative w-4 h-5 ${eyeBaseClass} border-red-500/20`}>
                  <div className={`absolute w-2 h-2 bg-red-600 rounded-full top-[45%] left-1/2 transform -translate-x-1/2 -translate-y-1/2 shadow-[0_0_5px_red] animate-pulse`}></div>
                </div>
              ))}
            </div>
            <div className="relative flex justify-center w-6 h-3">
              <div className="w-5 h-1.5 bg-black/80 rounded-full flex justify-between px-1">
                <div className="w-1 h-2 bg-white rounded-b-full shadow-sm"></div>
                <div className="w-1 h-2 bg-white rounded-b-full shadow-sm"></div>
              </div>
            </div>
          </div>
        );
      case 'ghosty':
        return (
          <div className="flex flex-col items-center opacity-90">
            <div className="flex gap-2 mb-1" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
              {[1, 2].map(i => (
                <div key={i} className={`w-3.5 h-3.5 bg-slate-900 rounded-full flex items-center justify-center`}>
                  <div className="w-1 h-1 bg-white rounded-full translate-x-1 -translate-y-1 opacity-40"></div>
                </div>
              ))}
            </div>
            <div className="w-4 h-4 bg-slate-900 rounded-full mt-1 animate-pulse"></div>
          </div>
        );
      case 'ninja':
        return (
          <div className="flex flex-col items-center">
             <div className="w-full h-4 bg-slate-900/80 mb-1 flex items-center justify-center relative">
                <div className="flex gap-4" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
                  {[1, 2].map(i => (
                    <div key={i} className="w-2.5 h-1 bg-white rounded-full rotate-[10deg] shadow-[0_0_5px_rgba(255,255,255,0.8)]"></div>
                  ))}
                </div>
             </div>
             <div className="w-6 h-1 bg-slate-900/40 rounded-full"></div>
          </div>
        );
      case 'bear':
        return (
          <div className="flex flex-col items-center">
            <div className="flex gap-2 mb-1" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
              {[1, 2].map(i => (
                <div key={i} className="w-2 h-2 bg-slate-900 rounded-full"></div>
              ))}
            </div>
            <div className="w-3 h-2 bg-black/20 rounded-full flex items-center justify-center">
               <div className="w-1 h-1 bg-black rounded-full"></div>
            </div>
          </div>
        );
      default: // classic
        return (
          <>
            <div className="flex gap-1 mb-1 transition-transform duration-300" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
              <div className={`relative w-4 h-5 ${eyeBaseClass} ${mood === 'evil' ? 'h-3.5 mt-1.5' : 'animate-blink'}`}>
                <div className={`${pupilClass} w-2 h-2`}></div>
              </div>
              <div className={`relative w-4 h-5 ${eyeBaseClass} ${mood === 'evil' ? 'h-3.5 mt-1.5' : 'animate-blink'}`} style={{ animationDelay: '0.1s' }}>
                <div className={`${pupilClass} w-2 h-2`}></div>
              </div>
            </div>
            <div className={`bg-slate-900/80 transition-all duration-300 ${mood === 'surprised' ? 'h-3 w-3 rounded-full' : 'w-4 h-2 rounded-b-full'}`} />
          </>
        );
    }
  };

  const bodyStyle: React.CSSProperties = {
    background: model === 'ghosty' 
      ? `radial-gradient(circle at 30% 30%, #fff, ${theme.via})`
      : `linear-gradient(135deg, ${theme.from}, ${theme.via}, ${theme.to})`,
    borderRadius: model === 'robot' ? '20%' : model === 'ghosty' ? '50% 50% 10% 10%' : '50%',
    opacity: model === 'slime' ? 0.85 : model === 'ghosty' ? 0.75 : 1,
    boxShadow: isSelected 
      ? `inset 0 4px 10px rgba(255,255,255,0.5), inset 0 -6px 12px rgba(0,0,0,0.2), 0 16px 0 ${theme.side}, 0 24px 20px rgba(0,0,0,0.4)`
      : `inset 0 4px 6px rgba(255,255,255,0.4), inset 0 -4px 8px rgba(0,0,0,0.2), 0 6px 0 ${theme.side}, 0 8px 6px rgba(0,0,0,0.3)`,
  };

  return (
    <div 
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      className={`relative w-[82%] h-[82%] cursor-pointer group transition-all duration-500 ease-[cubic-bezier(0.34,1.56,0.64,1)] flex items-center justify-center ${canMove ? 'hover:-translate-y-2' : ''}`}
      style={{ transform: transformStyle, zIndex: isSelected ? 50 : 10 }}
    >
        <div className={`w-full h-full flex items-center justify-center relative ${isWiggling ? 'animate-[shake_0.5s_ease-in-out_infinite]' : ''} ${isKingFloating ? 'animate-king-float' : ''} ${justBecameKing ? 'animate-levitate-once' : ''}`}
             style={bodyStyle}>
            {model === 'robot' && (
              <div className="absolute -top-1 left-1/4 w-1/2 h-1 bg-black/20 rounded-full" />
            )}
            {model === 'vampy' && (
              <div className="absolute -inset-2 bg-red-950/20 blur-xl opacity-0 group-hover:opacity-100 transition-opacity rounded-full"></div>
            )}
            {model === 'bear' && (
              <>
                <div className="absolute -top-2 -left-1 w-5 h-5 bg-inherit rounded-full shadow-sm border-t-2 border-white/20"></div>
                <div className="absolute -top-2 -right-1 w-5 h-5 bg-inherit rounded-full shadow-sm border-t-2 border-white/20"></div>
              </>
            )}
            <div className="relative w-full h-full flex flex-col items-center justify-center pointer-events-none z-10">
              {renderFaces()}
            </div>

            {piece.isKing && (
                <div className={`absolute -top-6 md:-top-8 left-1/2 transform -translate-x-1/2 w-8 h-8 md:w-10 md:h-10 z-30 pointer-events-none animate-crown`}>
                    <svg viewBox="0 0 24 24" fill="none" className="w-full h-full drop-shadow-xl">
                        <path d="M2 18h20v2H2v-2zm0-2l4-8 4 6 4-6 4 8H2z" fill="gold" stroke="#B8860B" strokeWidth="1"/>
                    </svg>
                </div>
            )}

            {model === 'ghosty' && (
              <div className="absolute -bottom-2 w-full flex justify-around px-1">
                <div className="w-3 h-3 bg-inherit rounded-full"></div>
                <div className="w-3 h-3 bg-inherit rounded-full"></div>
                <div className="w-3 h-3 bg-inherit rounded-full"></div>
              </div>
            )}
        </div>
    </div>
  );
};

export default ToonPiece;

