      case 'vampy':
        return (
          <div className="flex flex-col items-center">
            <div className="flex gap-1 mb-1" style={{ transform: `translate(${lookAtStyle.x}px, ${lookAtStyle.y}px)` }}>
              {[1, 2].map(i => (
                <div key={i} className={`relative w-4 h-5 ${eyeBaseClass} border-red-500/20`}>
                  <div className={`absolute w-2 h-2 bg-red-600 rounded-full top-[45%] left-1/2 transform -translate-x-1/2 -translate-y-1/2 shadow-[0_0_5px_red] animate-pulse`}></div>
