      )}

      <div className="absolute bottom-4 text-slate-700 text-[10px] font-bold tracking-widest uppercase opacity-40">
        ARENA: {currentTheme.name} | MODELO: {rules.pieceModel.toUpperCase()}
      </div>
    </div>
  );
};

