        </div>
      )}

      {/* Login Screen */}
      {gameState === 'login' && (
        <div className="absolute inset-0 z-[80] login-gradient flex flex-col items-center justify-center p-6 animate-fade-in">
           <div className="relative z-10 w-full max-sm:max-w-[340px] max-w-sm flex flex-col items-center bg-slate-800/80 backdrop-blur-xl p-8 rounded-[3rem] border-4 border-slate-700 shadow-2xl animate-pop">
              <div className="text-center mb-10 animate-logo">
                 <h1 className="text-5xl font-black text-yellow-400 tracking-tighter drop-shadow-[0_4px_0_rgba(0,0,0,0.5)]">TOON</h1>
                 <h2 className="text-3xl font-black text-white tracking-tighter -mt-2 drop-shadow-[0_3px_0_rgba(0,0,0,0.5)]">CHECKERS</h2>
              </div>

              <div className="w-full space-y-6">
                 <div className="relative">
                    <input 
                       type="text" 
                       placeholder="Seu Nickname..." 
                       value={nickname}
                       onChange={(e) => setNickname(e.target.value.substring(0, 12))}
